INSERT INTO `events_translations` (`event_id`, `language_id`, `title`, `event_date`, `menu_desc`, `short_desc`, `show_image`, `content`, `active`, `position`) VALUES
(1, 1, 'Добре дошли в новия ни сайт', '2013-05-15', 'Имаме нов сайт! С много нови неща, много яко.', 'Имаме нов сайт! С много нови неща, много яко. Имаме нов сайт! С много нови неща, много яко. Имаме нов сайт! С много нови неща, много яко. Имаме нов сайт! С много нови неща, много яко.', 'Yes', '<p>\r\n	Това е примерен текст. Можете да го замените с желания от вас текст за страницата.</p>\r\n<p>\r\n	Lorem ipsum е един от най-често използваните в печатарството безсмислени текстове, служещи да запълват със съдържание онези елементи от графичния дизайн, в които иначе се предполага да стои дълъг свързан текст. На английски такъв вид текст се нарича dummy text или placeholder text, като на български и двата термина могат да се срещнат непреведени.</p>\r\n<p>\r\n	Текстът Lorem ipsum е безсмислен, но визуално много прилича на истински, заради разпределението и честотата на срещане на по-къси, средни и дълги думи, разпределението на интервалите и препинателните знаци, както и дължината на изреченията. Разнообразието му осигурява, че ако се случи да бъде размножен, за да изпълни предвиденото пространство, да не се получат шарки от сорта на моарето вследствие еднотипно редуване на думи и интервали. &bdquo;Налят&ldquo; по този начин в графичните блокове Lorem ipsum позволява на окото да се абстрахира от конкретиката на смисления текст, и да се съсредоточи само върху особеностите на използвания шрифт и неговото визуално въздействие върху читателя.</p>\r\n<h1>\r\n	Защо да го използваме?</h1>\r\n<p>\r\n	Известен факт е, че читателя обръща внимание на съдържанието, което чете, а не на оформлението му. Свойството на Lorem Ipsum е, че до голяма степен има нормално разпределение на буквите и се чете по-лесно, за разлика от нормален текст на английски език като &quot;Това е съдържание, това е съдържание&quot;. Много системи за публикуване и редактори на Уеб страници използват Lorem Ipsum като примерен текстов модел &quot;по подразбиране&quot;, поради което при търсене на фразата &quot;lorem ipsum&quot; в Интернет ще бъдат открити... <a href=\"http://bg.lipsum.com/\" target=\"_blank\">повече</a></p>\r\n', 'No', 30),
(1, 2, 'Welcome to our new site', '2013-05-15', 'We have a new site! With a lot of new things very cool.', 'We have a new site! With a lot of new things very cool.', 'Yes', '<p>\r\n	<span id=\"result_box\" lang=\"en\"><span title=\"Това е примерен текст.\">This is sample text. </span><span title=\"Можете да го замените с желания от вас текст за страницата.\">You can replace it with your desired text for the page.</span><br />\r\n	<br />\r\n	<span title=\"Lorem ipsum е един от най-често използваните в печатарството безсмислени текстове, служещи да запълват със съдържание онези елементи от графичния дизайн, в които иначе се предполага да стои дълъг свързан текст.\">Lorem ipsum is one of the most commonly used in printing worthless texts serving to fill containing those elements of graphic design, where else am I supposed to stay connected long text. </span><span title=\"На английски такъв вид текст се нарича dummy text или placeholder text, като на български и двата термина могат да се срещнат непреведени.\">In English this kind of text is called dummy text or placeholder text, such as Bulgarian and the two terms can be found untranslated.</span></span></p>\r\n<p>\r\n	&nbsp;</p>\r\n', 'No', 20),
(2, 1, 'Спечелете пари', '2013-05-16', 'Разработване на нови методи за прибиране на пари от клиентите. Прочетете още..', 'Разработване на нови методи за прибиране на пари от клиентите. Прочетете още.. Разработване на нови методи за прибиране на пари от клиентите. Прочетете още.. Разработване на нови методи за прибиране на пари от клиентите. Прочетете още..', 'Yes', '<p>\r\n	<img alt=\"\" src=\"https://cs.fcst.bg/images/empty.jpg\" style=\"width: 300px; height: 196px; float: left; margin-right: 18px; margin-bottom: 12px; position: relative; top: 5px;\" />Това е примерен текст. Можете да го замените с желания от вас текст за страницата.</p>\r\n<p>\r\n	Lorem ipsum е един от най-често използваните в печатарството безсмислени текстове, служещи да запълват със съдържание онези елементи от графичния дизайн, в които иначе се предполага да стои дълъг свързан текст. На английски такъв вид текст се нарича dummy text или placeholder text, като на български и двата термина могат да се срещнат непреведени.</p>\r\n<p>\r\n	Текстът Lorem ipsum е безсмислен, но визуално много прилича на истински, заради разпределението и честотата на срещане на по-къси, средни и дълги думи, разпределението на интервалите и препинателните знаци, както и дължината на изреченията. Разнообразието му осигурява, че ако се случи да бъде размножен, за да изпълни предвиденото пространство, да не се получат шарки от сорта на моарето вследствие еднотипно редуване на думи и интервали. &bdquo;Налят&ldquo; по този начин в графичните блокове Lorem ipsum позволява на окото да се абстрахира от конкретиката на смисления текст, и да се съсредоточи само върху особеностите на използвания шрифт и неговото визуално въздействие върху читателя.</p>\r\n<h1>\r\n	Защо да го използваме?</h1>\r\n<p>\r\n	Известен факт е, че читателя обръща внимание на съдържанието, което чете, а не на оформлението му. Свойството на Lorem Ipsum е, че до голяма степен има нормално разпределение на буквите и се чете по-лесно, за разлика от нормален текст на английски език като &quot;Това е съдържание, това е съдържание&quot;. Много системи за публикуване и редактори на Уеб страници използват Lorem Ipsum като примерен текстов модел &quot;по подразбиране&quot;, поради което при търсене на фразата &quot;lorem ipsum&quot; в Интернет ще бъдат открити... <a href=\"http://bg.lipsum.com/\" target=\"_blank\">повече</a></p>\r\n', 'No', 20),
(3, 2, 'Five Bulgarian team will compete with European beer in France', '2013-05-16', 'Our competitors as appropriate of beer glasses with ping-pong balls begin to prepare for the European Championships.', 'Our competitors as appropriate of beer glasses with ping-pong balls begin to prepare for the European Championships in France, Toulouse. The epicenter of the training will be in Students&#39; town, where recently there first club Beer Pong country.', '', '<p>\r\n	<img alt=\"\" src=\"https://cs.fcst.bg/images/empty.jpg\" style=\"width: 300px; height: 196px; float: left; margin-right: 18px; margin-bottom: 12px; position: relative; top: 5px;\" /></p>\r\n<p>\r\n	&nbsp;</p>\r\n<p>\r\n	&nbsp;</p>\r\n<p>\r\n	&nbsp;</p>\r\n<p>\r\n	&nbsp;</p>\r\n<p>\r\n	&nbsp;</p>\r\n<p>\r\n	&nbsp;</p>\r\n<p>\r\n	&nbsp;</p>\r\n<p>\r\n	<span lang=\"en\"><span class=\"hps\">Our</span> <span class=\"hps\">competitors</span> <span class=\"hps\">as appropriate</span> <span class=\"hps\">of</span> <span class=\"hps\">beer glasses</span> <span class=\"hps\">with</span> <span class=\"hps\">ping</span><span class=\"atn\">-</span><span>pong balls</span> <span class=\"hps\">begin to prepare</span> <span class=\"hps\">for</span> <span class=\"hps\">the European Championships</span> <span class=\"hps\">in France,</span> <span class=\"hps\">Toulouse</span><span>.</span> <span class=\"hps\">The epicenter of the</span> <span class=\"hps\">training</span> <span class=\"hps\">will be in</span> <span class=\"hps\">Students&#39;</span> <span class=\"hps\">town, where</span> <span class=\"hps\">recently</span> <span class=\"hps\">there</span> <span class=\"hps\">first</span> <span class=\"hps\">club</span> <span class=\"hps\">Beer</span> <span class=\"hps\">Pong</span> <span class=\"hps\">country.</span><br />\r\n	<br />\r\n	<span class=\"hps\">The entire organization</span> <span class=\"hps\">is in the hands</span> <span class=\"hps\">of the</span> <span class=\"hps\">Bulgarian</span> <span class=\"hps\">National</span> <span class=\"hps\">Beer</span> <span class=\"hps\">Pong</span> <span class=\"hps\">Association</span> <span class=\"hps atn\">(</span><span>BNBPA</span><span>)</span> <span class=\"hps\">and</span> <span class=\"hps\">this week</span> <span class=\"hps\">on qualification</span> <span class=\"hps\">for</span> <span class=\"hps\">winning</span> <span class=\"hps\">5</span> <span class=\"hps\">quotas for</span> <span class=\"hps\">participation in the Euro</span> <span class=\"hps\">tournament</span><span>.</span> <span class=\"hps\">President</span> <span class=\"hps\">of the Association</span> <span class=\"hps\">and Vice President</span> <span class=\"hps\">Goran</span> <span class=\"hps\">Iltchev</span> <span class=\"hps\">Galina</span> <span class=\"hps\">Angelova</span> <span class=\"hps\">have</span> <span class=\"hps\">special invitations</span> <span class=\"hps\">to attend the</span> <span class=\"hps\">EU</span><span>.</span><br />\r\n	<br />\r\n	<span class=\"hps\">During the</span> <span class=\"hps\">racing</span> <span class=\"hps\">association</span> <span class=\"hps\">in</span> <span class=\"hps\">Beer Pong</span> <span class=\"hps\">will again</span> <span class=\"hps\">maintain the main aim</span> <span class=\"hps\">and</span> <span class=\"hps\">muse</span> <span class=\"hps\">of</span> <span class=\"hps\">creation</span> <span class=\"hps\">- support for</span> <span class=\"hps\">children suffering from</span> <span class=\"hps\">Down syndrome,</span> <span class=\"hps\">it will</span> <span class=\"hps\">set aside funds</span> <span class=\"hps\">to assist them</span><span>.</span></span></p>\r\n', 'No', 10),
(3, 1, 'Пет български отбора ще мерят сили с бира на европейското', '2013-11-27', 'Пет български отбора ще мерят сили с бира.', 'Наши състезатели по целене на бирени чаши с пинг-понг топчета започват да се подготвят за европейско първенство във Франция, град Тулуза. Епицентърът на тренировките ще е в Студенстки град, където отскоро съществува първия клуб по Бира Понг у нас.', '', '<p>\r\n	<img alt=\"\" src=\"https://cs.fcst.bg/images/empty.jpg\" style=\"width: 300px; height: 196px; float: left; margin-right: 18px; margin-bottom: 12px; position: relative; top: 5px;\" /></p>\r\n<p>\r\n	&nbsp;</p>\r\n<p>\r\n	&nbsp;</p>\r\n<p>\r\n	&nbsp;</p>\r\n<p>\r\n	&nbsp;</p>\r\n<p>\r\n	&nbsp;</p>\r\n<p>\r\n	&nbsp;</p>\r\n<p>\r\n	&nbsp;</p>\r\n<p>\r\n	Наши състезатели по целене на бирени чаши с пинг-понг топчета започват да се подготвят за европейско първенство във Франция, град Тулуза. Епицентърът на тренировките ще е в Студенстки град, където отскоро съществува първия клуб по Бира Понг у нас.</p>\r\n<p>\r\n	Цялата организация е в ръцете на Българска Национална Бира Понг Асоциация (БНБПА) и от тази седмица започват квалификации за спечелване на 5-те квоти за участие в евро турнира.&nbsp; Президентът на асоциацията Горан Илчев и вицепрезидентът Галина Ангелова имат специални покани за присъствие на европейското.<br />\r\n	<br />\r\n	По време на състезанията асоциацията по БИРА ПОНГ отново ще поддържа основната цел и муза за създаването си &ndash; подкрепа на деца, страдащи от синдром на Даун, като ще отделя средства за подпомагането им.<br />\r\n	<br />\r\n	Европейското първенство по БИРА ПОНГ се организира от Френската Бира Понг Академия, а наградата е цяла мечта &ndash; 1 седмица в Лас Вегас плюс 2 квоти за участие на световното първенство по БИРА ПОНГ, където наградният фонд е 100 000 $, а за класиралия се на първо място&nbsp; отбор по двойки са гарантирани&nbsp; 50 000 $.</p>\r\n', 'No', 10),
(4, 1, 'Facebook ампутира палеца в бутона &quot;Like&quot;', '2013-11-29', 'Facebook сама си разпорежда ампутация на палеца и така къса с може би най-известния си символ.', 'Facebook сама си разпорежда ампутация на палеца и така къса с може би най-известния си символ.', 'Yes', '<p>\r\n	&nbsp;</p>\r\n<div id=\"art_start\" style=\"font-size: 13px; font-family: Arial; margin: 0px auto; color: rgb(61, 61, 61); overflow: hidden; width: 652px; display: inline; font-style: normal; font-variant: normal; font-weight: normal; letter-spacing: normal; line-height: 19px; orphans: auto; text-align: start; text-indent: 0px; text-transform: none; white-space: normal; widows: auto; word-spacing: 0px; -webkit-text-stroke-width: 0px; background-color: rgb(255, 255, 255);\">\r\n	<p class=\"art_first\" style=\"font-size: 13px; font-family: Arial; margin: 0px 0px 10px; color: rgb(61, 61, 61); text-align: left;\">\r\n		Facebook сама си разпорежда ампутация на палеца и така къса с може би най-известния си символ.</p>\r\n	<p style=\"font-size: 13px; font-family: Arial; margin: 0px 0px 10px; color: rgb(61, 61, 61);\">\r\n		Бутонът &quot;Like&quot; с оптимистично опънатия нагоре палец ще бъде заменен от по-малък, тъмносин бутон с малко f от Facebook и думата &quot;Like&quot;. В допълнение ще има и бутон за споделяне със същия дизайн.</p>\r\n	<p style=\"font-size: 13px; font-family: Arial; margin: 0px 0px 10px; color: rgb(61, 61, 61);\">\r\n		Онова, което изглежда като относително малка промяна, в края на краищата засяга приблизително 7,5 милиона уеб страници, в които бутоните се показват общо 22 млрд. пъти на ден по целия свят.</p>\r\n	<p style=\"font-size: 13px; font-family: Arial; margin: 0px 0px 10px; color: rgb(61, 61, 61);\">\r\n		Но и за Facebook палеца е неделима част от корпоративната култура: Той е цитиран навсякъде в компанията, възпроизвежда се върху тениски, красеше дори и алеята до централата на Facebook в Менло Парк, Калифорния.</p>\r\n	<p style=\"font-size: 13px; font-family: Arial; margin: 0px 0px 10px; color: rgb(61, 61, 61);\">\r\n		Самият бутон е прозорецът на Facebook към мрежата: след като се зареди на компютъра на регистриран потребител във Facebook, социалната мрежа знае, че потребителят е сърфирал на съответната страница. Затова и защитниците на правата за лични данни настояват от 2011 година насам собствениците на сайтове да използват бутоните с повишено внимание.</p>\r\n	<p style=\"font-size: 13px; font-family: Arial; margin: 0px 0px 10px; color: rgb(61, 61, 61);\">\r\n		В интервю за co.design.com Хюго ван Хювен, дизайнерът на бутоните в социалната мрежа, обяснява подробно защо въпреки всичко това Facebook иска да премахне палеца и за първи път от 2010 г. насам да предприеме подобно дизайнерско обновяване.</p>\r\n	<p style=\"font-size: 13px; font-family: Arial; margin: 0px 0px 10px; color: rgb(61, 61, 61);\">\r\n		&bdquo;Досегашният светлосин бутон твърде много остава на заден план&quot;, обяснява той в интервюто. &quot;Искахме той да стане по-видим&quot;. При различни експерименти дизайнерите са установили, че все повече потребители кликват върху бутона, когато той е проектиран в поразително тъмносиньо. На него обаче вече не пасвал самият палец.</p>\r\n	<p style=\"font-size: 13px; font-family: Arial; margin: 0px 0px 10px; color: rgb(61, 61, 61);\">\r\n		В бъдеще палецът ще бъде запазен само в една голяма версия на бутона. Сега той ще се появява само в едно повторение на бутоните: уеб дизайнерите може да вграждат разширена версия на бутоните на своите страници, в които едно поле с палци показва броя получени &quot;харесвания&quot;.</p>\r\n	<p style=\"font-size: 13px; font-family: Arial; margin: 0px 0px 10px; color: rgb(61, 61, 61);\">\r\n		Промяната може да направи &quot;Like&quot; популярен в някои арабски страни. Там протегнатия нагоре палец има значението на известния на Запад изпънат напред среден пръст.</p>\r\n	<p style=\"font-size: 13px; font-family: Arial; margin: 0px 0px 10px; color: rgb(61, 61, 61);\">\r\n		<a href=\"http://www.investor.bg/news/index/260.html\" style=\"color: rgb(151, 27, 30) !important; text-decoration: none; outline: none; font-size: 13px !important; font-weight: bold;\" target=\"_blank\"><b style=\"font-family: Arial; font-size: 13px; color: rgb(151, 27, 30) !important; font-weight: bold;\">Още технологични новини четете в Investor.bg</b></a></p>\r\n</div>\r\n<p>\r\n	<span class=\"article_author_bottom\" style=\"font-size: 13px; font-style: italic; font-family: Arial; color: rgb(61, 61, 61); font-variant: normal; font-weight: normal; letter-spacing: normal; line-height: 19px; orphans: auto; text-align: start; text-indent: 0px; text-transform: none; white-space: normal; widows: auto; word-spacing: 0px; -webkit-text-stroke-width: 0px; background-color: rgb(255, 255, 255);\">По публикацията работи:<span class=\"Apple-converted-space\">&nbsp;</span><a href=\"mailto:boycho.popov@investor.bg\" style=\"color: rgb(151, 27, 30) !important; text-decoration: none; outline: none; font-size: 13px !important; font-weight: bold;\" title=\"Пиши на Бойчо Попов\">Бойчо Попов</a></span></p>\r\n<p>\r\n	&nbsp;</p>\r\n', 'No', 40),
(5, 1, 'Правила за разпределение на студентите за КР и КП по дисциплини', '2014-03-11', 'Правила за разпределение на студентите за КР и КП по дисциплини', 'На вниманието на студентите от специалност „Компютърно и софтуерно инженерство“ и КСТ относно новите правила за разпределение на студентите за КР и КП по дисциплини', 'Yes', '<p style=\"text-align: center;\">\r\n	<strong>На вниманието на студентите от специалност &bdquo;Компютърно и софтуерно инженерство&ldquo; и КСТ</strong></p>\r\n<p style=\"text-align: center;\">\r\n	<strong>Относно: Разпределение на студентите за КР и КП по дисциплини </strong></p>\r\n<hr />\r\n<p>\r\n	Разпределението на студентите за КР и КП по дисциплини се извършва по следните правила:&nbsp;</p>\r\n<ol>\r\n	<li>\r\n		КР и КП трябва да бъдат избрани по различни дисциплини.</li>\r\n	<li>\r\n		Разпределението на студентите за КР и КП се прави равномерно по заложените дисциплини съобразно заявените желания (първо, второ и трето желание) на студентите и средния им успех.</li>\r\n</ol>\r\n<p style=\"text-align: right;\">\r\n	<strong style=\"text-align: center;\">Решение на катедрения съвет на катедра &bdquo;Компютърни системи&ldquo; (24.02.2014г.)&nbsp;</strong></p>\r\n', 'No', 50),
(5, 2, 'Course Project Selection for Semester VI', '2014-03-11', '', 'Course Project Selection for Semester VI no later than 20.03.2014', '', '<p>\r\n	Every third year student must specify his preferences for course project preparation no later than 20.03.2014 at room 1327.</p>\r\n<p>\r\n	&nbsp;</p>\r\n', 'Yes', 50),
(11, 1, 'Летни стажове и практики', '2014-04-15', 'Кампания летни практики 2014', 'На вниманието на студентите от специалност „Компютърно и софтуерно инженерство“ и КСИ относно летните практики', 'Yes', '<p>\r\n	<a href=\"https://cs.fcst.bg/page.php?id=42\">Информация за летни практики</a></p>\r\n', 'No', 90),
(11, 2, 'Summer training practice 2014 :: Registration Start', '2014-04-24', 'Enrollment start for the summer trainnig practice at SAP Labs Bulgaria for 2nd and 3rd year students.', 'Enrollment start for the summer trainnig practice at SAP Labs Bulgaria for 2nd and 3rd year students.', '', '<p>\r\n	Interested students must declare their participation to student practice at SAP Labs Bulgaria to Eng. Sevinch Mehmed no later than <strong>20.05.2014</strong>.</p>\r\n<p>\r\n	&nbsp;</p>\r\n', 'Yes', 60),
(12, 2, 'Begin of Summer Practice Session 2014', '2014-07-02', 'Summer 2014 Practice Session Schedule', 'Summer 2014 Practice Session Schedule', 'Yes', '<div>\r\n	<div>\r\n		<strong>Summer 2014 Practice Session in:</strong></div>\r\n	<ul>\r\n		<li>\r\n			Company: <a href=\"https://cs.fcst.bg/userfiles/BSc_SummerPractices/SAP_Labs_Bulgaria.pptx\">SAP&nbsp;Labs</a>, BULGARIA</li>\r\n		<li>\r\n			Date: 7.07.2014 at 10:00 h</li>\r\n		<li>\r\n			Place: Hall Serdika&quot;&quot;, &nbsp;in the building of the company.</li>\r\n		<li>\r\n			Address: Sofia, blv Tsar Boris III 136</li>\r\n	</ul>\r\n</div>\r\n<p>\r\n	&nbsp;</p>\r\n', 'Yes', 70),
(6, 1, 'Тест 2', '2015-01-29', '', 'Lorem ipsum е един от най-често използваните в печатарството безсмислени текстове, служещи да запълват със съдържание онези елементи от графичния дизайн', 'Yes', '<p>\r\n	<img alt=\"\" src=\"https://cs.fcst.bg/images/empty.jpg\" style=\"width: 300px; height: 196px; float: left; margin-right: 18px; margin-bottom: 12px; position: relative; top: 5px;\" />Това е примерен текст. Можете да го замените с желания от вас текст за страницата.</p>\r\n<p>\r\n	Lorem ipsum е един от най-често използваните в печатарството безсмислени текстове, служещи да запълват със съдържание онези елементи от графичния дизайн, в които иначе се предполага да стои дълъг свързан текст. На английски такъв вид текст се нарича dummy text или placeholder text, като на български и двата термина могат да се срещнат непреведени.</p>\r\n<p>\r\n	Текстът Lorem ipsum е безсмислен, но визуално много прилича на истински, заради разпределението и честотата на срещане на по-къси, средни и дълги думи, разпределението на интервалите и препинателните знаци, както и дължината на изреченията. Разнообразието му осигурява, че ако се случи да бъде размножен, за да изпълни предвиденото пространство, да не се получат шарки от сорта на моарето вследствие еднотипно редуване на думи и интервали. &bdquo;Налят&ldquo; по този начин в графичните блокове Lorem ipsum позволява на окото да се абстрахира от конкретиката на смисления текст, и да се съсредоточи само върху особеностите на използвания шрифт и неговото визуално въздействие върху читателя.</p>\r\n<h1>\r\n	Защо да го използваме?</h1>\r\n<p>\r\n	Известен факт е, че читателя обръща внимание на съдържанието, което чете, а не на оформлението му. Свойството на Lorem Ipsum е, че до голяма степен има нормално разпределение на буквите и се чете по-лесно, за разлика от нормален текст на английски език като &quot;Това е съдържание, това е съдържание&quot;. Много системи за публикуване и редактори на Уеб страници използват Lorem Ipsum като примерен