(11, '2014-04-17 23:17:25', 'contact', 'ali hussein ibraheem', '\n			<b>Компания:</b> <br>\n			<b>Име:</b> ali hussein ibraheem<br>\n			<b>Адрес:</b> kiev-ukraine<br>\n			<b>Телефон:</b> +380(93)366-84-91<br>\n			<b>Електронна поща:</b> ali_ah2089@yahoo.com<br>\n			\n			<br>\n			\n			<b>Съобщение:</b><br><br>\n			\n			hello. i want to study master degree in computer and software engineering in your department on the new year (next). please tell me what the requires of registration and when the last day of registration.', 'Yes'),
(12, '2014-04-26 09:38:28', 'contact', 'Иван Иванов', '\n			<b>Компания:</b> <br>\n			<b>Име:</b> Иван Иванов<br>\n			<b>Адрес:</b> <br>\n			<b>Телефон:</b> <br>\n			<b>Електронна поща:</b> tonuto@abv.bg<br>\n			\n			<br>\n			\n			<b>Съобщение:</b><br><br>\n			\n			Добър ден.Интересувам се от дистанционната форма на обучение за степен бакалавър/след средно образование/ Какви специалности има и какви са семестриалните такси.Благодаря да отделеното време.', 'Yes'),
(13, '2014-05-07 12:55:01', 'contact', 'Деян Делийски', '\n			<b>Компания:</b> <br>\n			<b>Име:</b> Деян Делийски<br>\n			<b>Адрес:</b> <br>\n			<b>Телефон:</b> 0888145876<br>\n			<b>Електронна поща:</b> deian@gbg.bg<br>\n			\n			<br>\n			\n			<b>Съобщение:</b><br><br>\n			\n			Здравейте! В момента завършвам бакалаварска степен с диплом за бакалавър, специалност “Информатика”.във Икономически Университет-Варна ,възможно ли е да запиша магистъски курс&quot;ИНФОРМАТИКА&quot; във вашият иниверситет? Предварително благодаря за отговорът Ви!', 'Yes'),
(14, '2014-05-07 14:08:20', 'contact', '&lt;script&gt;alert(&#39;hacked&#39;)&lt;/script&gt;', '\n			<b>Компания:</b> <br>\n			<b>Име:</b> &lt;script&gt;alert(&#39;hacked&#39;)&lt;/script&gt;<br>\n			<b>Адрес:</b> <br>\n			<b>Телефон:</b> <br>\n			<b>Електронна поща:</b> <script>alert(&#34hacked&#34)</script><br>\n			\n			<br>\n			\n			<b>Съобщение:</b><br><br>\n			\n			&lt;script&gt;alert(&#39;hacked&#39;)&lt;/script&gt;', 'Yes'),
(15, '2014-05-07 14:09:07', 'contact', 'jjiijo', '\n			<b>Компания:</b> <br>\n			<b>Име:</b> jjiijo<br>\n			<b>Адрес:</b> <br>\n			<b>Телефон:</b> <br>\n			<b>Електронна поща:</b> uy8jhi<br>\n			\n			<br>\n			\n			<b>Съобщение:</b><br><br>\n			\n			ojioijijoijo', 'Yes'),
(16, '2014-05-21 22:27:19', 'contact', 'Мартин', '\n			<b>Компания:</b> <br>\n			<b>Име:</b> Мартин<br>\n			<b>Адрес:</b> <br>\n			<b>Телефон:</b> <br>\n			<b>Електронна поща:</b> martin_mk@abv.bg<br>\n			\n			<br>\n			\n			<b>Съобщение:</b><br><br>\n			\n			Искам да попитам кога е поправката по ПС(програмни среди) при проф. Наков и може ли да се явяват студенти от минали години.\r<br>\r<br>Мерси.', 'Yes'),
(17, '2014-05-23 13:08:15', 'contact', 'Angel', '\n			<b>Компания:</b> <br>\n			<b>Име:</b> Angel<br>\n			<b>Адрес:</b> <br>\n			<b>Телефон:</b> 0896048888<br>\n			<b>Електронна поща:</b> approved123@gmail.com<br>\n			\n			<br>\n			\n			<b>Съобщение:</b><br><br>\n			\n			Namerix uqzvimost/dupka v saita, ako ste zainteresovani mojete da me potursite na goreposocheniq telefon,  ili na tozi email addres..\r<br>//Izvinenie za latinicata//\r<br>\r<br>G.//\r<br>Angel Tsvetkov', 'Yes'),
(18, '2014-06-23 22:06:59', 'contact', 'cveti', '\n			<b>Компания:</b> <br>\n			<b>Име:</b> cveti<br>\n			<b>Адрес:</b> <br>\n			<b>Телефон:</b> <br>\n			<b>Електронна поща:</b> cwetkoiwanow@gmail.com<br>\n			\n			<br>\n			\n			<b>Съобщение:</b><br><br>\n			\n			interesuwa me trqbwa li mi predishen opit s kompiutri i kakwi sa semestrite..', 'Yes'),
(19, '2014-06-26 19:27:49', 'contact', 'Месут', '\n			<b>Компания:</b> <br>\n			<b>Име:</b> Месут<br>\n			<b>Адрес:</b> <br>\n			<b>Телефон:</b> <br>\n			<b>Електронна поща:</b> chelsea_nr1@abv.bg<br>\n			\n			<br>\n			\n			<b>Съобщение:</b><br><br>\n			\n			Добър Вечер! Искам да Ви попитам, дали дали кандидат-студентите, могат да подават кандидатстудентски документи в Събота и Неделя? Тези дни в ТУ София, броят ли се за Работни дни, за подаване на документи и пр. и дали има период от време, т.е. в същите часове ли се работи, както като нормалните работни часове? Благодаря Ви, предварително!', 'Yes'),
(20, '2014-07-03 10:52:06', 'contact', 'Николай Нероев', '\n			<b>Компания:</b> <br>\n			<b>Име:</b> Николай Нероев<br>\n			<b>Адрес:</b> <br>\n			<b>Телефон:</b> <br>\n			<b>Електронна поща:</b> faraona77@gmail.com<br>\n			\n			<br>\n			\n			<b>Съобщение:</b><br><br>\n			\n			Интересувам се от магистърските програми и понеже вече наближава времето за кандидатстване имам е два въпроса относно кандидатстването:\r<br>1. понеже моята специалност &quot;Мениджмънт и информатика в телекомуникациите и пощите&quot; е с  образователно-квалификационна степен &quot;Професионален бакалвър&quot; дали има проблем това? освен ,че се изучава 5 семестъра?\r<br>2. Понеже дипломите ще бъдат готови декември може ли само с академична справка да се кандидатства?\r<br>\r<br>С уважение\r<br>Николай Нероев', 'Yes'),
(21, '2014-07-09 10:20:42', 'contact', 'Георги Железов', '\n			<b>Компания:</b> <br>\n			<b>Име:</b> Георги Железов<br>\n			<b>Адрес:</b> Студентски град бл.59В<br>\n			<b>Телефон:</b> 0877113373<br>\n			<b>Електронна поща:</b> howkinss@gmail.com<br>\n			\n			<br>\n			\n			<b>Съобщение:</b><br><br>\n			\n			Здравейте, имам следния проблем.\r<br>Днес си платих за Юли и Август месец и при доманкинката от моя блок ми дадоха декларация, в която трябваше задължително да попълня оценки за среден успех, а се оказва, че ние не сме си взели все още всички изпити. Аз съм магистър 2ри семестър КСТ.\r<br>\r<br>Може ли да ми помогнете и информирате как се процедира, понеже виждам, че срока е до 15 този месец.\r<br>\r<br>Поздрави, Георги', 'Yes'),
(22, '2014-07-14 16:25:48', 'contact', 'Бранимир Данов', '\n			<b>Компания:</b> <br>\n			<b>Име:</b> Бранимир Данов<br>\n			<b>Адрес:</b> <br>\n			<b>Телефон:</b> <br>\n			<b>Електронна поща:</b> branimir_danov@abv.bg<br>\n			\n			<br>\n			\n			<b>Съобщение:</b><br><br>\n			\n			Магистърска програма &quot;Информационни технологии&quot; предлага ли се в задочна/дистанционна форма на обучение или е само в редовна?', 'Yes'),
(23, '2014-07-16 15:07:30', 'contact', 'Евстратиос  Далларис', '\n			<b>Компания:</b> <br>\n			<b>Име:</b> Евстратиос  Далларис<br>\n			<b>Адрес:</b> <br>\n			<b>Телефон:</b> <br>\n			<b>Електронна поща:</b> nickforthewin@hotmail.com<br>\n			\n			<br>\n			\n			<b>Съобщение:</b><br><br>\n			\n			Добър ден, желая да попитам за условията при кандидатсване на чужденци и изисквания, понеже аз съм гръцки гражданин и оценяването ми тук е по 20 бална система', 'Yes'),
(24, '2014-07-16 16:31:08', 'contact', 'Димитър', '\n			<b>Компания:</b> <br>\n			<b>Име:</b> Димитър<br>\n			<b>Адрес:</b> <br>\n			<b>Телефон:</b> 0898250210<br>\n			<b>Електронна поща:</b> darsik@abv.bg<br>\n			\n			<br>\n			\n			<b>Съобщение:</b><br><br>\n			\n			Искам да попитам за специалността Информационни технологии в индустрията . Какво представлява тя , приет съм в нея а нямам никаква информацията за учебния план и това какво ще изучава ? Дори в страницата на факултета няма информацията за тази специалност ?  Моля да ми бъде дадена по обстойна информация за специалността и това какво изучава тя . Все пак вие сте създали тази специалност с някаква цел , и факултета трябва да е изключително наясно с нея . Благодаря предварително !', 'Yes'),
(25, '2014-07-19 23:06:28', 'contact', 'Serafin Seoane Martinez', '\n			<b>Компания:</b> <br>\n			<b>Име:</b> Serafin Seoane Martinez<br>\n			<b>Адрес:</b> <br>\n			<b>Телефон:</b> <br>\n			<b>Електронна поща:</b> serafin.seoane@gmail.com<br>\n			\n			<br>\n			\n			<b>Съобщение:</b><br><br>\n			\n			Здравейте!Казвам се Серафин Сеоане и съм от Испания, като последните пет години живея в България. Интересувам се от специалностите в областта на математиката (бакалавърска програма), които се провеждат на английски език (видях на сайта специалност Математика и компщтърни науки). Може ли да ми дадете малко повече информация - тази година ще има ли такава специалност, какви са условията за кандидатстване, какъв е учебният план... Включително много бих се радвал, ако мога да дойда и да разговаряме директно. Благодяр за отделеното време! Серафин Сеоане', 'Yes'),
(26, '2014-08-03 16:38:49', 'contact', 'hdjdkw', '\n			<b>Компания:</b> <br>\n			<b>Име:</b> hdjdkw<br>\n			<b>Адрес:</b> <br>\n			<b>Телефон:</b> <br>\n			<b>Електронна поща:</b> dwqjkhj<br>\n			\n			<br>\n			\n			<b>Съобщение:</b><br><br>\n			\n			dwqjhdjkqw', 'Yes'),
(27, '2014-08-13 09:35:17', 'contact', 'Ивелин Мирославов Маринов', '\n			<b>Компания:</b> <br>\n			<b>Име:</b> Ивелин Мирославов Маринов<br>\n			<b>Адрес:</b> <br>\n			<b>Телефон:</b> <br>\n			<b>Електронна поща:</b> ivfirst@gmail.com<br>\n			\n			<br>\n			\n			<b>Съобщение:</b><br><br>\n			\n			Здравейте,\r<br>завършил съм степен бакалавър в ТУ София по специалност електроенергатика и електрообзавеждане. Интересувам се дали ще е възможно да запиша степен магистър по специалност комуникационна и компютърна техника, редовно или задочно без изравнителни изпити. Ще бъда доволен и от повече информация относно сроковете за записване и други изисквания.\r<br>Благодаря предварително!\r<br>\r<br>Поздрави,\r<br>инж. Ивелин Маринов', 'Yes'),
(28, '2014-08-13 12:56:29', 'contact', 'Златко Асенов', '\n			<b>Компания:</b> <br>\n			<b>Име:</b> Златко Асенов<br>\n			<b>Адрес:</b> <br>\n			<b>Телефон:</b> 0877017676<br>\n			<b>Електронна поща:</b> zlatko.asenov@gmail.com<br>\n			\n			<br>\n			\n			<b>Съобщение:</b><br><br>\n			\n			Здравейте,\r<br>\r<br>Искам да запиша задочно или дистанционно обучение по специалност &quot;Компютърно и софтуерно инженерство&quot; или &quot;Компютърни науки и инженерство&quot;.\r<br>\r<br>Дипломата ми за средно образование е от 1996 г. и бях освободен от матури поради отличен успех.\r<br>Имам диплома по право от ЮЗУ &quot;Неофит Рилски&quot;.\r<br>\r<br>Въпросът ми към Вас е трябва ли да държа кандидат-студентски изпит или може направо да запиша една от горните специалности?\r<br>\r<br>Поздрави,\r<br>\r<br>Златко Асенов', 'No'),
(29, '2014-08-16 18:50:54', 'contact', 'Ruslan Stefanov Todorov', '\n			<b>Компания:</b> Sky Soft Bulgaria ltd.<br>\n			<b>Име:</b> Ruslan Stefanov Todorov<br>\n			<b>Адрес:</b> Къпина 9<br>\n			<b>Телефон:</b> 359885249229<br>\n			<b>Електронна поща:</b> expertpcin@gmail.com<br>\n			\n			<br>\n			\n			<b>Съобщение:</b><br><br>\n			\n			Здравейте,\r<br>вашите уеб сървъри са незащитени и говоря за доста такива дори може да се окаже че аз знам поне 100 който вие не знаете. Имате ли нужда от одит за да добиете бегла представа какво показвате на хакерите?????', 'No'),
(30, '2014-09-17 09:00:18', 'contact', 'Симеон', '\n			<b>Компания:</b> <br>\n			<b>Име:</b> Симеон<br>\n			<b>Адрес:</b> <br>\n			<b>Телефон:</b> <br>\n			<b>Електронна поща:</b> kasandrite@abv.bg<br>\n			\n			<br>\n			\n			<b>Съобщение:</b><br><br>\n			\n			Мога ли все още да кандидатствам?', 'No'),
(31, '2014-09-18 18:04:23', 'contact', 'Тодор Георгиев', '\n			<b>Компания:</b> <br>\n			<b>Име:</b> Тодор Георгиев<br>\n			<b>Адрес:</b> <br>\n			<b>Телефон:</b> <br>\n			<b>Електронна поща:</b> todorg@gmail.com<br>\n			\n			<br>\n			\n			<b>Съобщение:</b><br><br>\n			\n			Здравейте,\r<br>\r<br>съвсем случайно попаднах на https://cs.fcst.bg/userfiles/bypass/ което е записано на 14.09.2014 и е зловреден код. Някой е компрометирал сървъра. Изтрийте го, но преди това вижте как е било записано и било ли е ползвано?\r<br>\r<br>Поздрави,\r<br>Тодор', 'No'),
(32, '2014-09-18 22:17:10', 'contact', 'Боряна Иванова Христова', '\n			<b>Компания:</b> <br>\n			<b>Име:</b> Боряна Иванова Христова<br>\n			<b>Адрес:</b> <br>\n			<b>Телефон:</b> <br>\n			<b>Електронна поща:</b> borqna.h@gmail.com<br>\n			\n			<br>\n			\n			<b>Съобщение:</b><br><br>\n			\n			Здравейте, юли месец 2014 защитих дипломната си работа, степен Бакалавър, ФКСТ. Искам да попитам кога ще се раздават дипломите ?', 'No'),
(33, '2014-09-19 16:50:47', 'contact', 'Александър', '\n			<b>Компания:</b> <br>\n			<b>Име:</b> Александър<br>\n			<b>Адрес:</b> <br>\n			<b>Телефон:</b> <br>\n			<b>Електронна поща:</b> alexchowe@gmail.com<br>\n			\n			<br>\n			\n			<b>Съобщение:</b><br><br>\n			\n			Здравейте. Искам да попитам кога ще бъде се проведе кандидатстването за 2014/2015 година и също така в кои специалности има задочно обучение?', 'No'),
(34, '2014-09-25 16:01:25', 'contact', 'Angel', '\n			<b>Компания:</b> <br>\n			<b>Име:</b> Angel<br>\n			<b>Адрес:</b> <br>\n			<b>Телефон:</b> 0896048888<br>\n			<b>Електронна поща:</b> approved123@gmail.com<br>\n			\n			<br>\n			\n			<b>Съобщение:</b><br><br>\n			\n			Здравейте.Казвам се Ангел Цветков.\r<br>\r<br>Пиша ви относно вашият саит : https://cs.fcst.bg/\r<br>\r<br>Намерих Дупка/Уязвимост (пропуск) във вашият саит..\r<br>\r<br>Ако сте заинтересовани може да ме намерите на този емайл..\r<br>\r<br>Поздрави ; // Ангел Цветков', 'No'),
(35, '2014-09-26 12:43:50', 'contact', 'Любомир Пачелиев', '\n			<b>Компания:</b> <br>\n			<b>Име:</b> Любомир Пачелиев<br>\n			<b>Адрес:</b> <br>\n			<b>Телефон:</b> <br>\n			<b>Електронна поща:</b> lubo.9476@gmail.com<br>\n			\n			<br>\n			\n			<b>Съобщение:</b><br><br>\n			\n			Добър ден!\r<br>Казвам се Любомир Пачелиев. Студент съм в ТУ София ф-л Пловдив. Желанието ми е да се преместя в ТУ София. Нямам намерение да сменят специалността, която е Компютърни системи и технологии. Втори курс съм и имам 4 не взети изпита. Възможно ли е да се прехвърля при вас. Получил съм разрешение от декана на Факултета по Електроника и Автоматика в ТУ София ф-л Пловдив. Ако е възможно, бихте ли ми разяснили процедурата по преместването? \r<br>Благодаря за отделеното време,\r<br>с уважение,\r<br>Любомир Пачелиев', 'No'),
(36, '2014-10-01 10:28:45', 'contact', 'Десислава', '\n			<b>Компания:</b> <br>\n			<b>Име:</b> Десислава<br>\n			<b>Адрес:</b> <br>\n			<b>Телефон:</b> <br>\n			<b>Електронна поща:</b> desinka93@abv.bg<br>\n			\n			<br>\n			\n			<b>Съобщение:</b><br><br>\n			\n			Добър ден , бих искала да попитам от къде мога да получа повече информация за дистанционно обучение на английски език  по специалноста &quot;Компютърни науки&quot;.', 'No'),
(37, '2014-10-02 14:35:09', 'contact', 'Мартин Гугутков', '\n			<b>Компания:</b> <br>\n			<b>Име:</b> Мартин Гугутков<br>\n			<b>Адрес:</b> <br>\n			<b>Телефон:</b> <br>\n			<b>Електронна поща:</b> martin.gugutkov@gmail.com<br>\n			\n			<br>\n			\n			<b>Съобщение:</b><br><br>\n			\n			Здравейте,\r<br>Аз съм студент 3 семестър - магистратура, спец. Компютърно и софтуерно инженерство. Моля за информация дали може да запиша семестъра и защо не мога да платя по банков път - извежда ми съобщение за прешка при проверка?', 'Yes'),
(38, '2014-10-06 11:18:55', 'contact', 'Катя Иванова', '\n			<b>Компания:</b> <br>\n			<b>Име:</b> Катя Иванова<br>\n			<b>Адрес:</b> <br>\n			<b>Телефон:</b> 0884765106<br>\n			<b>Електронна поща:</b> katiastefanova1966@abv.bg<br>\n			\n			<br>\n			\n			<b>Съобщение:</b><br><br>\n			\n			Невзети изпити - брой и дисциплини на Ивелин Антонов Стефанов - бакалавър , специалност ”Компютърно и софтуерно инженерство” - IV семестър ?', 'Yes'),
(39, '2014-10-07 16:17:09', 'contact', 'Лидия Мишева', '\n			<b>Компания:</b> <br>\n			<b>Име:</b> Лидия Мишева<br>\n			<b>Адрес:</b> <br>\n			<b>Телефон:</b> <br>\n			<b>Електронна поща:</b> georgieva.lidia@abv.bg<br>\n			\n			<br>\n			\n			<b>Съобщение:</b><br><br>\n			\n			Здравейте.\r<br>Интересуваме предлагате ли магистърско обучение за професионални бакалаври? Моля за линк или телефон, на който мога да взема повече информация.', 'Yes');
