INSERT INTO `gallery_translations` (`gallery_id`, `language_id`, `title`, `published`, `menu_desc`, `short_desc`, `show_image`, `content`, `active`, `position`) VALUES
(1, 1, 'doeros.com', '2013-05-16', '', 'Всеки проект разработен от нас включва, проучване на спецификата на задачата, проектиране на дизайна, непосредственото създаване, тестване и доставяне на продукта. До момента сме реализирали системи в административната, търговската и развлекателна област, както и специализиран софтуер.', 'Yes', '<p>\r\n	DOEROS е създадена от специалисти с богат опит в проектирането и разработването на софтуерни продукти през последните 10 години.<br />\r\n	<br />\r\n	Екипът ни се състои от хора с различни интереси в областта на информационните технологии, участвали в създаването, както на web, така и на desktop приложения от различен мащаб.<br />\r\n	<br />\r\n	Всеки проект разработен от нас включва, проучване на спецификата на задачата, проектиране на дизайна, непосредственото създаване, тестване и доставяне на продукта. До момента сме реализирали системи в административната, търговската и развлекателна област, както и специализиран софтуер.<br />\r\n	<br />\r\n	Целта ни е да бъдем полезни на по-голям кръг от хора и фирми в сферата на икономиката и здравеопазването, както и на всички нуждаещи се от специфичен софтуерен продукт.<br />\r\n	<br />\r\n	Бихме се радвали да споделим опита и знанията си с Вас и да Ви бъдем полезни в реализирането на идеите Ви.<br />\r\n	<br />\r\n	Надяваме се, че ще работим заедно.<br />\r\n	<br />\r\n	&nbsp;</p>\r\n', 'Yes', 10),
(1, 2, 'doeros.com', '2013-05-16', '', 'Each project developed by us include study of the specifics of the task of design, direct the production, testing and delivery of the product. So far we have implemented systems in the administrative, commercial and entertainment district, and specialized software.', 'Yes', '<p>\r\n	<span id=\"result_box\" lang=\"en\"><span class=\"hps\">DOEROS</span> <span class=\"hps\">was created by professionals</span> <span class=\"hps\">with extensive experience in</span> <span class=\"hps\">the design and development</span> <span class=\"hps\">of software products</span> <span class=\"hps\">over the past 10</span> <span class=\"hps\">years.</span><br />\r\n	<br />\r\n	<span class=\"hps\">Our team</span> <span class=\"hps\">consists of people</span> <span class=\"hps\">with different interests</span> <span class=\"hps\">in the field</span> <span class=\"hps\">of information technology,</span> <span class=\"hps\">participated in the creation</span> <span class=\"hps\">of both</span> <span class=\"hps\">web,</span> <span class=\"hps\">and</span> <span class=\"hps\">desktop</span> <span class=\"hps\">applications</span> <span class=\"hps\">of</span> <span class=\"hps\">all sizes</span><span>.</span><br />\r\n	<br />\r\n	<span class=\"hps\">Each project</span> <span class=\"hps\">developed by</span> <span class=\"hps\">us</span> <span class=\"hps\">include</span> <span class=\"hps\">study</span> <span class=\"hps\">of the specifics</span> <span class=\"hps\">of the task</span> <span class=\"hps\">of design</span><span>,</span> <span class=\"hps\">direct</span> <span class=\"hps\">the production, testing</span> <span class=\"hps\">and delivery</span> <span class=\"hps\">of the product.</span> <span class=\"hps\">So far</span> <span class=\"hps\">we have implemented</span> <span class=\"hps\">systems</span> <span class=\"hps\">in the administrative</span><span>,</span> <span class=\"hps\">commercial and</span> <span class=\"hps\">entertainment</span> <span class=\"hps\">district</span><span>, and</span> <span class=\"hps\">specialized software.</span><br />\r\n	<br />\r\n	<span class=\"hps\">Our goal is</span> <span class=\"hps\">to be helpful to</span> <span class=\"hps\">a</span> <span class=\"hps\">large number of people</span> <span class=\"hps\">and firms</span> <span class=\"hps\">in the economy</span> <span class=\"hps\">and health care</span><span>, as well as</span> <span class=\"hps\">all those in need</span> <span class=\"hps\">of</span> <span class=\"hps\">a specific</span> <span class=\"hps\">software product.</span><br />\r\n	<br />\r\n	<span class=\"hps\">We would be glad</span> <span class=\"hps\">to share our experience</span> <span class=\"hps\">and</span> <span class=\"hps\">knowledge with</span> <span class=\"hps\">you and</span> <span class=\"hps\">be helpful to you</span> <span class=\"hps\">in realizing</span> <span class=\"hps\">your ideas</span><span>.</span><br />\r\n	<br />\r\n	<span class=\"hps\">We hope</span> <span class=\"hps\">that we will work</span> <span class=\"hps\">together.</span></span></p>\r\n', 'Yes', 10),
(3, 1, 'test.com', '2013-05-16', '', 'Това е примерен текст. Можете да го замените с желания от вас текст за страницата.', 'Yes', '<p>\r\n	<img alt=\"\" src=\"https://cs.fcst.bg/images/empty.jpg\" style=\"width: 300px; height: 196px; float: left; margin-right: 18px; margin-bottom: 12px; position: relative; top: 5px;\" /></p>\r\n<p>\r\n	&nbsp;</p>\r\n<p>\r\n	&nbsp;</p>\r\n<p>\r\n	&nbsp;</p>\r\n<p>\r\n	&nbsp;</p>\r\n<p>\r\n	&nbsp;</p>\r\n<p>\r\n	&nbsp;</p>\r\n<p>\r\n	&nbsp;</p>\r\n<p>\r\n	Това е примерен текст. Можете да го замените с желания от вас текст за страницата.</p>\r\n<p>\r\n	Lorem ipsum е един от най-често използваните в печатарството безсмислени текстове, служещи да запълват със съдържание онези елементи от графичния дизайн, в които иначе се предполага да стои дълъг свързан текст. На английски такъв вид текст се нарича dummy text или placeholder text, като на български и двата термина могат да се срещнат непреведени.</p>\r\n<p>\r\n	Текстът Lorem ipsum е безсмислен, но визуално много прилича на истински, заради разпределението и честотата на срещане на по-къси, средни и дълги думи, разпределението на интервалите и препинателните знаци, както и дължината на изреченията. Разнообразието му осигурява, че ако се случи да бъде размножен, за да изпълни предвиденото пространство, да не се получат шарки от сорта на моарето вследствие еднотипно редуване на думи и интервали. &bdquo;Налят&ldquo; по този начин в графичните блокове Lorem ipsum позволява на окото да се абстрахира от конкретиката на смисления текст, и да се съсредоточи само върху особеностите на използвания шрифт и неговото визуално въздействие върху читателя.</p>\r\n<h1>\r\n	Защо да го използваме?</h1>\r\n<p>\r\n	Известен факт е, че читателя обръща внимание на съдържанието, което чете, а не на оформлението му. Свойството на Lorem Ipsum е, че до голяма степен има нормално разпределение на буквите и се чете по-лесно, за разлика от нормален текст на английски език като &quot;Това е съдържание, това е съдържание&quot;. Много системи за публикуване и редактори на Уеб страници използват Lorem Ipsum като примерен текстов модел &quot;по подразбиране&quot;, поради което при търсене на фразата &quot;lorem ipsum&quot; в Интернет ще бъдат открити... <a href=\"http://bg.lipsum.com/\" target=\"_blank\">повече</a></p>\r\n', 'Yes', 20),
(3, 2, 'test.com', '2013-05-16', '', 'This is sample text. You can replace it with the text you want for the page.', 'Yes', '<p>\r\n	<img alt=\"\" src=\"https://cs.fcst.bg/images/empty.jpg\" style=\"width: 300px; height: 196px; float: left; margin-right: 18px; margin-bottom: 12px; position: relative; top: 5px;\" /></p>\r\n', 'Yes', 20);
