INSERT INTO `pages_translations` (`page_id`, `language_id`, `title`, `short_description`, `content`, `active`, `position`) VALUES
(1, 1, 'Катедра &quot;Компютърни системи&quot;', '', '<p style=\"text-align: center;\">\r\n	<a href=\"https://www.tu-sofia.bg/department/preview/27?dep_id=31\" target=\"_blank\">Състав</a> | <a href=\"https://www.tu-sofia.bg/department/preview/27?dep_id=31\" target=\"_blank\">Дисциплини</a>&nbsp;| <a href=\"https://www.tu-sofia.bg/department/preview/27?dep_id=31\" target=\"_blank\">Публикации</a></p>\r\n<p>\r\n	Катедра &ldquo;<em>Изчислителна техника</em>&rdquo; е създадена през 1969 год . От 1993 год. е преименувана в &ldquo;<em>Компютърни системи</em>&rdquo;. Катедрата обучава студенти за придобиване на образователно-квалификационните степени магистър и бакалавър по 5 специалности, чиято цел е да осигури на студентите най-съвременни знания в областта на компютърните инженерни науки и усъвършенствани умения, изисквани от днешния конкурентен пазар за успешна професионална реализация.</p>\r\n<p>\r\n	Катедра &quot;Компютърни системи&quot; предлага обучение по:</p>\r\n<ul>\r\n	<li>\r\n		Компютърно и софтуерно инженерство - бакалавър</li>\r\n	<li>\r\n		Компютърно и софтуерно инженерство - магистър</li>\r\n	<li>\r\n		Графичен и web дизайн - магистър</li>\r\n	<li>\r\n		Computer science and engineering - бакалавър на английски език</li>\r\n	<li>\r\n		Computer science and engineering - магистър на английски език</li>\r\n</ul>\r\n<p>\r\n	&nbsp;</p>\r\n', 'Yes', 10),
(1, 2, 'Department &quot;Computer Systems&quot;', '', '<div class=\"contentpaneopen clearfix\">\r\n	<div style=\"text-align: center;\">\r\n		<a href=\"https://www.tu-sofia.bg/department/preview/27?dep_id=31\" target=\"_blank\">Staff</a> | <a href=\"https://www.tu-sofia.bg/department/preview/27?dep_id=31\" target=\"_blank\">Courses</a> | <a href=\"https://www.tu-sofia.bg/department/preview/27?dep_id=31\" target=\"_blank\">Publications</a></div>\r\n	<div>\r\n		&nbsp;</div>\r\n	<div>\r\n		The Department of Computing was established in 1969. Since 1993 it has been renamed &quot;Computer Systems&quot;. The Department trains students for master&#39;s and bachelor&#39;s degrees in 5 specialties, the aim of which is to provide students with state-of-the-art knowledge in the field of computer engineering and advanced skills required by today&#39;s competitive market for successful professional realization.</div>\r\n	<div>\r\n		&nbsp;</div>\r\n	<div>\r\n		The Department of Computer Systems offers training in:</div>\r\n	<ul>\r\n		<li>\r\n			Computer and Software Engineering - Bachelor in Bulgarian</li>\r\n		<li>\r\n			Computer and Software Engineering - Master&nbsp;in Bulgarian</li>\r\n		<li>\r\n			Graphic and Web Design - Master&nbsp;in Bulgarian</li>\r\n		<li>\r\n			Computer science and engineering - Bachelor in English</li>\r\n		<li>\r\n			Computer science and engineering - MSc in English</li>\r\n	</ul>\r\n</div>\r\n<p>\r\n	&nbsp;</p>\r\n', 'Yes', 10),
(13, 2, 'Academic Staff of Computer Systems Department', '', '<p>\r\n	<img alt=\"\" src=\"https://cs.fcst.bg/userfiles/pages/KS_NewSmall.jpg\" style=\"width: 625px; height: 225px;\" /></p>\r\n<h3>\r\n	Professors</h3>\r\n<hr />\r\n<ul>\r\n	<li>\r\n		<span style=\"line-height: 1.3em;\">Professor, PhD Ognyan Nakov</span>&nbsp;- Dean of <span style=\"color: #555555; font-family: Arial, Helvetica, sans-serif; font-size: small;\"><span style=\"line-height: normal;\">FCSC</span></span></li>\r\n	<li>\r\n		<span style=\"line-height: 1.3em;\">Professor, PhD&nbsp;Plamenka Borovska</span>&nbsp;- Head of Computer Systems Department , FCSC</li>\r\n</ul>\r\n<h3>\r\n	Associated Professors&nbsp;</h3>\r\n<hr />\r\n<ul>\r\n	<li>\r\n		Assoc. Prof, PhD Adelina Alexieva - Petrova</li>\r\n	<li>\r\n		Assoc. Prof. PhD Asen Todorov</li>\r\n	<li>\r\n		Assoc. Prof, PhD&nbsp;Valentin Mollov</li>\r\n	<li>\r\n		Assoc. Prof, PhD&nbsp;Georgi Naidenov</li>\r\n	<li>\r\n		Assoc. Prof, PhD&nbsp;Georgi Popov</li>\r\n	<li>\r\n		Assoc. Prof, PhD&nbsp;Daniela Gotseva -Vice Dean for Academic part Profile &quot;Bachelor&quot;, FCSC</li>\r\n	<li>\r\n		Assoc. Prof, PhD Irina Noninska</li>\r\n	<li>\r\n		<span style=\"line-height: 1.3em;\">Assoc. Prof, PhD Milena Lazarova</span>&nbsp;- Vice Dean of &quot;Reserach &amp; Development&quot;, FCSC</li>\r\n	<li>\r\n		Assoc. Prof, PhDNikolay Nikolov</li>\r\n	<li>\r\n		Assoc. Prof, PhD&nbsp;Nadejda Angelova</li>\r\n	<li>\r\n		Assoc. Prof, PhD&nbsp;Peter Manoilov</li>\r\n	<li>\r\n		Assoc. Prof, PhD&nbsp;Petko Stoyanov - Deputy Head of Computer Systems Department, FCSC</li>\r\n	<li>\r\n		Assoc. Prof, PhD Roumen Trifonov - Vice Dean of Education Account &quot;Learning&quot;, FCSC</li>\r\n	<li>\r\n		Assoc. Prof, PhD&nbsp;Stoyan Bonev</li>\r\n	<li>\r\n		<span style=\"line-height: 1.3em;\">Assoc. Prof, PhD&nbsp;Segei Nedev</span></li>\r\n</ul>\r\n<h3>\r\n	Assistant Professors</h3>\r\n<hr />\r\n<ul>\r\n	<li>\r\n		<span style=\"line-height: 1.3em;\">Assist. Prof., PhD Antonia Tasheva</span></li>\r\n	<li>\r\n		<span style=\"line-height: 1.3em;\">Assist. Prof., PhD Diana Grigorova</span></li>\r\n	<li>\r\n		<span style=\"line-height: 1.3em;\">Assist. Prof. Georgi Zaprynanov</span></li>\r\n	<li>\r\n		<span style=\"line-height: 1.3em;\">Assist. Prof.&nbsp;Iva Nikolova</span></li>\r\n	<li>\r\n		<span style=\"line-height: 1.3em;\">Assist. Prof.&nbsp;PhD Ivailo Simeonov</span></li>\r\n	<li>\r\n		<span style=\"line-height: 1.3em;\">Assist. Prof.&nbsp;PhD Kiril Mechkov</span></li>\r\n	<li>\r\n		<span style=\"line-height: 1.3em;\">Assist. Prof.&nbsp;Kamelia Kuneva - Rainova&nbsp;</span></li>\r\n	<li>\r\n		<span style=\"line-height: 1.3em;\">Assist. Prof. Konstantin Kostadinov</span></li>\r\n	<li>\r\n		<span style=\"line-height: 1.3em;\">Assist. Prof. Pavlina Bikova</span></li>\r\n	<li>\r\n		<span style=\"line-height: 1.3em;\">Assist. Prof. Roumen Visokov</span></li>\r\n</ul>\r\n<h3>\r\n	Assistants</h3>\r\n<hr />\r\n<ul>\r\n	<li>\r\n		<span style=\"line-height: 1.3em;\">Assist. Vladimir Dimitrov</span></li>\r\n	<li>\r\n		Assist. Boyan Petrov</li>\r\n	<li>\r\n		Assist. PhD Desislava Ivanova</li>\r\n	<li>\r\n		<span style=\"line-height: 1.3em;\">Assist. Ivan Stankov</span></li>\r\n	<li>\r\n		Assist. PhD Simeon Tsvetanov</li>\r\n	<li>\r\n		Assist. Martin Filev</li>\r\n	<li>\r\n		Assist. Filip Petrov</li>\r\n	<li>\r\n		Assist. Hristo Gendov</li>\r\n</ul>\r\n', 'Yes', 130),
(4, 1, 'За контакти', '', '<div class=\"accordion\" id=\"slide-contact\">\r\n	<div class=\"accordion-group\">\r\n		<div class=\"accordion-heading\">\r\n			<strong><span class=\"accordion-toggle\">Данни за контакт</span></strong></div>\r\n		<div class=\"accordion-body in collapse\" id=\"basic-details\" style=\"height: auto;\">\r\n			<div class=\"accordion-inner\">\r\n				<div class=\"contact-address\">\r\n					<span class=\"jicons-icons\"><img alt=\"\" src=\"https://cs.fcst.bg/userfiles/pages/con_address.png\" style=\"width: 16px; height: 16px; float: left; margin: 15px; position:relative; top:10px;\" /></span><br />\r\n					<address>\r\n						<div>\r\n							Адрес: 1000 София, район &bdquo;Студентски&ldquo;, бул. &bdquo;Кл. Охридски&ldquo; № 8</div>\r\n						<div>\r\n							Канцелария на катедра &bdquo;Компютърни системи&ldquo; &ndash; Блок 1, Етаж: 4, Стая: 1441</div>\r\n						<div>\r\n							Телефон: (+359) 2 965-2484</div>\r\n						<div>\r\n							Работно време: Понеделник - Петък от 9.00 ч. до 16.30 ч.</div>\r\n					</address>\r\n				</div>\r\n			</div>\r\n		</div>\r\n	</div>\r\n</div>\r\n<p>\r\n	&nbsp;</p>\r\n', 'Yes', 40),
(4, 2, 'Contacts', '', '<div class=\"accordion\" id=\"slide-contact\">\r\n	<div class=\"accordion-group\">\r\n		<div class=\"accordion-heading\">\r\n			<strong><span class=\"accordion-toggle\">Contact</span></strong></div>\r\n		<div class=\"accordion-body in collapse\" id=\"basic-details\" style=\"height: auto;\">\r\n			<div class=\"accordion-inner\">\r\n				<div class=\"contact-address\">\r\n					<span class=\"jicons-icons\"><img alt=\"\" src=\"https://cs.fcst.bg/userfiles/pages/con_address.png\" style=\"width: 16px; height: 16px; float: left; margin: 15px; position:relative; top:10px;\" /></span><br />\r\n					<address>\r\n						<div>\r\n							Address: Sofia, Studentski Str.&quot;Kl.Ohridski&quot; № 8</div>\r\n						<div>\r\n							Block 1, Floor: 4, Room: 1441,</div>\r\n						<div>\r\n							Phone: (+359) 2 965-2484.</div>\r\n						<div>\r\n							Working hours: Monday - Friday from 9.00 a.m. to 4.30 p.m.</div>\r\n					</address>\r\n				</div>\r\n			</div>\r\n		</div>\r\n	</div>\r\n</div>\r\n', 'Yes', 40),
