(47, 1, 'Изпитна сесия - магистри', '', '<h1>\r\n	<b>График за учебната 2023/2024 година</b></h1>\r\n<h2>\r\n	&nbsp;</h2>\r\n<h2>\r\n	<b>Редовна сесия</b></h2>\r\n<hr />\r\n<table border=\"1\" cellpadding=\"5\" cellspacing=\"5\" style=\"width: 640px\">\r\n	<tbody>\r\n		<tr>\r\n			<td>\r\n				<b>Дисциплина</b></td>\r\n			<td>\r\n				<b>Лектор</b></td>\r\n			<td>\r\n				<strong style=\"text-align: center;\">Изпитна дата</strong></td>\r\n			<td>\r\n				<strong>Начален час</strong></td>\r\n			<td>\r\n				<strong>Зала</strong></td>\r\n		</tr>\r\n		<tr>\r\n			<td>\r\n				&nbsp;</td>\r\n			<td>\r\n				&nbsp;</td>\r\n			<td>\r\n				&nbsp;</td>\r\n			<td>\r\n				&nbsp;</td>\r\n			<td>\r\n				&nbsp;</td>\r\n		</tr>\r\n		<tr>\r\n			<td>\r\n				&nbsp;</td>\r\n			<td>\r\n				&nbsp;</td>\r\n			<td>\r\n				&nbsp;</td>\r\n			<td>\r\n				&nbsp;</td>\r\n			<td>\r\n				&nbsp;</td>\r\n		</tr>\r\n	</tbody>\r\n</table>\r\n<h2>\r\n	&nbsp;</h2>\r\n<h2>\r\n	<b>Редовна сесия - абсолвенти</b></h2>\r\n<hr />\r\n<table border=\"1\" cellpadding=\"5\" cellspacing=\"5\" style=\"width: 640px\">\r\n	<tbody>\r\n		<tr>\r\n			<td>\r\n				<b>Дисциплина</b></td>\r\n			<td>\r\n				<span style=\"font-weight: 700; text-align: center;\">Лектор</span></td>\r\n			<td>\r\n				<strong>Изпитна дата</strong></td>\r\n			<td>\r\n				<strong>Начален час</strong></td>\r\n			<td>\r\n				<span style=\"font-weight: 700; text-align: center;\">Зала</span></td>\r\n		</tr>\r\n		<tr>\r\n			<td>\r\n				&nbsp;</td>\r\n			<td>\r\n				&nbsp;</td>\r\n			<td>\r\n				&nbsp;</td>\r\n			<td>\r\n				&nbsp;</td>\r\n			<td>\r\n				&nbsp;</td>\r\n		</tr>\r\n		<tr>\r\n			<td>\r\n				&nbsp;</td>\r\n			<td>\r\n				&nbsp;</td>\r\n			<td>\r\n				&nbsp;</td>\r\n			<td>\r\n				&nbsp;</td>\r\n			<td>\r\n				&nbsp;</td>\r\n		</tr>\r\n	</tbody>\r\n</table>\r\n<h2>\r\n	&nbsp;</h2>\r\n<h2>\r\n	<b>Поправителна сесия</b></h2>\r\n<hr />\r\n<table border=\"1\" cellpadding=\"5\" cellspacing=\"5\" style=\"width: 640px\">\r\n	<tbody>\r\n		<tr>\r\n			<td>\r\