(26, 2, 'Diploma Thesis Forms', '', '<ul>\r\n	<li>\r\n		Bachelor (&nbsp;<a href=\\\"/userfiles/20232024/diplomni_zadania/Bsc_CS_ThesisAssignment_BG.dotx\\\" target=\\\"_blank\\\">BG</a>&nbsp;|&nbsp;<a href=\\\"/userfiles/20232024/diplomni_zadania/Bsc_CS_ThesisAssignment_EN.dotx\\\" target=\\\"_blank\\\">EN</a>)</li>\r\n	<li>\r\n		Master <a href=\\\"/userfiles/20232024/diplomni_zadania/Msc_CSE_ThesisAssignment_BG.dotx\\\" target=\\\"_blank\\\">(BG&nbsp;</a>|&nbsp;<a href=\\\"/userfiles/20232024/diplomni_zadania/Msc_CSE_ThesisAssignment_EN.dotx\\\" target=\\\"_blank\\\">EN</a>)</li>\r\n</ul>\r\n<p>\r\n	&nbsp;</p>\r\n', 'Yes', 230),
(8, 1, 'Обяви', '', '<h1>\r\n	Магистри - прием зимен семестър 2025/26</h1>\r\n<p>\r\n	Кат. &quot;Компютърни системи&quot; към факултет &bdquo;Компютърни системи и технологии&ldquo; предлага следните магистърски програми:</p>\r\n<ul>\r\n	<li>\r\n		&quot;Компютърно и софтуерно инженерство&ldquo; - едногодишно обучение</li>\r\n	<li>\r\n		&quot;Компютърно и софтуерно инженерство&ldquo; - двугодишно обучение</li>\r\n</ul>\r\n<p>\r\n	Срокът за подаване на документи за всички специалности в ОКС &bdquo;магистър&ldquo; чрез конкурс по документи е от 4.09.2025 г. до 30.09.2025 г. вкл.</p>\r\n<p>\r\n	Подаването и приемът на документи за магистърските програми на кат. &quot;Компютърни системи&quot; при ФКСТ се осъществява по избор от страна на кандидата в една от двете посочени по-долу форми:&nbsp;</p>\r\n<ul>\r\n	<li>\r\n		<a href=\"https://script.google.com/macros/s/AKfycbxiyTq0jEl45-hcTY4C7hdnevfeI3dFCNWn6ZMZu3XExVhl9lP2_u5EOH1m3UVhr-L7/exec\">Онлайн подаване на документи</a>&nbsp;(от 04.09.2025 до 30.09.2025 г.)</li>\r\n	<li>\r\n		<a href=\"https://cs.fcst.bg/page.php?id=32\" target=\"_blank\">Подаване на документи на място</a>&nbsp;(от 9.09.2025 до 30.09.2025 г.)</li>\r\n</ul>\r\n<p>\r\n	За повече информация относно магистърските програми, условия, документи, такси и начини на кандидатстване вижте&nbsp; &quot;<a href=\"https://cs.fcst.bg/page.php?id=21\">Кандидатстване в магистърски програми&quot;</a></p>\r\n<p>\r\n	&nbsp;</p>\r\n', 'Yes', 80),
(52, 1, 'Кандидат-студентски прием в магистърски програми за новата учебна  2014-2015 година', '', '<p>\r\n	ФАКУЛТЕТ по КОМПЮТЪРНИ СИСТЕМИ и УПРАВЛЕНИЕ и Катедра &quot;КОМПЮТЪРНИ СИСТЕМИ&quot; обявяват прием в магистърско обучение за новата учебна 2014-2015 година</p>\r\n<ul>\r\n	<li>\r\n		<a href=\"https://cs.fcst.bg/page.php?id=35\">Срокове</a></li>\r\n	<li>\r\n		<a href=\"https://cs.fcst.bg/page.php?id=31\">Специалности</a></li>\r\n	<li>\r\n		За въпроси и контакти&nbsp;<a href=\"https://cs.fcst.bg/page.php?id=48\">ТУК</a></li>\r\n</ul>\r\n<p>\r\n	Обучението в магистърската програма по &quot;<strong>Информационни Технологии</strong>&quot; е организирано съвместно с водещи фирми от ИТ сектора и техни специалисти, които ще участват в учебния процес.</p>\r\n<p>\r\n	<img alt=\"\" src=\"https://cs.fcst.bg/userfiles/Magistri_AplicationForms/Master-IT.png\" style=\"width: 630px; height: 603px;\" /></p>\r\n', 'No', 470),
(39, 1, 'ПРОЕКТ BG051PO001-4.3.04-0044 „Формални и неформални електронни форми за дистанционно обучение по „Компютърни науки””', '', '<p>\r\n	&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;</p>\r\n<p align=\"center\">\r\n	<em>Проектът се осъществява с финансовата подкрепа на</em></p>\r\n<p align=\"center\">\r\n	<em>Оперативна програма &bdquo;Развитие на човешките ресурси&rdquo;,2007-2013,</em></p>\r\n<p align=\"center\">\r\n	<em>съфинансирана от Европейския социален фонд на Европейския съюз</em></p>\r\n<p align=\"center\">\r\n	Инвестира във вашето бъдеще!</p>\r\n<table align=\"center\" border=\"0\" cellpadding=\"3\" cellspacing=\"3\" style=\"width: 500px;\">\r\n	<tbody>\r\n		<tr>\r\n			<td>\r\n				<img alt=\"\" height=\"85\" src=\"https://cs.fcst.bg/userfiles/ESF_logo_BG.jpg\" width=\"120\" /></td>\r\n			<td style=\"text-align: right;\">\r\n				<img alt=\"\" height=\"82\" src=\"https://cs.fcst.bg/userfiles/EU_logo_BG.jpg\" width=\"105\" /></td>\r\n		</tr>\r\n	</tbody>\r\n</table>\r\n<ul>\r\n	<li style=\"margin-left: 0.38in;\">\r\n		Приоритетна ос 4: Подобряване на достъпа до образование и обучение</li>\r\n	<li style=\"margin-left: 0.38in;\">\r\n		Мярка на област на въздействие 4.3: Развитие на системата за учене през целия живот&nbsp;</li>\r\n	<li style=\"margin-left: 0.38in;\">\r\n		Бенефициент: Технически университет - София, чрез Факултет Компютърни системи и управление</li>\r\n	<li style=\"margin-left: 0.38in;\">\r\n		<p>\r\n			Ръководител на проекта: проф. д-р Огнян Наков</p>\r\n	</li>\r\n	<li style=\"margin-left: 0.38in;\">\r\n		<p>\r\n			Срок за изпълнение: 10.10.2012 - 10.10.2014 г.</p>\r\n	</li>\r\n	<li style=\"margin-left: 0.38in;\">\r\n		Обща стойност: 790 628,81 лв.</li>\r\n</ul>\r\n<div style=\"margin-left:.38in;\">\r\n	&nbsp;</div>\r\n<h1>\r\n	Цел на проекта:</h1>\r\n<p>\r\n	Основната цел е да се подпомогне инженерната специалност &bdquo;Компютърни науки&ldquo; с различни формални и неформални електронни форми на обучение, които да допринесат за по-качествено и гъвкаво обучение през целия живот на човек.</p>\r\n<h1>\r\n	Целеви групи</h1>\r\n<ul>\r\n	<li style=\"margin-left: 0.38in;\">\r\n		Основна целева група:</li>\r\n</ul>\r\n<div style=\"margin-left:.38in;\">\r\n	Студенти от ФКСТ в ОКС &lsquo;бакалавър&rsquo; и &lsquo;магистър&rsquo; в професионалните направления КСТ.</div>\r\n<div style=\"margin-left:.81in;\">\r\n	&nbsp;</div>\r\n<ul>\r\n	<li style=\"margin-left: 0.38in;\">\r\n		Допълнителна целева група:</li>\r\n</ul>\r\n<div style=\"margin-left:.38in;\">\r\n	Представители на преподавателския, административния и техническия състав във ФКСТ.</div>\r\n<div style=\"margin-left:.81in;\">\r\n	&nbsp;</div>\r\n<p style=\"margin-left:.13in;\">\r\n	Непряко се обхващат всички потенциални и фактически студенти и преподаватели на ТУ-София, които в бъдеще желаят да разработват и прилагат в своята работа електронни форми за дистанционно обучение.</p>\r\n<p style=\"margin-left:.13in;\">\r\n	&nbsp;</p>\r\n<h1>\r\n	Индикатори за изпълнение &ndash; основни резултати от&nbsp; проекта:</h1>\r\n<div style=\"margin-left:.81in;\">\r\n	&ndash; разработване на бакалавърска и магистърска програма по &bdquo;Компютърни науки&rdquo; за електронни форми на дистанционно обучение;</div>\r\n<div style=\"margin-left:.81in;\">\r\n	&ndash; създаване над 150 вида електронни ресурси от базови и специализирани електронни курсове в областта на компютърните науки;</div>\r\n<div style=\"margin-left:.81in;\">\r\n	&ndash; създаване на две виртуални лаборатории по &bdquo;Високопроизводителни изчисления и GRID технологиите&ldquo; и&nbsp; &bdquo;Управление на системи в реално време&ldquo;;</div>\r\n<div style=\"margin-left:.81in;\">\r\n	&ndash; модернизиране на зала с високотехнологични решения за видеоконферентни връзки и възможност за създаване на висококачествени видео ресурси.</div>\r\n', 'Yes', 350),
(7, 2, 'Terms', NULL, '<p>\r\n	<img alt=\"\" src=\"https://cs.fcst.bg/images/empty.jpg\" style=\"width: 300px; height: 196px; float: left; margin-right: 18px; margin-bottom: 12px; position: relative; top: 5px;\" />Това е примерен текст. Можете да го замените с желания от вас текст за страницата.</p>\r\n<p>\r\n	Lorem ipsum е един от най-често използваните в печатарството безсмислени текстове, служещи да запълват със съдържание онези елементи от графичния дизайн, в които иначе се предполага да стои дълъг свързан текст. На английски такъв вид текст се нарича dummy text или placeholder text, като на български и двата термина могат да се срещнат непреведени.</p>\r\n<p>\r\n	Текстът Lorem ipsum е безсмислен, но визуално много прилича на истински, заради разпределението и честотата на срещане на по-къси, средни и дълги думи, разпределението на интервалите и препинателните знаци, както и дължината на изреченията. Разнообразието му осигурява, че ако се случи да бъде размножен, за да изпълни предвиденото пространство, да не се получат шарки от сорта на моарето вследствие еднотипно редуване на думи и интервали. &bdquo;Налят&ldquo; по този начин в графичните блокове Lorem ipsum позволява на окото да се абстрахира от конкретиката на смисления текст, и да се съсредоточи само върху особеностите на използвания шрифт и неговото визуално въздействие върху читателя.</p>\r\n<h1>\r\n	Защо да го използваме?</h1>\r\n<p>\r\n	Известен факт е, че читателя обръща внимание на съдържанието, което чете, а не на оформлението му. Свойството на Lorem Ipsum е, че до голяма степен има нормално разпределение на буквите и се чете по-лесно, за разлика от нормален текст на английски език като &quot;Това е съдържание, това е съдържание&quot;. Много системи за публикуване и редактори на Уеб страници използват Lorem Ipsum като примерен текстов модел &quot;по подразбиране&quot;, поради което при търсене на фразата &quot;lorem ipsum&quot; в Интернет ще бъдат открити... <a href=\"http://bg.lipsum.com/\" target=\"_blank\">повече</a></p>\r\n', 'Yes', 70),
(8, 2, 'Аnnouncements', '', '<p>\r\n	Аnnouncements</p>\r\n', 'Yes', 80),
(7, 1, 'Условия за ползване', '', '<p>\r\n	&nbsp;</p>\r\n<p>\r\n	&nbsp;</p>\r\n', 'Yes', 70),
(9, 1, 'Бакалавърски програми', '', '<p>\r\n	Бакалавърското обучение във ФКСТ се провежда по специалностите:<br />\r\n	&nbsp;</p>\r\n<p>\r\n	<img alt=\"\" src=\"https://cs.fcst.bg/userfiles/pages/readingstudents.jpg\" style=\"width: 200px; height: 173px; float: left; margin-right:40px;\" /></p>\r\n<p>\r\n	&nbsp;</p>\r\n<p>\r\n	<strong>&quot;Компютърно и софтуерно инженерство&quot;<br />\r\n	<br />\r\n	&quot;Компютърни науки и инженерство&quot;<br />\r\n	<br />\r\n	&quot;Информационни технологии в транспорта&quot;<br />\r\n	<br />\r\n	&quot;Математика и компютърни науки&quot;</strong><br />\r\n	&nbsp;</p>\r\n<p>\r\n	&nbsp;</p>\r\n<p>\r\n	Обучението по специалностите <strong>&bdquo;Компютърни науки и инженерство</strong>&rdquo;, &quot;<strong>Информационни технологии в транспорта</strong>&quot; и <strong>&rdquo;Математика и компютърни науки</strong>&rdquo; се провежда на <strong>английски език</strong> и е ориентирано към чуждестранни студенти.</p>\r\n<p>\r\n	Обучението по специалността &quot;<strong>Информационни технологии в транспорта</strong>&quot; се провежда съвместно с <strong>Транспортен факултет при ТУ-София</strong>. Обучението и по четирите специалности за образователно-квалификационната степен бакалавър е с продължителност 4 години (8 семестъра) и има за цел да осигури високо професионална подготовка в области, свързани с проектирането, използването и внедряването на компютри, компютърни системи и информационни технологии в съответствие със съвременните бързо развиващи се компютърни системи.</p>\r\n<p style=\"text-align: justify;\">\r\n	Обучението по бакалавърските специалности предоставя голяма адаптивност в пазарна среда, позволяваща поддържане на придобитите знания и умения в съответствие с бъдещото развитието на компютърните системи и технологии. Завършващите студенти придобиват професионалната квалификационна степен компютърен инженер &ndash; бакалавър и са готови да покриват широките потребности от инженери по компютърни системи и технологии.</p>\r\n<p style=\"text-align: justify;\">\r\n	Обучението по бакалавърските специалности предоставя голяма адаптивност в пазарна среда, позволяваща поддържане на придобитите знания и умения в съответствие с бъдещото развитието на компютърните системи и технологии. Завършващите студенти придобиват професионалната квалификационна степен компютърен инженер &ndash; бакалавър и са готови да покриват широките потребности от инженери по компютърни системи и технологии. Специалност &rdquo;Математика и компютърни науки&rdquo;.</p>\r\n<p style=\"text-align: justify;\">\r\n	<span style=\"font-size: 10pt;\">Oбучението по специалността &rdquo;</span><strong style=\"font-size: 10pt;\">Математика и компютърни науки</strong><span style=\"font-size: 10pt;\">&rdquo; е съвместна инициатива с </span><strong style=\"font-size: 10pt;\">Факултета по математика и информатика при Софийски университет &ldquo;Климент Охридски&rdquo;</strong><span style=\"font-size: 10pt;\"> и има за цел да осигури високо-професионална подготовка и изграждане на специалисти със солидни фундаментални познания в областта на математиката и с приложно-инженерни умения и знания в областта на компютърните науки.</span></p>\r\n<p style=\"text-align: justify;\">\r\n	&nbsp;</p>\r\n<h3>\r\n	Специалности и учебни програми&nbsp;</h3>\r\n<hr />\r\n<table border=\"0\">\r\n	<tbody>\r\n		<tr>\r\n			<td>\r\n				<strong>СПЕЦИАЛНОСТ</strong></td>\r\n			<td>\r\n				<strong>РЕДОВНО ОБУЧЕНИЕ</strong></td>\r\n		</tr>\r\n		<tr>\r\n			<td>\r\n				1. Компютърни системи и технологии</td>\r\n			<td>\r\n				<a href=\"http://www.tu-sofia.bg/UPlan/UPlan-FKSU-KST-2010-bak.pdf\">бакал. kурс 2, 3 и 4 (5.3.)</a></td>\r\n		</tr>\r\n		<tr>\r\n			<td>\r\n				2. Компютърно и софтуерно инженерство (2013/2014)</td>\r\n			<td>\r\n				<a href=\"http://www.tu-sofia.bg/UPlan/UPlan-FKSU-BCSE-BG.pdf\">бакал.(5.3.)</a></td>\r\n		</tr>\r\n		<tr>\r\n			<td>\r\n				3. Информационни технологии</td>\r\n			<td>\r\n				-</td>\r\n		</tr>\r\n		<tr>\r\n			<td>\r\n				4. Компютърни технологии и приложно програмиранe</td>\r\n			<td>\r\n				-</td>\r\n		</tr>\r\n		<tr>\r\n			<td>\r\n				5. Компютърни технологии в нематериалната сфера(компютърна визуализация и мултимедия)</td>\r\n			<td>\r\n				-</td>\r\n		</tr>\r\n		<tr>\r\n			<td>\r\n				6. Компютърни науки (на английски език)</td>\r\n			<td>\r\n				<a href=\"http://www.tu-sofia.bg/UPlan/UPlan-FKSU-CS-2010-bak-Eng-2k.pdf\">бакал. курс 4 (5.3.)</a><br />\r\n				<a href=\"http://www.tu-sofia.bg/UPlan/UPlan-FKSU-CS-2010-bak-Eng-1k.pdf\">бакал. курс 2 и 3 (5.3.)</a></td>\r\n		</tr>\r\n		<tr>\r\n			<td>\r\n				7. Компютърни науки и инженерство (2013/2014)(на английски език)</td>\r\n			<td>\r\n				<a href=\"http://www.tu-sofia.bg/UPlan/UPlan-FKSU-BCSCe-BG.pdf\">бакал.(5.3.)</a></td>\r\n		</tr>\r\n		<tr>\r\n			<td>\r\n				8. Информационни технологии в транспорта(на английски език)</td>\r\n			<td>\r\n				<a href=\"http://www.tu-sofia.bg/UPlan/UPlan-FKSU-ITT-bak_BG.pdf\">бакалавър (5.3.) и (5.5.)</a></td>\r\n		</tr>\r\n	</tbody>\r\n</table>\r\n<p>\r\n	&nbsp;</p>\r\n', 'Yes', 90),
(10, 1, 'Магистърски програми', '', '<p>\r\n	Кандидат студентски прием за учебната 2023 / 2024 има за следните магистърски програми:</p>\r\n<table border=\\\"0\\\" cellpadding=\\\"1\\\" cellspacing=\\\"1\\\">\r\n	<tbody>\r\n		<tr>\r\n			<td>\r\n				<img alt=\\\"\\\" src=\\\"https://cs.fcst.bg/userfiles/pages/students.png\\\" style=\\\"width: 228px; height: 152px;\\\" /></td>\r\n			<td>\r\n				<ul>\r\n					<li>\r\n						&bdquo;Компютърно и софтуерно инженерство&ldquo; - едногодишно обучение</li>\r\n					<li>\r\n						&bdquo;Компютърно и софтуерно инженерство&ldquo; -двугодишно обучение</li>\r\n					<li>\r\n						&quot;Графичен и уеб дизайн&quot; - едногодишно обучение</li>\r\n					<li>\r\n						&quot;Компютърни науки и инженерство (на английски език) - едногодишно обучение</li>\r\n				</ul>\r\n			</td>\r\n		</tr>\r\n	</tbody>\r\n</table>\r\n<p>\r\n	&nbsp;</p>\r\n<hr />\r\n<table border=\\\"0\\\" cellpadding=\\\"3\\\" cellspacing=\\\"3\\\">\r\n	<tbody>\r\n		<tr>\r\n			<td valign=\\\"top\\\">\r\n				<img alt=\\\"\\\" src=\\\"https://cs.fcst.bg/userfiles/pages/important1.png\\\" style=\\\"width: 60px; height: 50px;\\\" /></td>\r\n			<td>\r\n				<p>\r\n					Обучението във всички специалности е само&nbsp;<strong>редовно</strong>.</p>\r\n			</td>\r\n		</tr>\r\n	</tbody>\r\n</table>\r\n<hr />\r\n<p>\r\n	За по-подробна информация може да разгледате учебните планове &nbsp;и кратки характеристики на изучаваните дисциплини на:</p>\r\n<p>\r\n	&nbsp;- Специалност &quot;<strong>Компютърно и софтуерно инженерство&quot;</strong></p>\r\n<ul>\r\n	<li>\r\n		Учебен план</li>\r\n	<li>\r\n		Характеристики на дисциплините</li>\r\n</ul>\r\n<p>\r\n	<strong>&nbsp;-</strong><span class=\\\"nolink\\\">&nbsp;Специалност&nbsp;</span>&quot;<b>Графичен и web дизайн&quot;</b></p>\r\n<ul>\r\n	<li>\r\n		Учебен план</li>\r\n	<li>\r\n		<span class=\\\"nolink\\\">Характеристики на изучаваните дисциплини</span></li>\r\n</ul>\r\n', 'Yes', 100),
(11, 1, 'Докторски програми', '', '<h3>\r\n	Информация за докторските програми на обучение ще бъде достъпна на по-късен етап.</h3>\r\n<p>\r\n	<img alt=\"\" src=\"https://cs.fcst.bg/userfiles/pages/application_icon_PHD.jpg\" style=\"width: 185px; height: 242px;\" /></p>\r\n', 'Yes', 110),
(19, 1, 'Академични календари', '', '<p>\r\n	<img alt=\"\" src=\"https://cs.fcst.bg/userfiles/pages/calendar_i.png\" style=\"width: 143px; height: 107px; float: left; margin-right: 40px;\" /></p>\r\n<p style=\"text-align: justify;\">\r\n	<a href=\"http://www.tu-sofia.bg/university/calendar\" target=\"_blank\">Календарен график на учебния процес за учебната&nbsp;2014/2015 година за степени &quot;бакалавър&quot; и &quot;магистър&quot;<!--а--></a></p>\r\n', 'Yes', 190),
(20, 1, 'Студентски практики и стажове', '', '<h3>\r\n	Практики и стажове във водещи фирми в ИТ сектора</h3>\r\n<hr />\r\n<p>\r\n	&nbsp;<a href=\\\"http://81.161.243.12/bgmoodle/mod/page/view.php?id=2192\\\" target=\\\"_blank\\\">Относно методиката за провеждане прочетете тук &gt;&gt;</a></p>\r\n<p>\r\n	<br />\r\n	<img alt=\\\"\\\" src=\\\"https://cs.fcst.bg/userfiles/logos/sap.gif\\\" style=\\\"width: 156px; height: 81px;\\\" /><img alt=\\\"\\\" src=\\\"https://cs.fcst.bg/userfiles/logos/DataProcessing.jpg\\\" style=\\\"width: 285px; height: 57px;\\\" /></p>\r\n<p>\r\n	<img alt=\\\"\\\" src=\\\"https://cs.fcst.bg/userfiles/logos/hostbg.png\\\" style=\\\"width: 200px; height: 81px;\\\" /></p>\r\n<p>\r\n	<img alt=\\\"\\\" src=\\\"https://cs.fcst.bg/userfiles/logos/global_teracomm_logo.png\\\" style=\\\"width: 199px; height: 75px;\\\" /><img alt=\\\"\\\" src=\\\"https://cs.fcst.bg/userfiles/logos/MediaBasket.jpg\\\" style=\\\"width: 206px; height: 81px;\\\" /><img alt=\\\"\\\" src=\\\"https://cs.fcst.bg/userfiles/logos/wg_logo.jpg\\\" style=\\\"width: 99px; height: 97px;\\\" /></p>\r\n<p>\r\n	<img alt=\\\"\\\" src=\\\"https://cs.fcst.bg/userfiles/logos/kipo.jpg\\\" style=\\\"width: 284px; height: 177px;\\\" /></p>\r\n', 'No', 200),
(13, 1, 'Преподавателски състав', '', '<h3>\r\n	Професори</h3>\r\n<hr />\r\n<ul>\r\n	<li>\r\n		<span style=\"line-height: 1.3em;\">Професор, Д-р Огнян Наков</span>&nbsp;- декан ФКСТ</li>\r\n	<li>\r\n		<span style=\"line-height: 1.3em;\">Професор, Д-р Пламенка Боровска</span>&nbsp;- ръководител катедра &quot;Компютърни системи&quot;, ФКСТ</li>\r\n</ul>\r\n<h3>\r\n	Доценти</h3>\r\n<hr />\r\n<ul>\r\n	<li>\r\n		<a href=\"https://cs.fcst.bg/page.php?id=44&amp;language=bg\" target=\"_blank\">Доц. Д-р Аделина Алексиева - Петрова</a></li>\r\n	<li>\r\n		Доц. Д-р Асен Тодоров</li>\r\n	<li>\r\n		Доц. Д-р Валентин Моллов</li>\r\n	<li>\r\n		Доц. Д-р Георги Найденов</li>\r\n	<li>\r\n		Доц. Д-р Георги Попов</li>\r\n	<li>\r\n		Доц. Д-р Даниела Гоцева - зам. декан по Учебна дейност, профил &quot;Бакалаври&quot;</li>\r\n	<li>\r\n		Доц. Д-р Ирина Нонинска</li>\r\n	<li>\r\n		<span style=\"line-height: 1.3em;\">Доц. Д-р Милена Лазарова</span>&nbsp;- зам. декан по &quot;Научна и приложна дейност&quot;, ФКСТ</li>\r\n	<li>\r\n		Доц. Д-р Николай Николов</li>\r\n	<li>\r\n		Доц. Д-р Надежда Ангелова</li>\r\n	<li>\r\n		Доц. Д-р Петър Маноилов</li>\r\n	<li>\r\n		Доц. Д-р Петко Стоянов&nbsp;- зам. ръководител катедра &quot;Компютърни системи&quot;, ФКСТ</li>\r\n	<li>\r\n		Доц. Д-р Румен Трифонов&nbsp;- зам. декан по Учебна дейност, профил &quot;Чуждоезиково обучение&quot;, ФКСТ</li>\r\n	<li>\r\n		Доц. Д-р Стоян Бонев</li>\r\n	<li>\r\n		<span style=\"line-height: 1.3em;\">Доц. Д-р Сергей Недев</span></li>\r\n</ul>\r\n<h3>\r\n	Главни асистенти</h3>\r\n<hr />\r\n<ul>\r\n	<li>\r\n		<span style=\"line-height: 1.3em;\">Гл. ас. Д-р Антония Ташева</span></li>\r\n	<li>\r\n		<span style=\"line-height: 1.3em;\">Гл. ас. Д-р Диана Григорова</span></li>\r\n	<li>\r\n		<span style=\"line-height: 1.3em;\">Гл. ас. Георги Запрянов</span></li>\r\n	<li>\r\n		<a href=\"https://cs.fcst.bg/page.php?id=45&amp;language=bg\"><span style=\"line-height: 1.3em;\">Гл. ас. Ива Николова</span></a></li>\r\n	<li>\r\n		<span style=\"line-height: 1.3em;\">Гл. ас. Д-р Ивайло Симеонов</span></li>\r\n	<li>\r\n		<span style=\"line-height: 1.3em;\">Гл. ас. Д-р Кирил Мечков</span></li>\r\n	<li>\r\n		<span style=\"line-height: 1.3em;\">Гл. ас. Камелия Кънева - Райнова&nbsp;</span></li>\r\n	<li>\r\n		<span style=\"line-height: 1.3em;\">Гл. ас. Константин Костадинов</span></li>\r\n	<li>\r\n		<span style=\"line-height: 1.3em;\">Гл. ас. Павлина Бикова</span></li>\r\n	<li>\r\n		<span style=\"line-height: 1.3em;\">Гл. ас. Румен Високов</span></li>\r\n</ul>\r\n<h3>\r\n	Асистенти</h3>\r\n<hr />\r\n<ul>\r\n	<li>\r\n		<span style=\"line-height: 1.3em;\">Ас. Владимир Димитров</span></li>\r\n	<li>\r\n		Ас. Боян Петров</li>\r\n	<li>\r\n		Ас. Д-р Десислава Иванова</li>\r\n	<li>\r\n		<span style=\"line-height: 1.3em;\">Ас. Иван Станков</span></li>\r\n	<li>\r\n		Ас. Д-р Симеон Цветанов</li>\r\n	<li>\r\n		Ас. Мартин Филев</li>\r\n	<li>\r\n		Ас. Филип Петров</li>\r\n	<li>\r\n		Ас. Христо Гендов</li>\r\n</ul>\r\n', 'Yes', 130),
(14, 1, 'Научна дейност', '', '<h3>\r\n	Актуални проекти</h3>\r\n<hr />\r\n<ul>\r\n	<li>\r\n		<h3>\r\n			<strong><span style=\"line-height: 1.3em;\">Проект Формални и неформални електронни форми за дистанционно обучение по &quot;Компютърни науки&quot;</span></strong><br />\r\n			<br />\r\n			&nbsp;</h3>\r\n	</li>\r\n</ul>\r\n<p>\r\n	<img alt=\"\" src=\"https://cs.fcst.bg/userfiles/pages/ESF_logo_BG.jpg\" style=\"width: 160px; height: 95px; float: left; margin-right: 120px;\" /><img alt=\"\" src=\"https://cs.fcst.bg/userfiles/pages/EU_logo_BG.jpg\" style=\"width: 122px; height: 95px; float: left;\" /></p>\r\n<p>\r\n	&nbsp;</p>\r\n<p>\r\n	&nbsp;</p>\r\n<p>\r\n	&nbsp;</p>\r\n<p>\r\n	<br />\r\n	&nbsp;</p>\r\n<p style=\"text-align: justify;\">\r\n	Подписан е договор за срок от 24 месеца между Факултет Компютърни системи и управление, ТУ-София и МОМН по Оперативна програма &bdquo;Развитие на човешките ресурси&rdquo; за предоставяне на безвъзмездна финансова помощ, по схема BG051PO001-4.3.04 &bdquo;<strong>Развитие на електронни форми на дистанционно обучение в системата на висшето образование</strong>&rdquo; в рамките на приоритетна ос 4 от Оперативна програма &bdquo;<strong>Развитие на човешките ресурси</strong>&rdquo;.</p>\r\n<p style=\"text-align: justify;\">\r\n	Проектът се осъществява с финансовата подкрепа на Оперативна програма &bdquo;Развитие на човешките ресурси&rdquo;, съфинансирана от Европейския социален фонд на Европейския съюз.</p>\r\n<p style=\"text-align: justify;\">\r\n	Ръководител на проекта: <strong>проф. д-р Огнян Наков</strong></p>\r\n<h3>\r\n	&nbsp;</h3>\r\n<h3>\r\n	Минали проекти</h3>\r\n<hr />\r\n<ul>\r\n	<li>\r\n		<h3>\r\n			<strong><span>Проект Blue Vision</span></strong></h3>\r\n	</li>\r\n</ul>\r\n<p style=\"text-align: justify;\">\r\n	Проект Blue Vision&nbsp;(обработване на мултиспектрални данни от дистанционно сондиране на Земята) има за цел да детектира и предотврати природни бедствия посредством дистанционни наблюдения на земната повърхност.</p>\r\n<ul>\r\n	<li>\r\n		<h3>\r\n			<strong><span>Проект TRICE (Training, Research, Innovations in Computer Education)</span></strong></h3>\r\n	</li>\r\n</ul>\r\n<p align=\"left\" style=\"text-align: justify;\">\r\n	Проектът<strong>&nbsp;<a href=\"http://trice.ecs.ru.acad.bg/\" style=\"color: #0244c5;\" target=\"_blank\">TRICE (Training, Research, Innovations in Computer Education)</a></strong> има за цел да подобри взаимодействието и сътрудничеството между университетите от една страна и компаниите и фирмите в областта на информационните технологии и компютърното инженерство, от друга. Катедрата &quot;Компютърни Системи&quot; е един от 70-те партньори по този европейски проект.</p>\r\n<ul>\r\n	<li>\r\n		<h3>\r\n			<strong><span>Научно-изследователски проекти към НИС &ndash; ТУ-София:</span></strong></h3>\r\n	</li>\r\n</ul>\r\n<p>\r\n	<span style=\"line-height: 1.3em;\">548 НИ-9 &ldquo;</span><strong style=\"line-height: 1.3em;\">Проблеми с идентификацията на контролирани събития в системите за сигурност</strong><span style=\"line-height: 1.3em;\">&rdquo;, ръководител <strong>доц.д-р Асен Тодоров</strong></span></p>\r\n<p>\r\n	<span style=\"line-height: 1.3em;\">549 НИ-9 &ldquo;</span><strong style=\"line-height: 1.3em;\">Изследване на протоколи за маршрутизация</strong><span style=\"line-height: 1.3em;\">&rdquo;, ръководител <strong>доц. д-р Н. Николов</strong></span></p>\r\n<p>\r\n	<span style=\"line-height: 1.3em;\">550 НИ-9 &ldquo;</span><strong style=\"line-height: 1.3em;\">Неконвенционални компютърни архитектури за провеждане и анализ на паралелни изчисления</strong><span style=\"line-height: 1.3em;\">&rdquo;, ръководител <strong>доц. д-р О. Наков</strong></span></p>\r\n<p>\r\n	<span style=\"line-height: 1.3em;\">582 ПД &ldquo;</span><strong style=\"line-height: 1.3em;\">Паралелни компютърни архитектури с многонишкова обработка</strong><span style=\"line-height: 1.3em;\">&rdquo;, ръководител <strong>доц. д-р Пламенка Боровска</strong></span></p>\r\n<p>\r\n	<span style=\"line-height: 1.3em;\">613 ИМ-9 &ldquo;</span><strong style=\"line-height: 1.3em;\">Университетска информационна система &ndash; модул Научна и приложна дейност</strong><span style=\"line-height: 1.3em;\">&rdquo;, ръководител <strong>доц. д- р Ангел Ангелов</strong></span></p>\r\n<p>\r\n	<span style=\"line-height: 1.3em;\">411 НК-9 &ldquo;</span><strong style=\"line-height: 1.3em;\">Единна среда за провеждане и анализ на алгоритми</strong><span style=\"line-height: 1.3em;\">&rdquo;, ръководител <strong>доц. д-р О. Наков</strong></span></p>\r\n<p>\r\n	<span style=\"line-height: 1.3em;\">409 НК-9 &ldquo;</span><strong style=\"line-height: 1.3em;\">Изследване на влиянието на характеристиките на компютърна мрежа на мултикомпютърни платформи върху бързодействието на паралелни алгоритми</strong><span style=\"line-height: 1.3em;\">&rdquo;, ръководител <strong>доц. д-р Пламенка Боровска</strong></span></p>\r\n<p>\r\n	<span style=\"line-height: 1.3em;\">599 НФ-9 <strong>Проект за частично финансиране на втора международна научна конференция &ldquo;Компютърни науки 2005&rdquo;</strong>, ръководител <strong>доц. д-р Пламенка Боровска</strong></span></p>\r\n', 'Yes', 140),
(15, 1, 'Канцеларии', '', '<h1 style=\\\"text-align: center;\\\">\r\n	Деканска канцелария</h1>\r\n<table align=\\\"center\\\" bgcolor=\\\"#F0F0F0\\\" border=\\\"0\\\" cellpadding=\\\"1\\\" cellspacing=\\\"1\\\" width=\\\"350\\\">\r\n	<tbody>\r\n		<tr>\r\n			<td>\r\n				<strong style=\\\"color: #555555;\\\">Име:</strong></td>\r\n			<td>\r\n				<strong style=\\\"color: #555555;\\\">Таня Манолова Георгиева</strong>&nbsp;</td>\r\n		</tr>\r\n		<tr>\r\n			<td>\r\n				<strong style=\\\"color: #555555;\\\">Телефон:</strong></td>\r\n			<td>\r\n				965 25 13</td>\r\n		</tr>\r\n		<tr>\r\n			<td>\r\n				<strong style=\\\"color: #555555;\\\">E-mail:</strong></td>\r\n			<td>\r\n				<a href=\\\"mailto:fksu-k@tu-sofia.bg\\\">fksu-k@tu-sofia.bg</a>&nbsp;</td>\r\n		</tr>\r\n		<tr>\r\n			<td>\r\n				<strong style=\\\"color: #555555;\\\">Кабинет:</strong></td>\r\n			<td>\r\n				1443a</td>\r\n		</tr>\r\n	</tbody>\r\n</table>\r\n<p>\r\n	&nbsp;</p>\r\n<hr />\r\n<h2 style=\\\"text-align: center;\\\">\r\n	&nbsp;</h2>\r\n<h1 style=\\\"text-align: center;\\\">\r\n	Факултетни канцеларии - студенти</h1>\r\n<table align=\\\"center\\\" bgcolor=\\\"#F0F0F0\\\" border=\\\"0\\\" cellpadding=\\\"1\\\" cellspacing=\\\"1\\\" width=\\\"350\\\">\r\n	<tbody>\r\n		<tr>\r\n			<td>\r\n				<strong style=\\\"color: #555555;\\\">Име:</strong></td>\r\n			<td>\r\n				<p>\r\n					<font color=\\\"#555555\\\"><b>Даниела Бочева</b></font><br />\r\n					<font color=\\\"#555555\\\"><b>Самира Алиман</b></font></p>\r\n			</td>\r\n		</tr>\r\n		<tr>\r\n			<td>\r\n				<strong style=\\\"color: #555555;\\\">Телефон:</strong></td>\r\n			<td>\r\n				965 20 54</td>\r\n		</tr>\r\n		<tr>\r\n			<td>\r\n				<strong style=\\\"color: #555555;\\\">E-mail:<span id=\\\"cke_bm_86S\\\" style=\\\"display: none;\\\">&nbsp;</span><span style=\\\"display: none;\\\">&nbsp;</span></strong></td>\r\n			<td>\r\n				<p>\r\n					<span style=\\\"font-family: Arial, Helvetica, sans-serif;\\\"><span style=\\\"background-color:#ffffff;\\\">dbocheva@tu-so