(16, 1, 'Технически сътрудници', '', '<p style=\\\"text-align: center;\\\">\r\n	&nbsp;</p>\r\n<h1 style=\\\"text-align: center;\\\">\r\n	Технически сътрудници&nbsp;</h1>\r\n<table align=\\\"center\\\" bgcolor=\\\"#F0F0F0\\\" border=\\\"0\\\" cellpadding=\\\"1\\\" cellspacing=\\\"1\\\" width=\\\"350\\\">\r\n	<tbody>\r\n		<tr>\r\n			<td>\r\n				<strong style=\\\"color: #555555;\\\">Име:</strong></td>\r\n			<td>\r\n				<p>\r\n					<font color=\\\"#555555\\\"><b>Ирина Георгиева</b></font></p>\r\n				<p>\r\n					<font color=\\\"#555555\\\"><b>Тихомир Добрев</b></font></p>\r\n			</td>\r\n		</tr>\r\n		<tr>\r\n			<td>\r\n				<strong style=\\\"color: #555555;\\\">Телефон:</strong></td>\r\n			<td>\r\n				965 24 84</td>\r\n		</tr>\r\n		<tr>\r\n			<td>\r\n				<strong style=\\\"color: #555555;\\\">E-mail:</strong></td>\r\n			<td>\r\n				<p>\r\n					irina@yu-sofia.bg</p>\r\n				<p>\r\n					t.dobrev@tu-sofia.bg</p>\r\n			</td>\r\n		</tr>\r\n		<tr>\r\n			<td>\r\n				<strong style=\\\"color: #555555;\\\">Кабинет:</strong></td>\r\n			<td>\r\n				1323</td>\r\n		</tr>\r\n	</tbody>\r\n</table>\r\n<p>\r\n	<strong>Приемно време за студенти:</strong>&nbsp;всеки ден от 9:00 до 12:00 часа и от 13:30 - 15:30 часа.</p>\r\n', 'Yes', 160),
(17, 1, 'Учебна база', '', '<p>\r\n	<img alt=\"\" src=\"https://cs.fcst.bg/userfiles/pages/lecturehall1216.png\" style=\"width: 250px; height: 152px;\" /><img alt=\"\" src=\"https://cs.fcst.bg/userfiles/pages/lab_cp.png\" style=\"width: 250px; height: 148px;\" /></p>\r\n<p>\r\n	<img alt=\"\" src=\"https://cs.fcst.bg/userfiles/pages/lab_hpcs.png\" style=\"width: 250px; height: 153px;\" /><img alt=\"\" src=\"https://cs.fcst.bg/userfiles/pages/lab_ipv6.png\" style=\"width: 250px; height: 160px;\" /></p>\r\n<p>\r\n	<img alt=\"\" src=\"https://cs.fcst.bg/userfiles/pages/lab_ms.png\" style=\"width: 250px; height: 157px;\" /><img alt=\"\" src=\"https://cs.fcst.bg/userfiles/pages/lab_pe.png\" style=\"width: 250px; height: 124px;\" /></p>\r\n<p>\r\n	<img alt=\"\" src=\"https://cs.fcst.bg/userfiles/pages/lab_pip.png\" style=\"width: 250px; height: 133px;\" /></p>\r\n', 'Yes', 170);
INSERT INTO `pages_translations` (`page_id`, `language_id`, `title`, `short_description`, `content`, `active`, `position`) VALUES
(18, 1, 'История на ФКСТ и катедра &quot;Компютърни системи&quot;', '', '<p style=\"text-align: justify;\">\r\n	Бързото развитие и усъвършенстване на компютърните технологии, както и големия брой IT фирми, работещи в областта на създаване и приложение на компютърни и информационни технологии, налага необходимост от високо квалифицирани професионалисти, използващи съвременните технологични иновации. Тъй като търсенето на добре подготвени професионалисти в областта на компютърните науки е много голямо във всички области на техниката, науката, икономиката, образованието, медицината, транспорта и др. интересът към обучение във ФКСТ е много голям.</p>\r\n<p style=\"text-align: justify;\">\r\n	Факултет &bdquo;Компютърни системи и управление&rdquo; (ФКСТ) е основан през 1987 г. и е един от най-големите факултети в Технически университет &ndash; София. В него работят 23 хабилитирани преподаватели &ndash; 3 професори и 2 0 доценти, 23 главни асистента и 11 асистента, 4 инженери и 8 души административен персонал.</p>\r\n<p style=\"text-align: justify;\">\r\n	Във ФКСТ се обучават над 1600 студенти, от които около 1300 са бакалаври, а над 300 са магистри. Всяка година във ФКСТ се дипломират около 200 инженери &ndash; бакалаври и около 70 инженери &ndash; магистри. Докторантите, обучавани във ФКСТ са около 40.</p>\r\n<p style=\"text-align: justify;\">\r\n	Преподавателите от ФКСТ обучават студенти от останалите базови факултети в Технически университет &ndash; София (ФТК, ФЕТТ, ЕФ, ТФ, СФ), както и от трите факултета за чуждоезиково обучение (ФАИО, ФаГИОПМ, ФФОЕ) като отговарят и провеждат обучението по специални дисциплини, съответстващи на научното им направление.</p>\r\n<p style=\"text-align: justify;\">\r\n	Преподавателите от ФКСТ активно участват в обучението към сектор ССДО/ЦНО при ТУ-София, а също и в обучението в Професионалната гимназия по Компютърни технологии и системи &ndash; гр. Правец. В структурата на ФКСТ има 2 катедри: катедра &bdquo;<strong>Kомпютърни системи</strong>&rdquo;, основана през 1969 г., и катедра &bdquo;<strong>Програмиране и компютърни технологии</strong>&rdquo;, основана през 1984 г.</p>\r\n<ul>\r\n	<li style=\"text-align: justify;\">\r\n		<span style=\"line-height: 1.3em;\"><strong>Катедра &bdquo;Компютърни системи&rdquo;</strong> обучава студенти за придобиване на образователно-квалификационните степени магистър и бакалавър по 7 специалности, чиято цел е да осигури на студентите най-съвременни знания в областта на компютърните инженерни науки и усъвършенствани умения, изисквани от днешния конкурентен пазар за успешна професионална реализация.</span></li>\r\n	<li style=\"text-align: justify;\">\r\n		<span style=\"line-height: 1.3em;\"><strong>Катедра &bdquo;Програмиране и компютърни технологии&rdquo;</strong> (pct.tu-sofia.bg) осигурява и провежда обучението по програмиране и информатика за всички професионални направления в ТУ &ndash; София, а също и обучението по 2 от предлаганите във факултета специалности за образователно-квалификационна степен магистър.</span></li>\r\n</ul>\r\n<p align=\"center\" class=\"style1\" style=\"text-align: justify;\">\r\n	<strong>&nbsp;</strong></p>\r\n<p align=\"center\" class=\"style1\">\r\n	<strong>Бивши и настоящи ръководители на катедра &quot;Компютърни системи&quot; </strong></p>\r\n<ul>\r\n	<li>\r\n		От 1969 до 1992 - проф. д.т.н. Борис Боровски</li>\r\n</ul>\r\n<ul>\r\n	<li>\r\n		От 1992 до 1996 - проф. д.т.н. Боян Янков</li>\r\n</ul>\r\n<ul>\r\n	<li>\r\n		От 1996 до 2000 - доц. д-р Васил Василев</li>\r\n</ul>\r\n<ul>\r\n	<li>\r\n		От 2000 до 2004 - доц. д-р Ради Романски</li>\r\n</ul>\r\n<ul>\r\n	<li>\r\n		От 2004 - до сега проф. д-р Пламенка Боровска</li>\r\n</ul>\r\n<p>\r\n	&nbsp;</p>\r\n<table border=\"0\" cellpadding=\"1\" cellspacing=\"1\" style=\"width: 500px;\">\r\n	<tbody>\r\n		<tr>\r\n			<td style=\"text-align: center;\">\r\n				<img alt=\"\" src=\"https://cs.fcst.bg/userfiles/pages/borovski.jpg\" style=\"width: 80px; height: 112px;\" /></td>\r\n			<td style=\"text-align: center;\">\r\n				<img alt=\"\" src=\"https://cs.fcst.bg/userfiles/pages/jankov.jpg\" style=\"width: 86px; height: 112px;\" /></td>\r\n			<td style=\"text-align: center;\">\r\n				<img alt=\"\" src=\"https://cs.fcst.bg/userfiles/pages/vasilev.jpg\" style=\"width: 84px; height: 112px;\" /></td>\r\n			<td style=\"text-align: center;\">\r\n				<img alt=\"\" src=\"https://cs.fcst.bg/userfiles/pages/romanski2.jpg\" style=\"width: 80px; height: 112px;\" /></td>\r\n			<td style=\"text-align: center;\">\r\n				<img alt=\"\" src=\"https://cs.fcst.bg/userfiles/pages/borovska2.jpg\" style=\"width: 86px; height: 112px;\" /></td>\r\n		</tr>\r\n		<tr>\r\n			<td style=\"text-align: center;\">\r\n				проф. д.т.н. Борис Боровски</td>\r\n			<td style=\"text-align: center;\">\r\n				проф. д.т.н. Боян Янков</td>\r\n			<td style=\"text-align: center;\">\r\n				доц. д-р Васил Василев</td>\r\n			<td style=\"text-align: center;\">\r\n				доц. д-р Ради Романски</td>\r\n			<td style=\"text-align: center;\">\r\n				проф. д-р Пламенка Боровска</td>\r\n		</tr>\r\n	</tbody>\r\n</table>\r\n<p>\r\n	&nbsp;</p>\r\n', 'Yes', 180),
(21, 1, 'Магистри - прием зимен семестър 2025/2026', '', '<p id=\"Top\">\r\n	&nbsp;</p>\r\n<table border=\"0\" cellpadding=\"1\" cellspacing=\"1\" style=\"width: 100%\">\r\n	<tbody>\r\n		<tr>\r\n			<td>\r\n				<p>\r\n					<img alt=\"\" src=\"https://cs.fcst.bg/userfiles/pages/students.png\" style=\"width: 228px; height: 152px;\" /></p>\r\n				<p>\r\n					<a href=\"https://www.tu-sofia.bg/master/183\" target=\"_blank\">Обява за новата учебна 2025/2026 година</a></p>\r\n				<a href=\"#Какво\"> </a><a href=\"#Как\"> </a><a href=\"#Кога\"> </a><a href=\"#Къде\"> </a>\r\n				<ul>\r\n					<li>\r\n						<a href=\"#Какво\">Какво да кандидатствам?<!--а--></a></li>\r\n					<li>\r\n						<a href=\"#Какво\"> </a><a href=\"#Как\">Как да кандидатствам?<!--а--></a></li>\r\n					<li>\r\n						<a href=\"#Как\"> </a><a href=\"#Кога\">Кога да кандидатствам?<!--а--></a></li>\r\n					<li>\r\n						<a href=\"#Кога\"> </a><a href=\"#Къде\">Къде да кандидатствам?<!--а--></a></li>\r\n				</ul>\r\n				<a href=\"#Къде\"> </a></td>\r\n			<td>\r\n				<a href=\"https://script.google.com/macros/s/AKfycbxiyTq0jEl45-hcTY4C7hdnevfeI3dFCNWn6ZMZu3XExVhl9lP2_u5EOH1m3UVhr-L7/exec\" target=\"_blank\"><button style=\"background-color: #b31b1b; border: none; cursor: pointer; padding: 15px 32px; color: white; text-align: center; font-size: 16px;\" type=\"button\" value=\"Go to Application Form\">Подай онлайн заявление &gt;&gt;</button></a></td>\r\n		</tr>\r\n	</tbody>\r\n</table>\r\n<hr />\r\n<table border=\"0\" cellpadding=\"5\" cellspacing=\"1\" style=\"width: 100%\">\r\n	<tbody>\r\n		<tr>\r\n			<td id=\"Какво\">\r\n				<h1>\r\n					Какво мога да кандидатствам?&nbsp; <a href=\"#Top\"><button style=\"background-color: #b31b1b; border: none; cursor: pointer; padding: 5px 5px; color: white; text-align: center; font-size: 16px;\" type=\"button\" value=\"back to top\">Начало</button></a></h1>\r\n				<p>\r\n					<span style=\"width: 236px; height: 239px;\">Магистърски програми по:</span></p>\r\n				<ul>\r\n					<li>\r\n						<strong style=\"width: 236px; height: 239px;\">&bdquo;Компютърно и софтуерно инженерство&ldquo; - едногодишно обучение</strong></li>\r\n					<li>\r\n						<strong style=\"width: 236px; height: 239px;\">&bdquo;Компютърно и софтуерно инженерство&ldquo; -двугодишно обучение</strong></li>\r\n					<li>\r\n						<strong style=\"width: 236px; height: 239px;\">&quot;Компютърни науки и инженерство (на английски език) - едногодишно обучение</strong></li>\r\n				</ul>\r\n				<p>\r\n					&nbsp;</p>\r\n			</td>\r\n		</tr>\r\n		<tr>\r\n			<td bgcolor=\"#b31b1b\" id=\"КСИ\">\r\n				<h2>\r\n					<span style=\"color:#ffffff;\">Магистърска програма: &quot;<strong>Компютърно и софтуерно инженерство&quot; (КСИ)</strong></span><strong style=\"color: rgb(255, 255, 255); background-color: rgb(255, 255, 255); font-size: 12px;\"><img alt=\"\" src=\"//userfiles/backtotop.gif\" /><img alt=\"\" src=\"//userfiles/backtotop.gif\" /></strong></h2>\r\n				<p>\r\n					<span style=\"color:#ffffff;\"><strong>Предназначена е за завършили бакалавърска и/или магистърска степен от всички професионални направления от области: 5 &ldquo;Технически науки&rdquo;, 4.5 &ldquo;Математика&rdquo;, 4.6 &ldquo;Информатика и компютърни науки&rdquo;, 4.1 &quot;Физически науки&quot;, 9 &quot;Сигурност и отбрана&quot;.</strong></span></p>\r\n			</td>\r\n		</tr>\r\n		<tr>\r\n			<td>\r\n				<hr />\r\n				<p style=\"margin-left: 40px;\">\r\n					<strong>Професионално направление</strong>: 5.3. Комуникационна и компютърна техника<br />\r\n					<strong>Професионална квалификация:</strong>&nbsp;Магистър- инженер<br />\r\n					<strong><strong>Форма на обучение:</strong> </strong>Редовна<br />\r\n					<strong><strong>Продължителност на обучение</strong>: </strong>1 година (2 семестъра), 2 години (4 семестъра)<br />\r\n					<strong><strong>Тип плащане</strong>: </strong>Държавна поръчка, Платено обучение<br />\r\n					<strong><strong>Език на преподаване</strong>: </strong>Български<br />\r\n					<strong><strong>Прием</strong>: </strong>Септември</p>\r\n				<hr />\r\n				<p>\r\n					Магистърската програма по &bdquo;Компютърно и софтуерно инженерство&ldquo; има за цел да даде възможност на студентите, които вече са получили бакалавърска степен в професионалното направление &bdquo;Комуникационна и компютърна техника&ldquo; да разширят и задълбочат знанията и уменията си при формулиране и решаване на разнообразни съвременни проблеми в широк кръг области на приложение на информационните технологии като по този начин са по-ефективни в работата си и са успешни на IT пазара на труда.&nbsp;</p>\r\n			</td>\r\n		</tr>\r\n		<tr>\r\n			<td>\r\n				<ul>\r\n					<li>\r\n						<span style=\"font-size:14px;\"><span style=\"color:#ff0000;\"><strong>Специалност &bdquo;Компютърно и софтуерно инженерство&rdquo; - едногодишно обучение&nbsp;</strong></span></span></li>\r\n				</ul>\r\n				<p style=\"margin-left: 40px;\">\r\n					<strong>Форма: </strong><em>Държавна поръчка</em> или <em>платено обучение</em></p>\r\n				<p>\r\n					Програмата е&nbsp;продържителност на обучението 1 година (два семестъра) е предназначена&nbsp;за студенти, завършили образователно &ndash; квалификационна степен &bdquo;Бакалавър&ldquo; или &bdquo;Магистър&ldquo; по специалности от професионални направления в област <strong>5 &quot;Технически науки&quot;</strong>, <strong>4.5 &quot;Математика&quot;</strong> и <strong>4.6 &quot;Информатика и компютърни науки&quot;</strong>.&nbsp;</p>\r\n				<p>\r\n					За повече подробности относно изучаваните дисциплини по семестри: <a href=\"https://www.tu-sofia.bg/uplan/uplan\">Факултет Компютърни системи и технологии - Учебен план на специалност &quot;КСИ-1&quot;</a></p>\r\n				<p>\r\n					&nbsp;</p>\r\n				<ul>\r\n					<li>\r\n						<span style=\"font-size:14px;\"><span style=\"color:#ff0000;\"><strong>Специалност</strong>&nbsp;&bdquo;<strong>Компютърно и софтуерно инженерство&rdquo;&nbsp; - двугодишно обучение</strong></span></span></li>\r\n				</ul>\r\n				<p style=\"margin-left: 40px;\">\r\n					<strong>Форма:</strong> <em>Платено обучение</em></p>\r\n				<p>\r\n					Програмата е с продържителност на обучението 2 години (четири семестъра) е предназначени за студенти, завършили образователно &ndash; квалификационна степен &bdquo;Бакалавър&ldquo; или &bdquo;Магистър&ldquo; по специалности от професионални направления в област <strong>4.1 &quot;Физически науки&quot;</strong> и <strong>9 &quot;Сигурност и отбрана&quot;</strong>.</p>\r\n				<p>\r\n					За повече подробности относно изучаваните дисциплини по семестри:&nbsp;<a href=\"https://www.tu-sofia.bg/uplan/uplan\">Факултет Компютърни системи и технологии - Учебен план на специалност &quot;КСИ-2&quot;</a></p>\r\n				<p>\r\n					&nbsp;</p>\r\n			</td>\r\n		</tr>\r\n		<tr>\r\n			<td bgcolor=\"#b31b1b\" id=\"КНИ\">\r\n				<h2>\r\n					<span style=\"color:#ffffff;\">Магистърска програма: &quot;Компютърни науки и инженерство&quot; (на английски език)</span></h2>\r\n				<p>\r\n					<strong style=\"color: rgb(255, 255, 255);\">Предназначена е&nbsp;за завършили бакалавърска или магистърска степен от професионални направления от области: 5 &quot;Технически науки&quot;,&nbsp; и 4.5 &quot;Математика&quot;, 4.6 &quot;Информатика и компютърни науки&quot;</strong></p>\r\n			</td>\r\n		</tr>\r\n		<tr>\r\n			<td>\r\n				<hr />\r\n				<p style=\"margin-left: 40px;\">\r\n					<strong>Професионално направление</strong>: 5.3. Комуникационна и компютърна техника<br />\r\n					<strong>Професионална квалификация:</strong>&nbsp;Магистър- инженер<br />\r\n					<strong>Форма на обучение:</strong>&nbsp;Редовна<br />\r\n					<strong>Продължителност на обучение:</strong>&nbsp;2 семестъра<br />\r\n					<strong>Тип плащане:</strong>: Държавна поръчка, Платено обучение<br />\r\n					<strong>Език на преподаване</strong>&nbsp;Английски<br />\r\n					<strong>Прием</strong>: Септември</p>\r\n				<hr />\r\n			</td>\r\n		</tr>\r\n		<tr>\r\n			<td>\r\n				<p>\r\n					За повече подробности относно изучаваните дисциплини по семестри:&nbsp;<a href=\"https://www.tu-sofia.bg/uplan/uplan\">Факултет Компютърни системи и технологии - Учебен план на специалност &quot;КНИ&quot;</a></p>\r\n			</td>\r\n		</tr>\r\n	</tbody>\r\n</table>\r\n<hr />\r\n<table border=\"0\" cellpadding=\"5\" cellspacing=\"1\" style=\"width: 100%\">\r\n	<tbody>\r\n		<tr>\r\n			<td id=\"Как\">\r\n				<h1>\r\n					Как да кандидатствам? <a href=\"#Top\"><button style=\"background-color: #b31b1b; border: none; cursor: pointer; padding: 5px 5px; color: white; text-align: center; font-size: 16px;\" type=\"button\" value=\"back to top\">Начало</button></a></h1>\r\n			</td>\r\n		</tr>\r\n		<tr>\r\n			<td bgcolor=\"#b31b1b\">\r\n				<h2>\r\n					<span style=\"color:#ffffff;\">Условия за кандидатстване</span></h2>\r\n			</td>\r\n		</tr>\r\n		<tr>\r\n			<td>\r\n				<hr />\r\n				<p>\r\n					Приемът за всички специалности в образователно-квалификационна степен &bdquo;магистър&ldquo; се извършва чрез конкурс по документи. Конкурсът се извършва по низходящ ред на състезателния бал.</p>\r\n				<p>\r\n					<span style=\"color: rgb(66, 66, 66); font-family: arial, helvetica, sans-serif; text-align: justify;\">Право да кандидатстват ползват лицата, които имат успех от дипломата за ОКС &bdquo;бакалавър&rdquo; не по-малък от &bdquo;добър&rdquo;, независимо от вида и формата на избраното обучение. При преминаване от една в друга ОКС се допуска признаване на вече изучавани дисциплини.</span></p>\r\n				<p>\r\n					При условията и по реда за прием на български граждани могат да кандидатстват и да бъдат приети за обучение в образователно-квалификационна степен &bdquo;магистър&ldquo; и граждани от страните - членки на Европейския съюз и на Европейското икономическо пространство.</p>\r\n				<p>\r\n					Приемът на чуждестранни граждани за обучение в образователно-квалификационна степен &bdquo;магистър&ldquo; се урежда с Наредбата за държавните изисквания за прием на студенти във висшите училища на Република България &ndash; раздел IV.</p>\r\n				<p>\r\n					Чуждестранните граждани могат да кандидатстват и да се обучават в ТУ-София в образователно квалификационна степен &bdquo;магистър&ldquo;:</p>\r\n				<ol>\r\n					<li style=\"margin-left: 40px;\">\r\n						<p>\r\n							в изпълнение на междуправителствени спогодби за образователен, научен и културен обмен;</p>\r\n					</li>\r\n					<li style=\"margin-left: 40px;\">\r\n						<p>\r\n							съгласно актове на Министерския съвет;</p>\r\n					</li>\r\n					<li style=\"margin-left: 40px;\">\r\n						<p>\r\n							при условията на чл. 95, ал. 8 и 10 от Закона за висшето образование.</p>\r\n					</li>\r\n				</ol>\r\n				<p>\r\n					Чуждестранните граждани могат да кандидатстват за обучение и при условията и по реда за прием на българските граждани във висшите училища на Република България, ако:</p>\r\n				<ol>\r\n					<li style=\"margin-left: 40px;\">\r\n						<p>\r\n							имат статут на постоянно пребиваващи на територията на Република България;</p>\r\n					</li>\r\n					<li style=\"margin-left: 40px;\">\r\n						<p>\r\n							имат статут на бежанци;</p>\r\n					</li>\r\n					<li style=\"margin-left: 40px;\">\r\n						<p>\r\n							са от българска народност, удостоверена по реда на Постановление № 103 на Министерския съвет от 1993 г. за осъществяване на образователна дейност сред българите в чужбина. Чуждестранните граждани, приети по реда на ПМС № 103, чл. 4, ал. 1 и ПМС № 228, чл. 3 и завършили образователно квалификационна степен &bdquo;бакалавър&ldquo;, кандидатстват и се обучават в магистърска степен при условията и по реда за приемане на българските граждани съгласно чл. 11, ал. 3, т. 3 и ал. 4 от Наредбата за държавните изисквания за прием на студенти във висшите училища на Република България.</p>\r\n					</li>\r\n				</ol>\r\n				<p>\r\n					&nbsp;</p>\r\n			</td>\r\n		</tr>\r\n		<tr>\r\n			<td bgcolor=\"#b31b1b\">\r\n				<h2>\r\n					<span style=\"color:#ffffff;\">Необходими документи и такси</span></h2>\r\n			</td>\r\n		</tr>\r\n		<tr>\r\n			<td>\r\n				<p>\r\n					<span style=\"font-size:16px;\"><strong>Документи за кандидатстване</strong></span></p>\r\n				<p>\r\n					За кандидатстване в ОКС &quot;магистър&quot; специалност &quot;КСИ&quot;, &quot;КНИ&quot;:</p>\r\n				<ul>\r\n					<li>\r\n						<strong>Заявление по образец (задължително!)</strong>\r\n						<ul>\r\n							<li>\r\n								<em><strong>ВНИМАНИЕ</strong></em>: Кандидат студенти, избрали форма на подаване на заявление <strong><u>на място</u></strong> в университета трябва да изтеглят и попълнят ръчно дадените фирмуляри. Всички останалите попълват онлайн формуляра за заявления.&nbsp;</li>\r\n						</ul>\r\n					</li>\r\n				</ul>\r\n				<ul>\r\n					<li>\r\n						<strong>Копие от&nbsp;диплома за степен &quot;бакалавър&quot;,&nbsp;академична справка или уверение&nbsp;</strong><strong>(задължително!)</strong>\r\n						<ul>\r\n							<li>\r\n								<strong><em>ВНИМАНИЕ</em>:</strong>&nbsp;Завършилите специалности &quot;КСТ&quot; и&nbsp; &bdquo;КСИ&ldquo;, &quot;ИТИ&quot;,&nbsp; ОКС &quot;бакалавър&quot; във ФКСТ при ТУ-София, заверяват заявлението в учебната канцелария и не представят копие от диплома за степен &quot;бакалавър&quot;, академична справка или уверение.</li>\r\n						</ul>\r\n					</li>\r\n				</ul>\r\n				<ul>\r\n					<li>\r\n						<strong>Квитанция за платена държавна такса за кандидатстване&nbsp;</strong><strong>(задължително!)</strong>\r\n						<ul>\r\n							<li>\r\n								<em><strong>ВНИМАНИЕ</strong></em>: За кандидат-студенти, отговарящи на условията на Чл. 11 &quot;Освобождаване от такса за кандидатстване&quot; се прилага сканирано копие на документ, удостоверяващ обстоятелството.</li>\r\n						</ul>\r\n					</li>\r\n				</ul>\r\n				<ul>\r\n					<li>\r\n						<strong>Служебни бележки за участие в дейности (незадължително, но носят х1 допълнителна точка при балообразуването).</strong>\r\n						<ul>\r\n							<li>\r\n								Бележки за участие в научни проекти и договори, свързани с компютърните технологии.&nbsp;</li>\r\n							<li>\r\n								Копия от статии, отпечатани в реферирани периодични издания и сборници от конференции, свързани с компютърните технологии.</li>\r\n						</ul>\r\n					</li>\r\n				</ul>\r\n				<p>\r\n					<em>&nbsp;</em></p>\r\n				<p>\r\n					<em><span style=\"font-size:16px;\"><strong>Семестриални такси&nbsp;</strong></span></em></p>\r\n				<ul>\r\n					<li>\r\n						<a href=\"https://www.tu-sofia.bg/university/308\" target=\"_blank\">Семестриални такси за учебната 2025/26 - държавна поръчка</a></li>\r\n					<li>\r\n						<a href=\"https://www.tu-sofia.bg/university/333\" target=\"_blank\">Семестриални такси за учебната 2025/26 - платено обучение</a></li>\r\n				</ul>\r\n				<p>\r\n					<em><strong><span style=\"font-size:16px;\">Административни услуги</span></strong></em></p>\r\n				<ul>\r\n					<li>\r\n						<a href=\"https://www.tu-sofia.bg/university/310\" target=\"_blank\">Такси за административни услуги</a></li>\r\n				</ul>\r\n				<p>\r\n					<strong><em><span style=\"font-size:16px;\">Плащане на такси</span></em></strong></p>\r\n				<ul>\r\n					<li>\r\n						<a href=\"https://www.tu-sofia.bg/university/331\" target=\"_blank\">Безкасово плащане на семестриални такси</a></li>\r\n				</ul>\r\n			</td>\r\n		</tr>\r\n		<tr>\r\n			<td bgcolor=\"#b31b1b\">\r\n				<h2>\r\n					<span style=\"color:#ffffff;\">Балообразуване</span></h2>\r\n			</td>\r\n		</tr>\r\n		<tr>\r\n			<td>\r\n				<hr />\r\n				<p>\r\n					<span style=\"font-size:14px;\"><em style=\"color: rgb(66, 66, 66); font-family: Verdana, &quot;Myriad Pro&quot;, Tahoma, Arial, Helvetica, sans-serif; text-align: justify;\"><strong><span style=\"padding: 0px !important; margin-left: 0px; font-family: arial, helvetica, sans-serif;\">Преминаване от ОКС &bdquo;бакалавър&rdquo; в ОКС &bdquo;магистър&rdquo; по същата или сродна, посочена в учебния план, специалност</span></strong></em></span></p>\r\n				<p style=\"margin-left: 40px;\">\r\n					<span style=\"font-family: arial, helvetica, sans-serif; color: rgb(66, 66, 66); text-align: justify;\">Максималният състезателният бал е 100 точки и се образува от:</span></p>\r\n				<ul>\r\n					<li>\r\n						<p style=\"margin-left: 40px;\">\r\n							<span style=\"margin-left: 0px; font-family: arial, helvetica, sans-serif; padding: 0px !important;\">средния успех от дипломата за ОКС &bdquo;бакалавър&rdquo;, умножен по 10. Максимално 60 точки;</span></p>\r\n					</li>\r\n					<li>\r\n						<p style=\"margin-left: 40px;\">\r\n							<span style=\"margin-left: 0px; font-family: arial, helvetica, sans-serif; padding: 0px !important;\">оценката от дипломната работа, умножена по 2. Максимално 12 точки;</span></p>\r\n					</li>\r\n					<li>\r\n						<p style=\"margin-left: 40px;\">\r\n							<span style=\"margin-left: 0px; font-family: arial, helvetica, sans-serif; padding: 0px !important;\">сумата от оценките на 3 предмета -<em> </em><strong>Математика 1</strong>, <strong>Математика 2</strong> и <strong>ПИК1</strong>, изучавани в курса на обучение, едни и същи за всяка специалност, определени от съответния факултетен съвет. Максимално 18 точки;</span></p>\r\n					</li>\r\n					<li>\r\n						<p style=\"margin-left: 40px;\">\r\n							<span style=\"margin-left: 0px; font-family: arial, helvetica, sans-serif; padding: 0px !important;\">за всяка специалност, по преценка на факултетния съвет, се дават до 10 точки за участие в научна конференция, публикувана статия, изучавана определена дисциплина или група дисциплини, завършен определен университет и др.</span></p>\r\n					</li>\r\n				</ul>\r\n				<p style=\"padding: 0px 10px 0px 0px; margin-top: 0px; color: rgb(66, 66, 66); line-height: 17px; font-family: Verdana, &quot;Myriad Pro&quot;, Tahoma, Arial, Helvetica, sans-serif; text-align: justify;\">\r\n					<span style=\"margin-left: 0px; font-family: arial, helvetica, sans-serif; padding: 0px !important;\">Кандидатите за места по държавна поръчка и платено обучение се състезават помежду си в отделни групи.</span></p>\r\n			</td>\r\n		</tr>\r\n		<tr>\r\n			<td>\r\n				<hr />\r\n				<p style=\"padding: 0px 10px 0px 0px; margin-top: 0px; color: rgb(66, 66, 66); line-height: 17px; font-family: Verdana, &quot;Myriad Pro&quot;, Tahoma, Arial, Helvetica, sans-serif; text-align: justify;\">\r\n					<em style=\"font-size: 13px;\"><strong><span style=\"padding: 0px !important; margin-left: 0px; font-family: arial, helvetica, sans-serif;\">Преминаване от ОКС &bdquo;професионален бакалавър&rdquo; в ОКС &bdquo;магистър&rdquo; от същото професионално направление</span></strong></em></p>\r\n				<p style=\"padding: 0px 10px 0px 0px; margin-top: 0px; color: rgb(66, 66, 66); line-height: 17px; font-family: Verdana, &quot;Myriad Pro&quot;, Tahoma, Arial, Helvetica, sans-serif; text-align: justify;\">\r\n					<span style=\"font-family: arial, helvetica, sans-serif;\">Завършилите ОКС &bdquo;професионален бакалавър&rdquo; могат да продължат образованието си директно в ОКС &bdquo;магистър&rdquo; с двугодишно обучение - само за същото професионално направление и само платено.</span></p>\r\n			</td>\r\n		</tr>\r\n		<tr>\r\n			<td id=\"Кога\">\r\n				<h1>\r\n					<strong><span style=\"color:#000000;\">Кога да кандидатствам?</span>&nbsp;</strong><a href=\"#Top\"><button style=\"background-color: #b31b1b; border: none; cursor: pointer; padding: 5px 5px; color: white; text-align: center; font-size: 16px;\" type=\"button\" value=\"back to top\">Начало</button></a></h1>\r\n			</td>\r\n		</tr>\r\n		<tr>\r\n			<td>\r\n				<hr />\r\n				<p>\r\n					&nbsp;</p>\r\n				<ul>\r\n					<li>\r\n						<a href=\"https://cs.fcst.bg/page.php?id=8\">График - прием зимен семестър 2025/26</a></li>\r\n				</ul>\r\n				<p>\r\n					&nbsp;</p>\r\n			</td>\r\n		</tr>\r\n		<tr>\r\n			<td id=\"Къде\">\r\n				<h1>\r\n					<strong>Къде да кандидатствам?</strong>&nbsp;<a href=\"#Top\"><button style=\"background-color: #b31b1b; border: none; cursor: pointer; padding: 5px 5px; color: white; text-align: center; font-size: 16px;\" type=\"button\" value=\"back to top\">Начало</button></a></h1>\r\n			</td>\r\n		</tr>\r\n		<tr>\r\n			<td>\r\n				<hr />\r\n				<p>\r\n					Подаването и приемът на документи за магистърските програми на кат. &quot;Компютърни системи&quot; при ФКСТ се осъществява по избор от страна на кандидата в <strong>ЕДНА ОТ ДВЕТЕ</strong> посочени по-долу <strong>ФОРМИ</strong>.</p>\r\n			</td>\r\n		</tr>\r\n		<tr>\r\n			<td>\r\n				<ul>\r\n					<li>\r\n						<strong>Онлайн подаване на документи</strong>:&nbsp;<a href=\"https://script.google.com/macros/s/AKfycbxiyTq0jEl45-hcTY4C7hdnevfeI3dFCNWn6ZMZu3XExVhl9lP2_u5EOH1m3UVhr-L7/exec\" target=\"_blank\"><button style=\"background-color: #b31b1b; border: none; cursor: pointer; padding: 15px 32px; color: white; text-align: center; font-size: 16px;\" type=\"button\" value=\"Go to Application Form\">Подай онлайн заявление &gt;&gt;</button></a></li>\r\n				</ul>\r\n				<p>\r\n					Регистрацията се прави ЛИЧНО от кандидат-студента и е ЕДНОКРАТНА. За деклариране на неверни данни носите пряка отговорност и недопускане до участие в класирането и обучението. След успешна регистрация ще получите имейл за потвърждение с входящия номер на подаденото от вас заявление, както и копие от попълненото заявление за кандидатстване за съответна магистърска специалност и форма на обучение. Молим да запазите получения входящ номер на заявлението за административна справка за резултатите от класирането.</p>\r\n			</td>\r\n		</tr>\r\n		<tr>\r\n			<td>\r\n				<ul>\r\n					<li>\r\n						<strong>Подаване на документи с попълване на място</strong>:</li>\r\n				</ul>\r\n				<p style=\"margin-left: 80px;\">\r\n					Адрес:&nbsp;1000 София, район &bdquo;Студентски&ldquo;, бул. &bdquo;Кл. Охридски&ldquo; № 8<br />\r\n					Канцелария на катедра &bdquo;<em>Компютърни системи</em>&ldquo; &ndash; Блок 1, Етаж: 2, Стая: 1201<br />\r\n					маг. инж. Ирина Георгиева, e-mail: irina@tu-sofia.bg<br />\r\n					Работно време:&nbsp;Понеделник - Петък от 9.30 ч. до 16.30 ч.</p>\r\n			</td>\r\n		</tr>\r\n	</tbody>\r\n</table>\r\n<p>\r\n	&nbsp;</p>\r\n', 'Yes', 210),
(59, 2, 'Thesis assignment forms', '', '<h2>\r\n	Bachelor&#39;s degree</h2>\r\n<ul>\r\n	<li>\r\n		<a href=\"/userfiles/20232024/diplomni_zadania_Kuchmova/Bsc_CS_ThesisAssignment_EN.dotx\" target=\"_blank\">Bachelor CSE (EN)</a></li>\r\n	<li>\r\n		<a href=\"/userfiles/20232024/diplomni_zadania_Kuchmova/Bsc_CS_ThesisAssignment_BG.dotx\" target=\"_blank\">Bachelor CSE (BG)</a></li>\r\n</ul>\r\n<p>\r\n	&nbsp;</p>\r\n<hr />\r\n<h2>\r\n	Master&#39;s degree</h2>\r\n<ul>\r\n	<li>\r\n		<a href=\"/userfiles/20232024/diplomni_zadania_Kuchmova/Msc_CSE_ThesisAssignment_EN.dotx\" target=\"_blank\">Master CSE (EN)</a></li>\r\n	<li>\r\n		<a href=\"/userfiles/20232024/diplomni_zadania_Kuchmova/Msc_CSE_ThesisAssignment_BG.dotx\" target=\"_blank\">Master CSE (BG)</a></li>\r\n</ul>\r\n<p>\r\n	&nbsp;</p>\r\n<h2>\r\n	Declaration of Authorship</h2>\r\n<hr />\r\n<ul>\r\n	<li>\r\n		Declaration</li>\r\n</ul>\r\n', 'Yes', 300),
(60, 2, 'Guidelines for graduates', '', '<h2>\r\n	Diploma Assignment Formation</h2>\r\n<hr />\r\n<p>\r\n	<font color=\"#b22222\"><span style=\"font-size: 14px;\"><b>Deadlines</b></span></font></p>\r\n<p>\r\n	<span class=\"OYPEnA text-decoration-none text-strikethrough-none\">The thesis&#39;s completion deadline is according to the timetable for the respective academic year.</span></p>\r\n<ul>\r\n	<li>\r\n		<a href=\"/userfiles/grafik_bak_graduates_2023-24_KSI_last_EN.pdf\">Academ<img alt=\"\" src=\"//userfiles/grafik_bak_graduates_2023-24_KSI_last_EN.pdf\" />ic Calendar - Graduates</a></li>\r\n</ul>\r\n<p>\r\n	<span style=\"color:#b22222;\"><span style=\"font-size:14px;\"><strong>Choice of supervisor</strong></span></span></p>\r\n<p style=\"text-align: justify;\">\r\n	The choice is made on the initiative of the graduate and with the agreement of the preferred supervisor. Any specialist with higher technical education may be selected as the supervisor of the thesis. In cases where the thesis supervisor is not a lecturer at FCST, it is mandatory that such a lecturer be selected as the thesis advisor.</p>\r\n<p>\r\n	<strong style=\"color: rgb(178, 34, 34);\"><span style=\"font-size:14px;\">Approval of the thesis assignment</span></strong></p>\r\n<ul>\r\n	<li style=\"text-align: justify;\">\r\n		The diploma assignment is prepared by the supervisor in two versions in Bulgarian and English.</li>\r\n</ul>\r\n<ul>\r\n	<li style=\"text-align: justify;\">\r\n		The assignment should be completed, printed and signed by the graduate, supervisor and advisor (if any !).</li>\r\n</ul>\r\n<ul>\r\n	<li style=\"text-align: justify;\">\r\n		An approved thesis assignment is valid for one academic year from the date of submission.</li>\r\n</ul>\r\n<ul>\r\n	<li style=\"text-align: justify;\">\r\n		A change of graduate supervisor, after an already approved assignment, is allowed, but after submitting and approving an application to the Dean, which must be accompanied by the written agreement of the current graduate supervisor for the change.</li>\r\n</ul>\r\n<ul>\r\n	<li style=\"text-align: justify;\">\r\n		The completed form has to be printed into<strong> three copies</strong>. <strong>It is signed by the supervisor and the graduate</strong>. It is left in the student&#39;s office to receive an approval and &quot;<span class=\"OYPEnA text-decoration-none text-strikethrough-none\" style=\"font-weight: 700;\">Semester completition</span>&quot; stamp.</li>\r\n</ul>\r\n<ul>\r\n	<li style=\"text-align: justify;\">\r\n		<span class=\"OYPEnA text-decoration-none text-strikethrough-none\" style=\"color: rgb(0, 0, 0); font-weight: 700;\">Two passport-size photographs of the graduate on matte paper are placed in a mailing envelope, </span><span class=\"OYPEnA text-decoration-none text-strikethrough-none\" style=\"color: rgb(0, 0, 0);\">labeled with</span><span class=\"OYPEnA text-decoration-none text-strikethrough-none\" style=\"color: rgb(0, 0, 0); font-weight: 700;\"> </span><span class=\"OYPEnA text-decoration-none text-strikethrough-none\" style=\"color: rgb(0, 0, 0);\">the </span><span class=\"OYPEnA text-decoration-none text-strikethrough-none\" style=\"color: rgb(0, 0, 0); font-style: italic;\">graduate&#39;s full name</span><span class=\"OYPEnA text-decoration-none text-strikethrough-none\" style=\"color: rgb(0, 0, 0);\">, </span><span class=\"OYPEnA text-decoration-none text-strikethrough-none\" style=\"color: rgb(0, 0, 0); font-style: italic;\">faculty number</span><span class=\"OYPEnA text-decoration-none text-strikethrough-none\" style=\"color: rgb(0, 0, 0);\">, </span><span class=\"OYPEnA text-decoration-none text-strikethrough-none\" style=\"color: rgb(0, 0, 0); font-style: italic;\">email address</span><span class=\"OYPEnA text-decoration-none text-strikethrough-none\" style=\"color: rgb(0, 0, 0);\">, and </span><span class=\"OYPEnA text-decoration-none text-strikethrough-none\" style=\"color: rgb(0, 0, 0); font-style: italic;\">cell phone number</span><span class=\"OYPEnA text-decoration-none text-strikethrough-none\" style=\"color: rgb(0, 0, 0);\"> </span><span class=\"OYPEnA text-decoration-none text-strikethrough-none\" style=\"color: rgb(0, 0, 0); font-weight: 700;\">are left in Room 1322a at the time of thesis assignment admission.</span></li>\r\n</ul>\r\n<ul>\r\n	<li style=\"text-align: justify;\">\r\n		The thesis assignments are approved by the signature and stamp of the Dean and Head of Department.</li>\r\n</ul>\r\n<ul>\r\n	<li style=\"text-align: justify;\">\r\n		The graduate receives <strong>PERSONALLY</strong> one copy of the approved thesis assignment from the technical assistant of the department, Room 1322a which he is obliged to attach to the documentation of the finished thesis and to bind it together with it.</li>\r\n</ul>\r\n<p>\r\n	<font color=\"#b22222\"><span style=\"font-size: 14px;\"><b>Thesis submission</b></span></font></p>\r\n<p>\r\n	<span class=\"OYPEnA text-decoration-none text-strikethrough-none\">The completed documentation, printed and bound together with the </span><span class=\"OYPEnA text-decoration-none text-strikethrough-none\" style=\"font-weight: 700;\">approved thesis assignment</span><span class=\"OYPEnA text-decoration-none text-strikethrough-none\"> and </span><span class=\"OYPEnA text-decoration-none text-strikethrough-none\" style=\"font-weight: 700;\">declaration of authorship</span><span class=\"OYPEnA text-decoration-none text-strikethrough-none\">, must be handed in </span><span class=\"OYPEnA text-decoration-none text-strikethrough-none\" style=\"font-weight: 700;\">two weeks before the announced date for the defense</span><span class=\"OYPEnA text-decoration-none text-strikethrough-none\"> </span><span class=\"OYPEnA text-decoration-none text-strikethrough-none\" style=\"font-weight: 700;\">in Room 1201 between 1:30 and 4:30 PM</span><span class=\"OYPEnA text-decoration-none text-strikethrough-none\">.</span></p>\r\n<h2>\r\n	&nbsp;</h2>\r\n<h2>\r\n	Formation of thesis</h2>\r\n<hr />\r\n<p>\r\n	<span style=\"color:#b22222;\"><strong><span style=\"font-size:14px;\">Formation of the assignment</span></strong></span></p>\r\n<ul>\r\n	<li style=\"text-align: justify;\">\r\n		<strong>Topic</strong>. The topic contains as a title the immediate task to be solved by the graduate.</li>\r\n</ul>\r\n<ul>\r\n	<li style=\"text-align: justify;\">\r\n		<strong>Initial setup</strong>. In the initial setup are set the necessary hardware and software, which the graduate must use in his work: - element base, electronic and digital devices, other machines and devices; - programming environments, programming languages, design automation software, simulators, etc. It is also possible to set as objectives in the initial setting some basic parameters that the graduate should have to achieve in the process of his work.</li>\r\n</ul>\r\n<ul>\r\n	<li style=\"text-align: justify;\">\r\n		<strong>Explanatory note</strong>. The explanatory note presents the content of the thesis by chapters.</li>\r\n</ul>\r\n<ul>\r\n	<li style=\"text-align: justify;\">\r\n		<strong>Experimental part</strong>. The experimental part of the assignment specifies the type of experiments that will be conducted and the format in which the results of the experiments will be presented (timelines, tables, graphs, etc.)</li>\r\n</ul>\r\n<p>\r\n	<strong style=\"color: rgb(178, 34, 34);\"><span style=\"font-size:14px;\">Formation of the thesis content</span></strong></p>\r\n<ul>\r\n	<li style=\"text-align: justify;\">\r\n		Recommended thesis length:\r\n		<ul>\r\n			<li>\r\n				40 - 50 pages for the Bachelor&#39;s degree</li>\r\n			<li>\r\n				50 - 60 pages for the Master&#39;s degree</li>\r\n		</ul>\r\n	</li>\r\n</ul>\r\n<ul>\r\n	<li style=\"text-align: justify;\">\r\n		Structuring:\r\n		<ul>\r\n			<li>\r\n				Front page</li>\r\n			<li>\r\n				Approved thesis assignment</li>\r\n			<li>\r\n				Contents</li>\r\n			<li>\r\n				Introduction</li>\r\n			<li>\r\n				Statement of the thesis by separate chapters</li>\r\n			<li>\r\n				Conclusion</li>\r\n			<li>\r\n				List of literature sources used</li>\r\n			<li>\r\n				Appendices</li>\r\n		</ul>\r\n	</li>\r\n</ul>\r\n<p style=\"text-align: justify;\">\r\n	The <strong>introduction</strong> contains a summary of the activities carried out by the graduate during the thesis design process. The thesis chapter by chapter statement presents the process of thesis development. It accurately states the engineering problem to be solved and the requirements that the presented solution must meet. The graduate should mainly emphasize the engineering aspect of the specific work carried out by him/her, in the process of design and implementation of the problem set in the assignment. Subsequently, he/she must present and analyse the results obtained.</p>\r\n<p style=\"text-align: justify;\">\r\n	The thesis presentation for Master&#39;s students should additionally contain a literature review as well as an analysis of multiple possible solutions and a justification of the specific choice made.</p>\r\n<p style=\"text-align: justify;\">\r\n	Examples of structuring the thesis presentation:</p>\r\n<ul>\r\n	<li style=\"margin-left: 40px; text-align: justify;\">\r\n		<p>\r\n			for development of <em><strong>hardware devices</strong></em>: goal and objectives; synthesis of the device block diagram; justification of the choice of the element base; design of the electrical circuit; design of the printed circuit board; testing and settings.</p>\r\n	</li>\r\n</ul>\r\n<ul>\r\n	<li style=\"margin-left: 40px; text-align: justify;\">\r\n		<p>\r\n			for development of a <em><strong>programming system</strong></em>: goal and objectives; synthesis of structure, system functions and user interfaces; design of block diagrams of algorithms, database formats, timing diagrams of communication protocols; program implementation- general structure, class hierarchy, commentary of the program source; experimental results.</p>\r\n	</li>\r\n</ul>\r\n<p style=\"text-align: justify;\">\r\n	The conclusion summarizes the main characteristics and features of the presented engineering solution, its advantages and disadvantages, the results of the experiments, their engineering interpretation and suggestions for further work on the solution of the given problem. The appendices contain source text of programs, formats of data structures, screen forms, obtained results, wiring diagrams, graphic originals of printed items, reference data, etc.</p>\r\n<p style=\"text-align: justify;\">\r\n	&nbsp;</p>\r\n<p style=\"text-align: justify;\">\r\n	<span style=\"font-family: &quot;Times New Roman&quot;, serif; font-size: 16px; font-weight: 700; text-indent: 48px; white-space-collapse: preserve;\">REQUIREMENTS FOR FORMATTING THE THESIS TEXT</span></p>\r\n<p style=\"text-align: justify;\">\r\n	<span style=\"font-family: &quot;Times New Roman&quot;, serif; font-size: 16px; font-weight: 700; text-indent: 48px; white-space-collapse: preserve;\">General requirements</span></p>\r\n<ul>\r\n	<li style=\"text-align: justify;\">\r\n		The pages must be in A4 format (21.0 cm x 29.7 cm).</li>\r\n</ul>\r\n<ul>\r\n	<li style=\"text-align: justify;\">\r\n		Each section of the thesis should begin on a new page, and should be written on the first line, centred in capital letters, in bold.</li>\r\n</ul>\r\n<ul>\r\n	<li style=\"text-align: justify;\">\r\n		Each paragraph and sub-paragraph is written on a new line, with tabbing.&nbsp;</li>\r\n</ul>\r\n<ul>\r\n	<li style=\"text-align: justify;\">\r\n		All text must be double-spaced, with no syllable transpositions.&nbsp;</li>\r\n</ul>\r\n<ul>\r\n	<li style=\"text-align: justify;\">\r\n		The margins on each page should be as follows:\r\n		<ul>\r\n			<li>\r\n				top 2.5 cm; left 3.0 cm</li>\r\n			<li>\r\n				bottom 2.5 cm; right 2.0 cm.&nbsp;</li>\r\n		</ul>\r\n	</li>\r\n</ul>\r\n<ul>\r\n	<li style=\"text-align: justify;\">\r\n		Formatting of the text shall respect the following parameters:\r\n		<ul>\r\n			<li>\r\n				Font: Times New Roman, size 12 point (12 pt.), style Regular, Italic for key concepts only;&nbsp;</li>\r\n		</ul>\r\n	</li>\r\n</ul>\r\n<ul>\r\n	<li style=\"text-align: justify;\">\r\n		Line spacing: 1.5 lines;&nbsp;</li>\r\n</ul>\r\n<ul>\r\n	<li style=\"text-align: justify;\">\r\n		Each paragraph begins with an indent (First line) of 1.25 cm;&nbsp;</li>\r\n</ul>\r\n<ul>\r\n	<li style=\"text-align: justify;\">\r\n		Footnotes: Times New Roman font, size 10 pt., single spacing;&nbsp;</li>\r\n</ul>\r\n<ul>\r\n	<li style=\"text-align: justify;\">\r\n		The main text and footnotes to be double-sided (Alignment: Justified);</li>\r\n</ul>\r\n<ul>\r\n	<li style=\"text-align: justify;\">\r\n		Pagination: bottom right, in Arabic numerals;</li>\r\n</ul>\r\n<ul>\r\n	<li style=\"text-align: justify;\">\r\n		No text such as author&#39;s name, thesis title, chapter headings, etc. in the top margin (Header) and the bottom margin (Footer).</li>\r\n</ul>\r\n<div>\r\n	&nbsp;</div>\r\n<div>\r\n	<span style=\"font-family: &quot;Times New Roman&quot;, serif; font-size: 16px; font-weight: 700; text-align: justify; text-indent: 48px; white-space-collapse: preserve;\">Title page</span></div>\r\n<ul>\r\n	<li style=\"text-align: justify;\">\r\n		The inscription &quot;TECHNICAL UNIVERSITY - SOFIA&quot; shall be in capital letters, size 18 pt, bold and centred.&nbsp;</li>\r\n</ul>\r\n<ul>\r\n	<li style=\"text-align: justify;\">\r\n		The inscription &#39;FACULTY OF COMPUTER SYSTEMS AND TECHNOLOGIES&#39; must appear in capital letters, size 16 pt, bold and centred.&nbsp;</li>\r\n</ul>\r\n<ul>\r\n	<li style=\"text-align: justify;\">\r\n		The title of the thesis must be in capital letters, size 20 point, bold and centred.&nbsp;</li>\r\n</ul>\r\n<ul>\r\n	<li style=\"text-align: justify;\">\r\n		The text under the title is 14 pt, bold.&nbsp;</li>\r\n</ul>\r\n<ul>\r\n	<li style=\"text-align: justify;\">\r\n		The year in which the dissertation is to be defended is indicated at the bottom of the title page.&nbsp;</li>\r\n</ul>\r\n<div>\r\n	<div>\r\n		&nbsp;</div>\r\n	<div>\r\n		<span style=\"font-family: &quot;Times New Roman&quot;, serif; font-size: 16px; font-weight: 700; text-align: justify; text-indent: 48px; white-space-collapse: preserve;\">Contents</span></div>\r\n	<div>\r\n		&nbsp;</div>\r\n	<div style=\"text-align: justify;\">\r\n		In the Table of Contents, the titles of all sections, e.g. &quot;INTRODUCTION&quot;, &quot; REFERENCES&quot;, etc., must be in capital letters and 12 pt. font size. , bold.</div>\r\n	<div>\r\n		&nbsp;</div>\r\n	<div>\r\n		&nbsp;</div>\r\n</div>\r\n<div>\r\n	<span style=\"font-family: &quot;Times New Roman&quot;, serif; font-size: 16px; font-weight: 700; text-align: justify; text-indent: 48px; white-space-collapse: preserve;\">Headings of sections, paragpraphs and sub-paragraphs</span></div>\r\n<ul>\r\n	<li style=\"text-align: justify;\">\r\n		Sections shall be numbered in Roman numerals, capitalised, centred and in bold type, size 14 pt.&nbsp;</li>\r\n</ul>\r\n<ul>\r\n	<li style=\"text-align: justify;\">\r\n		Paragraphs shall be numbered in Arabic numerals, reordered in 14 pt. font size, bold, indented 1.25 cm from the left margin of the page.&nbsp;</li>\r\n</ul>\r\n<ul>\r\n	<li style=\"text-align: justify;\">\r\n		Sub-paragraphs shall be in font size 13 pt., bold, indented 2.0 cm from the left margin.&nbsp;</li>\r\n</ul>\r\n<p style=\"margin-left: 40px;\">\r\n	<strong><em>Example:</em></strong></p>\r\n<p style=\"margin-left: 80px;\">\r\n	I. SECTION TITLE (Bold, 14 pt.)&nbsp;</p>\r\n<p style=\"margin-left: 80px;\">\r\n	Paragraph heading (Bold, 14 pt.)&nbsp;</p>\r\n<p style=\"margin-left: 80px;\">\r\n	Exposition text ................&nbsp;</p>\r\n<p style=\"margin-left: 80px;\">\r\n	Sub-paragraph heading (Bold, 13 pt.)&nbsp;</p>\r\n<p style=\"margin-left: 80px;\">\r\n	Text from exposition ..........................&nbsp;</p>\r\n<p style=\"margin-left: 80px;\">\r\n	Sub-paragraph title (Bold, 13 pt.)&nbsp;</p>\r\n<p style=\"margin-left: 80px;\">\r\n	Text from exposition ................................ etc.</p>\r\n<div style=\"margin-left: 40px;\">\r\n	&nbsp;</div>\r\n<div>\r\n	<span style=\"font-family: &quot;Times New Roman&quot;, serif; font-size: 16px; font-weight: 700; text-align: justify; text-indent: 48px; white-space-collapse: preserve;\">Styling of tables</span></div>\r\n<div>\r\n	<ul>\r\n		<li>\r\n			Tables in the statement should be numbered and headed.</li>\r\n	</ul>\r\n	<ul>\r\n		<li>\r\n			Number the tables consecutively in Arabic numerals for the whole statement to establish the total number (Table 1, Table 2, ...).</li>\r\n	</ul>\r\n	<ul>\r\n		<li>\r\n			The table number should be placed immediately before the title, which should be worded concisely and clearly, in bold and double-spaced.&nbsp;</li>\r\n	</ul>\r\n	<ul>\r\n		<li>\r\n			The font size of the table shall not be smaller than 10 pt. and not larger than 12 pt.</li>\r\n	</ul>\r\n	<ul>\r\n		<li>\r\n			It is obligatory to have a commentary and a reference to the tables in the thesis - for example: (Table 3).</li>\r\n	</ul>\r\n	<ul>\r\n		<li>\r\n			Each table should be set out on one page if possible. If it is necessary to carry on to the next page, &#39;continued&#39; should be written in the top right-hand corner.<span style=\"font-family: Arial, Verdana, sans-serif;\">.</span><span style=\"font-family: Arial, Verdana, sans-serif;\">&nbsp;</span></li>\r\n	</ul>\r\n	<div>\r\n		&nbsp;</div>\r\n	<div>\r\n		<span style=\"font-family: &quot;Times New Roman&quot;, serif; font-size: 16px; font-weight: 700; text-align: justify; text-indent: 48px; white-space-collapse: preserve;\">Styling of figures</span></div>\r\n	<ul>\r\n		<li>\r\n			Each figure (diagram, chart) should have a sequential number, a clear, concise and accurate title.&nbsp;</li>\r\n	</ul>\r\n	<ul>\r\n		<li>\r\n			The numbering and title should be similar to tables, except that they should be centred below the figure.&nbsp;</li>\r\n	</ul>\r\n	<ul>\r\n		<li>\r\n			A legend is needed to read the figures.&nbsp;</li>\r\n	</ul>\r\n	<ul>\r\n		<li>\r\n			A commentary and reference to the figures in the thesis is required in the text.\r\n			<ul>\r\n				<li>\r\n					For example: (Fig. 7).​<span style=\"text-align: justify; font-family: &quot;Times New Roman&quot;, serif; font-size: 12pt; white-space-collapse: preserve;\">&nbsp;</span></li>\r\n			</ul>\r\n		</li>\r\n	</ul>\r\n</div>\r\n<h2>\r\n	<span style=\"font-family: &quot;Times New Roman&quot;, serif; font-size: 16px; text-align: justify; text-indent: 48px; white-space-collapse: preserve;\">Printing and binding</span></h2>\r\n<ul>\r\n	<li style=\"text-align: justify;\">\r\n		Binding is done with a plastic comb (spiral), transparent colourless foil and black spine.</li>\r\n</ul>\r\n<ul>\r\n	<li style=\"text-align: justify;\">\r\n		The bound thesis is presented to the supervisor, who signs it at his/her choice.</li>\r\n</ul>\r\n<ul>\r\n	<li style=\"text-align: justify;\">\r\n		Two weeks before the defence, the thesis is handed in to the technical secretary of the department to be made available to the members of the committee..</li>\r\n</ul>\r\n<p style=\"margin-left: 40px;\">\r\n	&nbsp;</p>\r\n<h2>\r\n	Conducting diploma defences</h2>\r\n<hr />\r\n<p>\r\n	<strong><span style=\"color:#b22222;\"><span style=\"font-size:14px;\">Appointment and approval of a reviewer</span></span></strong></p>\r\n<ul>\r\n	<li style=\"text-align: justify;\">\r\n		The reviewer of the thesis is appointed by the head of the department on the proposal of the thesis supervisor.</li>\r\n</ul>\r\n<ul>\r\n	<li style=\"text-align: justify;\">\r\n		Any specialist with higher technical education, possessing the necessary knowledge in the relevant field, may be selected as a reviewer of the thesis. In cases where the supervisor of the thesis is not a lecturer at FCST, it is mandatory that such a lecturer be selected as the thesis reviewer.</li>\r\n</ul>\r\n<ul>\r\n	<li style=\"text-align: justify;\">\r\n		The thesis supervisor writes his/her proposal for a reviewer on the back of the initial page of the thesis.</li>\r\n</ul>\r\n<ul>\r\n	<li style=\"text-align: justify;\">\r\n		After the reviewer has been approved by the head of the department, the graduate submits the thesis to the reviewer.</li>\r\n</ul>\r\n<p>\r\n	<strong style=\"font-size: 14px;\"><span style=\"color:#b22222;\">The thesis defence procedure</span></strong></p>\r\n<ul>\r\n	<li style=\"text-align: justify;\">\r\n		The thesis defense procedure is initiated on the schedule set for the FCST, after the submission of the completed thesis and the review to the department office.</li>\r\n</ul>\r\n<ul>\r\n	<li style=\"text-align: justify;\">\r\n		The graduate is referred to the relevant examination board by the dissertation supervisor or the head of the department.</li>\r\n</ul>\r\n<ul>\r\n	<li style=\"text-align: justify;\">\r\n		The date of the diploma defense is set by the chair of the examination commission.</li>\r\n</ul>\r\n<ul>\r\n	<li style=\"text-align: justify;\">\r\n		For the defense, the graduate must prepare:</li>\r\n</ul>\r\n<ul style=\"margin-left: 40px;\">\r\n	<li style=\"text-align: justify;\">\r\n		Multimedia presentation about the essence of the thesis (~ 7- 8 minutes).</li>\r\n</ul>\r\n<ul style=\"margin-left: 40px;\">\r\n	<li style=\"text-align: justify;\">\r\n		Live demonstration of the product created (~ 3 - 4 minutes).</li>\r\n</ul>\r\n', 'Yes', 310);
INSERT INTO `pages_translations` (`page_id`, `language_id`, `title`, `short_description`, `content`, `active`, `position`) VALUES
(36, 1, 'Класиране', '', '<h2>\r\n	Резултати след класиране в ОКС &quot;Магистър&quot;</h2>\r\n<h2>\r\n	&nbsp;</h2>\r\n<h2>\r\n	Учебна 2025/26 г.</h2>\r\n<hr />\r\n<ul>\r\n	<li>\r\n		<a href=\"/userfiles/20252026/klasirane1-KSI.pdf\">Kласиране ОКС магистър, спец. &quot;Компютърно и софтуерно инженерство&quot;</a></li>\r\n</ul>\r\n<h2>\r\n	<span style=\"font-size: 12px;\">За записвания:</span></h2>\r\n<h2>\r\n	<strong data-end=\"115\" data-start=\"101\" style=\"font-size: 12px;\">Инспектор:</strong><span style=\"font-size: 12px;\"> Даниела Бочева</span></h2>\r\n<p data-end=\"209\" data-start=\"101\">\r\n	<strong data-end=\"160\" data-start=\"133\">Студентска канцелария 1</strong><br data-end=\"163\" data-start=\"160\" />\r\n	Кабинет: <strong data-end=\"182\" data-start=\"172\">1322-A</strong><br data-end=\"185\" data-start=\"182\" />\r\n	Телефон: <strong data-end=\"209\" data-start=\"194\">02 965-2054</strong></p>\r\n<!--\r\n<h2>\r\n	Балообразуване</h2>\r\n<hr />\r\n<p>\r\n	<span style=\"\\&quot;font-size:14px;\\&quot;\"><em 0px=\"\" font-family:=\"\" margin-left:=\"\" myriad=\"\" span=\"\" style=\"\\&quot;padding:\" text-align:=\"\">Преминаване от ОКС &bdquo;бакалавър&rdquo; в ОКС &bdquo;магистър&rdquo; по същата или сродна, посочена в учебния план, специалност</em></span></p>\r\n<p>\r\n	<span 100=\"\" color:=\"\" li=\"\" style=\"\\&quot;margin-left:\" text-align:=\"\"><span 0px=\"\" 10.=\"\" 60=\"\" font-family:=\"\" li=\"\" padding:=\"\" style=\"\\&quot;margin-left:\"><span 0px=\"\" 12=\"\" 2.=\"\" font-family:=\"\" li=\"\" padding:=\"\" style=\"\\&quot;margin-left:\"><span .=\"\" 0px=\"\" 18=\"\" 3=\"\" font-family:=\"\" li=\"\" padding:=\"\" style=\"\\&quot;margin-left:\"><span 0px=\"\" 10=\"\" 10px=\"\" color:=\"\" font-family:=\"\" line-height:=\"\" margin-top:=\"\" myriad=\"\" p=\"\" padding:=\"\" style=\"\\&quot;padding:\" text-align:=\"\"><span 0px=\"\" color:=\"\" em=\"\" font-family:=\"\" myriad=\"\" padding:=\"\" span=\"\" style=\"\\&quot;font-size:\" text-align:=\"\"><strong><span 0px=\"\" 10px=\"\" color:=\"\" font-family:=\"\" line-height:=\"\" margin-top:=\"\" myriad=\"\" p=\"\" padding:=\"\" style=\"\\&quot;padding:\" text-align:=\"\"><span .=\"\" 0px=\"\" 10px=\"\" 6=\"\" color:=\"\" font-family:=\"\" line-height:=\"\" margin-top:=\"\" myriad=\"\" p=\"\" style=\"\\&quot;padding:\" text-align:=\"\"><span 0px=\"\" 10px=\"\" color:=\"\" font-family:=\"\" line-height:=\"\" margin-left:=\"\" margin-top:=\"\" myriad=\"\" p=\"\" style=\"\\&quot;padding:\" text-align:=\"\"><span 0px=\"\" 10px=\"\" color:=\"\" font-family:=\"\" line-height:=\"\" margin-left:=\"\" margin-top:=\"\" myriad=\"\" p=\"\" style=\"\\&quot;padding:\" text-align:=\"\">&lt;span style=&quot;\\&amp;quot;padding:&quot; 0px=&quot;&quot; !important;=&quot;&quot; margin-left:=&quot;&quot; 0px;=&quot;&quot; font-family:=&quot;&quot; arial,=&quot;&quot; helvetica,=&quot;&quot; sans-serif;\\&quot;=&quot;&quot;&gt;Състезателният бал е средноаритметична оценка от средния успех от предметите, включени в учебния план на изравнителното обучение, и средния успех от оценките от държавните изпити или от защитата на дипломната работа на вече завършената ОКС. Минималният успех на кандидатите, формиран по описания начин, трябва да бъде &bdquo;добър&ldquo;.</span></span></span></span></strong></span></span></span></span></span></span></p>\r\n<p>\r\n	<span 100=\"\" color:=\"\" li=\"\" style=\"\\&quot;margin-left:\" text-align:=\"\"><span 0px=\"\" 10.=\"\" 60=\"\" font-family:=\"\" li=\"\" padding:=\"\" style=\"\\&quot;margin-left:\"><span 0px=\"\" 12=\"\" 2.=\"\" font-family:=\"\" li=\"\" padding:=\"\" style=\"\\&quot;margin-left:\"><span .=\"\" 0px=\"\" 18=\"\" 3=\"\" font-family:=\"\" li=\"\" padding:=\"\" style=\"\\&quot;margin-left:\"><span 0px=\"\" 10=\"\" 10px=\"\" color:=\"\" font-family:=\"\" line-height:=\"\" margin-top:=\"\" myriad=\"\" p=\"\" padding:=\"\" style=\"\\&quot;padding:\" text-align:=\"\"><span 0px=\"\" color:=\"\" em=\"\" font-family:=\"\" myriad=\"\" padding:=\"\" span=\"\" style=\"\\&quot;font-size:\" text-align:=\"\"><strong><span 0px=\"\" 10px=\"\" color:=\"\" font-family:=\"\" line-height:=\"\" margin-top:=\"\" myriad=\"\" p=\"\" padding:=\"\" style=\"\\&quot;padding:\" text-align:=\"\"><span .=\"\" 0px=\"\" 10px=\"\" 6=\"\" color:=\"\" font-family:=\"\" line-height:=\"\" margin-top:=\"\" myriad=\"\" p=\"\" style=\"\\&quot;padding:\" text-align:=\"\"><span 0px=\"\" 10px=\"\" color:=\"\" font-family:=\"\" line-height:=\"\" margin-left:=\"\" margin-top:=\"\" myriad=\"\" p=\"\" style=\"\\&quot;padding:\" text-align:=\"\">&nbsp;</span></span></span></strong></span></span></span></span></span></span></p>\r\n<div>\r\n	<span 100=\"\" color:=\"\" li=\"\" style=\"\\&quot;margin-left:\" text-align:=\"\"><span 0px=\"\" 10.=\"\" 60=\"\" font-family:=\"\" li=\"\" padding:=\"\" style=\"\\&quot;margin-left:\"><span 0px=\"\" 12=\"\" 2.=\"\" font-family:=\"\" li=\"\" padding:=\"\" style=\"\\&quot;margin-left:\"><span .=\"\" 0px=\"\" 18=\"\" 3=\"\" font-family:=\"\" li=\"\" padding:=\"\" style=\"\\&quot;margin-left:\"><span 0px=\"\" 10=\"\" 10px=\"\" color:=\"\" font-family:=\"\" line-height:=\"\" margin-top:=\"\" myriad=\"\" p=\"\" padding:=\"\" style=\"\\&quot;padding:\" text-align:=\"\"><span 0px=\"\" color:=\"\" em=\"\" font-family:=\"\" myriad=\"\" padding:=\"\" span=\"\" style=\"\\&quot;font-size:\" text-align:=\"\"><strong><span 0px=\"\" 10px=\"\" color:=\"\" font-family:=\"\" line-height:=\"\" margin-top:=\"\" myriad=\"\" p=\"\" padding:=\"\" style=\"\\&quot;padding:\" text-align:=\"\"><span .=\"\" 0px=\"\" 10px=\"\" 6=\"\" color:=\"\" font-family:=\"\" line-height:=\"\" margin-top:=\"\" myriad=\"\" p=\"\" style=\"\\&quot;padding:\" text-align:=\"\"><span 0px=\"\" 10px=\"\" color:=\"\" font-family:=\"\" line-height:=\"\" margin-left:=\"\" margin-top:=\"\" myriad=\"\" p=\"\" style=\"\\&quot;padding:\" text-align:=\"\"><em><strong><span style=\"\\&quot;font-size:14px;\\&quot;\">Преминаване от ОКС &bdquo;професионален бакалавър&rdquo; в ОКС &bdquo;магистър&rdquo; от същото професионално направление</span></strong></em></span></span></span></strong></span></span></span></span></span></span></div>\r\n<div>\r\n	<span 100=\"\" color:=\"\" li=\"\" style=\"\\&quot;margin-left:\" text-align:=\"\"><span 0px=\"\" 10.=\"\" 60=\"\" font-family:=\"\" li=\"\" padding:=\"\" style=\"\\&quot;margin-left:\"><span 0px=\"\" 12=\"\" 2.=\"\" font-family:=\"\" li=\"\" padding:=\"\" style=\"\\&quot;margin-left:\"><span .=\"\" 0px=\"\" 18=\"\" 3=\"\" font-family:=\"\" li=\"\" padding:=\"\" style=\"\\&quot;margin-left:\"><span 0px=\"\" 10=\"\" 10px=\"\" color:=\"\" font-family:=\"\" line-height:=\"\" margin-top:=\"\" myriad=\"\" p=\"\" padding:=\"\" style=\"\\&quot;padding:\" text-align:=\"\"><span 0px=\"\" color:=\"\" em=\"\" font-family:=\"\" myriad=\"\" padding:=\"\" span=\"\" style=\"\\&quot;font-size:\" text-align:=\"\"><strong><span 0px=\"\" 10px=\"\" color:=\"\" font-family:=\"\" line-height:=\"\" margin-top:=\"\" myriad=\"\" p=\"\" padding:=\"\" style=\"\\&quot;padding:\" text-align:=\"\"><span .=\"\" 0px=\"\" 10px=\"\" 6=\"\" color:=\"\" font-family:=\"\" line-height:=\"\" margin-top:=\"\" myriad=\"\" p=\"\" style=\"\\&quot;padding:\" text-align:=\"\"><span 0px=\"\" 10px=\"\" color:=\"\" font-family:=\"\" line-height:=\"\" margin-left:=\"\" margin-top:=\"\" myriad=\"\" p=\"\" style=\"\\&quot;padding:\" text-align:=\"\">&nbsp;</span></span></span></strong></span></span></span></span></span></span></div>\r\n<div>\r\n	<span 100=\"\" color:=\"\" li=\"\" style=\"\\&quot;margin-left:\" text-align:=\"\"><span 0px=\"\" 10.=\"\" 60=\"\" font-family:=\"\" li=\"\" padding:=\"\" style=\"\\&quot;margin-left:\"><span 0px=\"\" 12=\"\" 2.=\"\" font-family:=\"\" li=\"\" padding:=\"\" style=\"\\&quot;margin-left:\"><span .=\"\" 0px=\"\" 18=\"\" 3=\"\" font-family:=\"\" li=\"\" padding:=\"\" style=\"\\&quot;margin-left:\"><span 0px=\"\" 10=\"\" 10px=\"\" color:=\"\" font-family:=\"\" line-height:=\"\" margin-top:=\"\" myriad=\"\" p=\"\" padding:=\"\" style=\"\\&quot;padding:\" text-align:=\"\"><span 0px=\"\" color:=\"\" em=\"\" font-family:=\"\" myriad=\"\" padding:=\"\" span=\"\" style=\"\\&quot;font-size:\" text-align:=\"\"><strong><span 0px=\"\" 10px=\"\" color:=\"\" font-family:=\"\" line-height:=\"\" margin-top:=\"\" myriad=\"\" p=\"\" padding:=\"\" style=\"\\&quot;padding:\" text-align:=\"\"><span .=\"\" 0px=\"\" 10px=\"\" 6=\"\" color:=\"\" font-family:=\"\" line-height:=\"\" margin-top:=\"\" myriad=\"\" p=\"\" style=\"\\&quot;padding:\" text-align:=\"\"><span 0px=\"\" 10px=\"\" color:=\"\" font-family:=\"\" line-height:=\"\" margin-left:=\"\" margin-top:=\"\" myriad=\"\" p=\"\" style=\"\\&quot;padding:\" text-align:=\"\">Завършилите ОКС &bdquo;професионален бакалавър&rdquo; могат да продължат образованието си директно в ОКС &bdquo;магистър&rdquo; с двугодишно обучение - само за същото професионално направление и само платено.</span></span></span></strong></span></span></span></span></span></span></div>\r\n<div>\r\n	<span 100=\"\" color:=\"\" li=\"\" style=\"\\&quot;margin-left:\" text-align:=\"\"><span 0px=\"\" 10.=\"\" 60=\"\" font-family:=\"\" li=\"\" padding:=\"\" style=\"\\&quot;margin-left:\"><span 0px=\"\" 12=\"\" 2.=\"\" font-family:=\"\" li=\"\" padding:=\"\" style=\"\\&quot;margin-left:\"><span .=\"\" 0px=\"\" 18=\"\" 3=\"\" font-family:=\"\" li=\"\" padding:=\"\" style=\"\\&quot;margin-left:\"><span 0px=\"\" 10=\"\" 10px=\"\" color:=\"\" font-family:=\"\" line-height:=\"\" margin-top:=\"\" myriad=\"\" p=\"\" padding:=\"\" style=\"\\&quot;padding:\" text-align:=\"\"><span 0px=\"\" color:=\"\" em=\"\" font-family:=\"\" myriad=\"\" padding:=\"\" span=\"\" style=\"\\&quot;font-size:\" text-align:=\"\"><strong><span 0px=\"\" 10px=\"\" color:=\"\" font-family:=\"\" line-height:=\"\" margin-top:=\"\" myriad=\"\" p=\"\" padding:=\"\" style=\"\\&quot;padding:\" text-align:=\"\"><span .=\"\" 0px=\"\" 10px=\"\" 6=\"\" color:=\"\" font-family:=\"\" line-height:=\"\" margin-top:=\"\" myriad=\"\" p=\"\" style=\"\\&quot;padding:\" text-align:=\"\"><span 0px=\"\" 10px=\"\" color:=\"\" font-family:=\"\" line-height:=\"\" margin-left:=\"\" margin-top:=\"\" myriad=\"\" p=\"\" style=\"\\&quot;padding:\" text-align:=\"\">&nbsp;</span></span></span></strong></span></span></span></span></span></span></div>\r\n<div>\r\n	<span 100=\"\" color:=\"\" li=\"\" style=\"\\&quot;margin-left:\" text-align:=\"\"><span 0px=\"\" 10.=\"\" 60=\"\" font-family:=\"\" li=\"\" padding:=\"\" style=\"\\&quot;margin-left:\"><span 0px=\"\" 12=\"\" 2.=\"\" font-family:=\"\" li=\"\" padding:=\"\" style=\"\\&quot;margin-left:\"><span .=\"\" 0px=\"\" 18=\"\" 3=\"\" font-family:=\"\" li=\"\" padding:=\"\" style=\"\\&quot;margin-left:\"><span 0px=\"\" 10=\"\" 10px=\"\" color:=\"\" font-family:=\"\" line-height:=\"\" margin-top:=\"\" myriad=\"\" p=\"\" padding:=\"\" style=\"\\&quot;padding:\" text-align:=\"\"><span 0px=\"\" color:=\"\" em=\"\" font-family:=\"\" myriad=\"\" padding:=\"\" span=\"\" style=\"\\&quot;font-size:\" text-align:=\"\"><strong><span 0px=\"\" 10px=\"\" color:=\"\" font-family:=\"\" line-height:=\"\" margin-top:=\"\" myriad=\"\" p=\"\" padding:=\"\" style=\"\\&quot;padding:\" text-align:=\"\"><span .=\"\" 0px=\"\" 10px=\"\" 6=\"\" color:=\"\" font-family:=\"\" line-height:=\"\" margin-top:=\"\" myriad=\"\" p=\"\" style=\"\\&quot;padding:\" text-align:=\"\"><span 0px=\"\" 10px=\"\" color:=\"\" font-family:=\"\" line-height:=\"\" margin-left:=\"\" margin-top:=\"\" myriad=\"\" p=\"\" style=\"\\&quot;padding:\" text-align:=\"\">Обучението&nbsp; започва с допълващо обучение за изучаване на основни дисциплини, формиращи специалността. Срокът на допълващото обучение е една година (два семестъра). В съответствие с учебния план се осигуряват 60 кредита по ЕСНТК.&nbsp; Записването се извършва чрез конкурс по документи. Кандидатите трябва да имат успех не по-малко &bdquo;добър&ldquo; от диплома за завършена ОКС &bdquo;професионален бакалавър&rdquo;.</span></span></span></strong></span></span></span></span></span></span></div>\r\n<div>\r\n	<span 100=\"\" color:=\"\" li=\"\" style=\"\\&quot;margin-left:\" text-align:=\"\"><span 0px=\"\" 10.=\"\" 60=\"\" font-family:=\"\" li=\"\" padding:=\"\" style=\"\\&quot;margin-left:\"><span 0px=\"\" 12=\"\" 2.=\"\" font-family:=\"\" li=\"\" padding:=\"\" style=\"\\&quot;margin-left:\"><span .=\"\" 0px=\"\" 18=\"\" 3=\"\" font-family:=\"\" li=\"\" padding:=\"\" style=\"\\&quot;margin-left:\"><span 0px=\"\" 10=\"\" 10px=\"\" color:=\"\" font-family:=\"\" line-height:=\"\" margin-top:=\"\" myriad=\"\" p=\"\" padding:=\"\" style=\"\\&quot;padding:\" text-align:=\"\"><span 0px=\"\" color:=\"\" em=\"\" font-family:=\"\" myriad=\"\" padding:=\"\" span=\"\" style=\"\\&quot;font-size:\" text-align:=\"\"><strong><span 0px=\"\" 10px=\"\" color:=\"\" font-family:=\"\" line-height:=\"\" margin-top:=\"\" myriad=\"\" p=\"\" padding:=\"\" style=\"\\&quot;padding:\" text-align:=\"\"><span .=\"\" 0px=\"\" 10px=\"\" 6=\"\" color:=\"\" font-family:=\"\" line-height:=\"\" margin-top:=\"\" myriad=\"\" p=\"\" style=\"\\&quot;padding:\" text-align:=\"\"><span 0px=\"\" 10px=\"\" color:=\"\" font-family:=\"\" line-height:=\"\" margin-left:=\"\" margin-top:=\"\" myriad=\"\" p=\"\" style=\"\\&quot;padding:\" text-align:=\"\">&nbsp;</span></span></span></strong></span></span></span></span></span></span></div>\r\n<div>\r\n	<span 100=\"\" color:=\"\" li=\"\" style=\"\\&quot;margin-left:\" text-align:=\"\"><span 0px=\"\" 10.=\"\" 60=\"\" font-family:=\"\" li=\"\" padding:=\"\" style=\"\\&quot;margin-left:\"><span 0px=\"\" 12=\"\" 2.=\"\" font-family:=\"\" li=\"\" padding:=\"\" style=\"\\&quot;margin-left:\"><span .=\"\" 0px=\"\" 18=\"\" 3=\"\" font-family:=\"\" li=\"\" padding:=\"\" style=\"\\&quot;margin-left:\"><span 0px=\"\" 10=\"\" 10px=\"\" color:=\"\" font-family:=\"\" line-height:=\"\" margin-top:=\"\" myriad=\"\" p=\"\" padding:=\"\" style=\"\\&quot;padding:\" text-align:=\"\"><span 0px=\"\" color:=\"\" em=\"\" font-family:=\"\" myriad=\"\" padding:=\"\" span=\"\" style=\"\\&quot;font-size:\" text-align:=\"\"><strong><span 0px=\"\" 10px=\"\" color:=\"\" font-family:=\"\" line-height:=\"\" margin-top:=\"\" myriad=\"\" p=\"\" padding:=\"\" style=\"\\&quot;padding:\" text-align:=\"\"><span .=\"\" 0px=\"\" 10px=\"\" 6=\"\" color:=\"\" font-family:=\"\" line-height:=\"\" margin-top:=\"\" myriad=\"\" p=\"\" style=\"\\&quot;padding:\" text-align:=\"\"><span 0px=\"\" 10px=\"\" color:=\"\" font-family:=\"\" line-height:=\"\" margin-left:=\"\" margin-top:=\"\" myriad=\"\" p=\"\" style=\"\\&quot;padding:\" text-align:=\"\">След успешно завършване на допълващото обучение студентите продължават обучението си в магистърска степен заедно със студентите, обучаващи се за магистри.</span></span></span></strong></span></span></span></span></span></span></div> -->', 'Yes', 320),
(51, 2, 'Weekly Timetables - Academic Year 2014/2015', '', '<p>\r\n	<strong>BSc Students:</strong></p>\r\n<ul>\r\n	<li>\r\n		<strong>Winter Semester:</strong> <a href=\"https://cs.fcst.bg/userfiles/WeeklyTimeTables/RAZ_1k_ZIM_14_15.pdf\">Course I</a> | <a href=\"https://cs.fcst.bg/userfiles/WeeklyTimeTables/RAZ_2k_ZIM_14_15.pdf\">Course II</a> | <a href=\"https://cs.fcst.bg/userfiles/WeeklyTimeTables/RAZ_3k_ZIM_14_15.pdf\">Course III</a> | <a href=\"https://cs.fcst.bg/userfiles/WeeklyTimeTables/RAZ_4k_ZIM_14_15.pdf\">Course IV</a></li>\r\n</ul>\r\n', 'Yes', 260),
(48, 1, 'За въпроси и контакти', '', '<p>\r\n	<strong>Отговорник магистърско обучение кат. &ldquo;Компютърни Системи&rdquo;: </strong></p>\r\n<ul>\r\n	<li>\r\n		маг. инж. Ирина Георгиева, тел. 02 965 24 84, e-mail: irina@tu-sofia.bg</li>\r\n</ul>\r\n', 'Yes', 440),
(38, 1, 'Проекти', '', '<p>\r\n	Катедра КС участва в международен проект &bdquo;<strong>БЪДЕЩОТО ОБРАЗОВАНИЕ И ОБУЧЕНИЕ ПО КОМПЮТИНГ: КАК ДА ПОДПОМАГАМЕ УЧЕНЕТО ПО ВСЯКО ВРЕМЕ И НА ВСЯКО МЯСТО</strong>&rdquo;. В проекта са включени 67 университета и 35 фирми от България и чужбина. Координатор е Русенският университет. Проектът е с продължителност 3 години: от 10.2013 до 09. 2016.</p>\r\n<p>\r\n	Основна цел на проекта е повишаване на качеството на компютърното образование посредством споделяне на нови знания, обсъждане на нови методологии за преподаването им, въвеждане на иновационни образователни технологии и подкрепа на разпространението на добри практики между всички страни-партньори.</p>\r\n<p>\r\n	Продуктите на проекта ще са от полза за всички страни, участващи в образованието по компютинг като:</p>\r\n<ul>\r\n	<li>\r\n		Университети и национални институции, разработващи политики в областта на образованието по компютинг;</li>\r\n	<li>\r\n		Университетски преподаватели, които са лектори/обучители в областта на компютинга;</li>\r\n	<li>\r\n		Студенти бакалаври, магистри и докторанти&nbsp; по компютинг;</li>\r\n	<li>\r\n		Изследователски институти и центрове по компютинг;</li>\r\n	<li>\r\n		Компании и МСП в областта на компютинга.</li>\r\n</ul>\r\n<p>\r\n	Проектът ще промени методологията на обучение на компютърни специалисти, ще приложи най-съвременни технологии в образованието и ще работи за по-тясно сътрудничество между университети, изследователски институти и промишленост.</p>\r\n<p>\r\n	Повече информация за проекта може да намерите тук. <a href=\"http://fetch.ecs.uni-ruse.bg\">http://fetch.ecs.uni-ruse.bg</a>, а постера можете да изтеглите <a href=\"https://cs.fcst.bg/userfiles/Projects/FETCH-poster.pdf\">оттук</a>.</p>\r\n', 'Yes', 340),
(33, 1, 'Такси', '', '<p>\r\n	<img alt=\\\"\\\" src=\\\"https://cs.fcst.bg/userfiles/pages/trainingfees.gif\\\" style=\\\"width: 153px; height: 103px;\\\" /></p>\r\n<hr />\r\n<div style=\\\"text-align: center; font-weight: bold;\\\">\r\n	&nbsp;</div>\r\n<p>\r\n	<em><span style=\\\"font-size:16px;\\\"><strong>Семестриални такси&nbsp;</strong></span></em></p>\r\n<ul>\r\n	<li>\r\n		<a href=\\\"https://www.tu-sofia.bg/university/308\\\" target=\\\"_blank\\\">Семестриални такси за учебната 2023/2024 - държавна поръчка</a></li>\r\n	<li>\r\n		<a href=\\\"https://www.tu-sofia.bg/university/333\\\" target=\\\"_blank\\\">Семестриални такси за учебната 2023/2024 - платено обучение</a></li>\r\n</ul>\r\n<p>\r\n	<em><strong><span style=\\\"font-size:16px;\\\">Административни услуги</span></strong></em></p>\r\n<ul>\r\n	<li>\r\n		<a href=\\\"https://www.tu-sofia.bg/university/310\\\" target=\\\"_blank\\\">Такси за административни услуги</a></li>\r\n</ul>\r\n<p>\r\n	<strong><em><span style=\\\"font-size:16px;\\\">Плащане на такси</span></em></strong></p>\r\n<p>\r\n	Таксите се внасят в касата на ТУ-София (стая 1337, блок 1) чрез POS терминал&nbsp;<span style=\\\"color: rgb(66, 66, 66); font-family: arial;\\\">или с бюджетно платежно нареждане.</span></p>\r\n<p>\r\n	Възможно е и разсрочено плащане. За повече информация вижте на сайта на ТУ-София или направете справка в каб.1337.</p>\r\n<ul>\r\n	<li>\r\n		<a href=\\\"https://www.tu-sofia.bg/university/331\\\" target=\\\"_blank\\\">Безкасово плащане на семестриални такси</a></li>\r\n</ul>\r\n<p>\r\n	&nbsp;</p>\r\n<hr />\r\n<p>\r\n	&nbsp;&nbsp;<span style=\\\"line-height: 1.3em;\\\"> </span></p>\r\n', 'Yes', 290),
(42, 1, 'Летни практики', '', '<div style=\\\"text-align: justify;\\\">\r\n	&nbsp;</div>\r\n<p style=\\\"margin-top: 0cm; text-align: justify;\\\">\r\n	&nbsp;</p>\r\n<p style=\\\"margin-top: 0cm; text-align: justify;\\\">\r\n	<span style=\\\"font-size: 9pt; font-family: Arial, sans-serif;\\\"><o:p></o:p></span></p>\r\n', 'Yes', 380),
(59, 1, '', '', '<h1>\r\n	Бланки за дипломни задания</h1>\r\n<hr />\r\n<h2>\r\n	ОКС &quot;Бакалавър&quot;</h2>\r\n<ul>\r\n	<li>\r\n		<a href=\"/userfiles/20232024/diplomni_zadania_Kuchmova/Dipl_b_KSI.dotx\" target=\"_blank\">Бакалавър специалност КСИ</a></li>\r\n	<li>\r\n		<a href=\"/userfiles/20232024/diplomni_zadania_Kuchmova/Dipl_b_KST.dotx\" target=\"_blank\">Бакалавър специалност КСТ</a></li>\r\n	<li>\r\n		<a href=\"https://cs.fcst.bg/userfiles/Dipl_b_ITI_new.docx\">Бакалавър специалност ИТИ</a></li>\r\n	<li>\r\n		<a href=\"/userfiles/20232024/diplomni_zadania/cyber_b.docx\" target=\"_blank\">Бакалавър специалнокст Киберсигурност</a></li>\r\n</ul>\r\n<hr />\r\n<h2>\r\n	ОКС &quot;Магистър&quot;</h2>\r\n<ul>\r\n	<li>\r\n		<a href=\"/userfiles/20232024/diplomni_zadania_Kuchmova/Dipl_m_KSI.dotx\" target=\"_blank\">Магистър специалност КСИ</a></li>\r\n	<li>\r\n		<a href=\"/userfiles/20232024/diplomni_zadania_Kuchmova/Dipl_m_KST.dotx\" target=\"_blank\">Магистър специалност КСТ</a></li>\r\n	<li>\r\n		<a href=\"/userfiles/20232024/diplomni_zadania_Kuchmova/Dipl_m_GWD.dotx\" target=\"_blank\">Магистър специалност ГУД</a></li>\r\n	<li>\r\n		<a href=\"\\\" target=\"\\&quot;_blank\\&quot;\">Магистър специалност ИТ</a></li>\r\n	<li>\r\n		<a href=\"/userfiles/20232024/diplomni_zadania/Cyber_m.docx\" target=\"_blank\">Магистър специалност Киберсигурност</a></li>\r\n</ul>\r\n<h1>\r\n	Декларация за авторство</h1>\r\n<hr />\r\n<ul>\r\n	<li>\r\n		<a href=\"/userfiles/20232024/diplomni_zadania/Deklaracia_avtorstvo.pdf\" target=\"_blank\">Декларация</a></li>\r\n</ul>\r\n', 'Yes', 550),
(60, 1, 'Указания за дипломанти', '', '<h2>\r\n	Оформяне на дипломни задания</h2>\r\n<hr />\r\n<p>\r\n	<span style=\"color:#b22222;\"><span style=\"font-size:14px;\"><strong>Срокове</strong></span></span></p>\r\n<p>\r\n	<span class=\"OYPEnA text-decoration-none text-strikethrough-none\">Срокът за заверка на заданието следва да бъде спазен, съгласно графика за съответната учебна година.</span></p>\r\n<ul>\r\n	<li>\r\n		<a href=\"https://cs.fcst.bg/page.php?id=72\">Академичен календар - абсолвенти</a></li>\r\n</ul>\r\n<p>\r\n	<span style=\"color:#b22222;\"><span style=\"font-size:14px;\"><strong>Избор на ръководител</strong></span></span></p>\r\n<p style=\"text-align: justify;\">\r\n	Изборът се извършва по инициатива на дипломанта и със съгласието на желания от него ръководител. За ръководител на дипломната работа може да бъде избран всеки специалист с висше техническо образование. В случаите когато ръководителя на дипломната работа не е преподавател във ФКСТ, е задължително такъв преподавател да бъде избран за консултант на дипломната работа.</p>\r\n<p>\r\n	<strong style=\"color: rgb(178, 34, 34);\"><span style=\"font-size:14px;\">Утвърждаване на дипломно задание</span></strong></p>\r\n<ul>\r\n	<li style=\"text-align: justify;\">\r\n		Дипломното задание се оформя от ръководителя на дипломанта в два екземпляра.</li>\r\n</ul>\r\n<ul>\r\n	<li style=\"text-align: justify;\">\r\n		Заданието се попълва, разпечатва и подписва от дипломанта, ръководителя и консултанта (ако има такъв !).</li>\r\n</ul>\r\n<ul>\r\n	<li style=\"text-align: justify;\">\r\n		Утвърденото дипломно задание е със срок на валидност една учебна година, считано от дата на заявяване.</li>\r\n</ul>\r\n<ul>\r\n	<li style=\"text-align: justify;\">\r\n		Смяна на дипломен ръководител, след утвърдено вече задание, се допуска, но след подаване и одобряване на молба до Декана, към която трябва да бъде приложено писменото съгласие на настоящият дипломен ръководител за смяната.</li>\r\n</ul>\r\n<ul>\r\n	<li style=\"text-align: justify;\">\r\n		Попълнената бланка се разпечатва в <strong>три екземпляра</strong>. Подписва се от <strong>ръководителя</strong> и <strong>дипломанта</strong>. Оставя в студентска канцелария за получаване на заверка и печат <em>&quot;Семестриално завършил</em>&quot;.</li>\r\n</ul>\r\n<ul>\r\n	<li style=\"text-align: justify;\">\r\n		<span class=\"OYPEnA text-decoration-none text-strikethrough-none\">При заверката на дипломното задание трябва да се носят </span><span class=\"OYPEnA text-decoration-none text-strikethrough-none\" style=\"font-weight: 700;\">два броя матирани снимки за документи</span><span class=\"OYPEnA text-decoration-none text-strikethrough-none\">. Снимките да са в </span><span class=\"OYPEnA text-decoration-none text-strikethrough-none\" style=\"font-weight: 700;\">пощенски плик</span><span class=\"OYPEnA text-decoration-none text-strikethrough-none\">, на който да са написани: </span><span class=\"OYPEnA text-decoration-none text-strikethrough-none\" style=\"font-style: italic;\">Трите имена на Дипломанта</span><span class=\"OYPEnA text-decoration-none text-strikethrough-none\">, </span><span class=\"OYPEnA text-decoration-none text-strikethrough-none\" style=\"font-style: italic;\">Факултетен номер</span><span class=\"OYPEnA text-decoration-none text-strikethrough-none\">, </span><span class=\"OYPEnA text-decoration-none text-strikethrough-none\" style=\"font-style: italic;\">Е-мейл адрес</span><span class=\"OYPEnA text-decoration-none text-strikethrough-none\">, </span><span class=\"OYPEnA text-decoration-none text-strikethrough-none\" style=\"font-style: italic;\">Тел. номер.</span>.</li>\r\n</ul>\r\n<ul>\r\n	<li style=\"text-align: justify;\">\r\n		Дипломните задания се утвърждават с подпис и печат от декан и ръководител катедра.</li>\r\n</ul>\r\n<ul>\r\n	<li style=\"text-align: justify;\">\r\n		Дипломантът получава <strong>ЛИЧНО</strong> едно копие на утвърденото дипломно задание от студентска канцелария №1 или №2 което е длъжен да приложи към документацията на готовата дипломна работа и да я до подвърже заедно с нея.</li>\r\n</ul>\r\n<p>\r\n	<span style=\"color:#b22222;\"><span style=\"font-size:14px;\"><strong>Предаване за защита</strong></span></span></p>\r\n<p>\r\n	<span class=\"OYPEnA text-decoration-none text-strikethrough-none\">Готовата документация, разпечатана и подвързана заедно с </span><span class=\"OYPEnA text-decoration-none text-strikethrough-none\" style=\"font-weight: 700;\">утвърденото Дипломно задание и</span><span class=\"OYPEnA text-decoration-none text-strikethrough-none\"> </span><span class=\"OYPEnA text-decoration-none text-strikethrough-none\" style=\"font-weight: 700;\">Декларация за авторство,</span><span class=\"OYPEnA text-decoration-none text-strikethrough-none\"> се предава в </span><span class=\"OYPEnA text-decoration-none text-strikethrough-none\" style=\"font-weight: 700;\">двуседмичен срок преди обявената дата за защита</span><span class=\"OYPEnA text-decoration-none text-strikethrough-none\"> </span><span class=\"OYPEnA text-decoration-none text-strikethrough-none\" style=\"font-weight: 700;\">в</span><span class=\"OYPEnA text-decoration-none text-strikethrough-none\"> </span><span class=\"OYPEnA text-decoration-none text-strikethrough-none\" style=\"font-weight: 700;\">каб. 1201 между 13:30 и 16:30 часа.</span></p>\r\n<p>\r\n	&nbsp;</p>\r\n<h2>\r\n	Оформяне на дипломни работи</h2>\r\n<hr />\r\n<p>\r\n	<span style=\"color:#b22222;\"><strong><span style=\"font-size:14px;\">Оформяне на заданието</span></strong></span></p>\r\n<ul>\r\n	<li style=\"text-align: justify;\">\r\n		<strong>Тема</strong>. Темата съдържа като заглавие непосредствената задача, която се поставя за разрешаване на дипломанта.</li>\r\n</ul>\r\n<ul>\r\n	<li style=\"text-align: justify;\">\r\n		<strong>Изходна постановка</strong>. В изходната постановка се задават необходимите апаратни и програмни средства, които дипломантът трябва да използува в своята работа: &ndash; елементна база, електронни и цифрови устройства, други машини и апарати; &ndash; програмни среди, езици за програмиране, програмни продукти за автоматизация на проектирането, симулатори и др. Възможно е в изходната постановка да бъдат зададени като цели и някои основни параметри, които дипломантът трябва да трябва да постигне в процеса на своята работа.</li>\r\n</ul>\r\n<ul>\r\n	<li style=\"text-align: justify;\">\r\n		<strong>Обяснителна записка</strong>. В обяснителната записка се представя съдържанието на дипломната работа по глави.</li>\r\n</ul>\r\n<ul>\r\n	<li style=\"text-align: justify;\">\r\n		<strong>Експериментална част</strong>. В експерименталната част на заданието се задава вида на експериментите, които ще бъдат проведени, както и формата, в която ще бъдат представени резултатите от проведените експерименти (времедиаграми, таблици, графики, и др.)</li>\r\n</ul>\r\n<p>\r\n	<strong style=\"color: rgb(178, 34, 34);\"><span style=\"font-size:14px;\">Оформяне на съдържанието на дипломната работа</span></strong></p>\r\n<ul>\r\n	<li style=\"text-align: justify;\">\r\n		Препоръчителен обем на дипломната работа:\r\n		<ul>\r\n			<li>\r\n				40 - 50 страници за ОКС &quot;Бакалавър&quot;</li>\r\n			<li>\r\n				50 - 60 страници за ОКС &quot;Магистър&quot;</li>\r\n		</ul>\r\n	</li>\r\n</ul>\r\n<ul>\r\n	<li style=\"text-align: justify;\">\r\n		Структуриране:\r\n		<ul>\r\n			<li>\r\n				Заглавна страница;</li>\r\n			<li>\r\n				Утвърдено дипломно задание</li>\r\n			<li>\r\n				Съдържание</li>\r\n			<li>\r\n				Увод</li>\r\n			<li>\r\n				Изложение на дипломната работа по отделни глави</li>\r\n			<li>\r\n				Заключение</li>\r\n			<li>\r\n				Списък на използвани литературни източници</li>\r\n			<li>\r\n				Приложения</li>\r\n		</ul>\r\n	</li>\r\n</ul>\r\n<p style=\"text-align: justify;\">\r\n	<strong>Уводът</strong> съдържа резюме на дейностите извършени от дипломанта в процеса на дипломното проектиране. Изложението на дипломната работа по глави представя процеса на разработка на дипломната работа. В него точно се формулира инженерния проблем, който предстои да бъде решен и изискванията, на които представеното решение трябва да отговаря. Дипломантът трябва да наблегне основно на инженерния аспект на извършена от него конкретна работа, в процеса на проектиране и реализация на поставената в заданието задача. Впоследствие трябва да представи и анализира получените резултати.</p>\r\n<p style=\"text-align: justify;\">\r\n	<strong>Изложението</strong> на дипломните работи за магистри трябва да съдържа допълнително литературен обзор, както и анализ на множество възможни решения и обосновка на направения конкретен избор.</p>\r\n<p style=\"text-align: justify;\">\r\n	Примери за структуриране на изложението:</p>\r\n<ul>\r\n	<li style=\"margin-left: 40px; text-align: justify;\">\r\n		<p>\r\n			за разработка на <em><strong>апаратни средства</strong></em>: цел и задачи; синтез на блокова схема на устройството; обосновка на избора на елементна база; проектиране на електрическа схема; проектиране на печатна платка; тестване и настройки.</p>\r\n	</li>\r\n</ul>\r\n<ul>\r\n	<li style=\"margin-left: 40px; text-align: justify;\">\r\n		<p>\r\n			за разработка на <em><strong>програмна система</strong></em>: цел и задачи; синтез на структура, функции на системата и потребителски интерфейси; проектиране на блок схеми на алгоритми, формати на бази данни, времедиаграми на комуникационни протоколи; програмна реализация- обща структура, йерархия на класове, коментар на изходния текст на програмата; опитни резултати.</p>\r\n	</li>\r\n</ul>\r\n<p style=\"text-align: justify;\">\r\n	<strong>Заключението</strong> обобщава основните характеристики и особености на на представеното инженерно решение, неговите предимства и недостатъци, резултатите от експериментите, тяхната инженерна трактовка и предложения за по-нататъшна работа върху решаването на зададения проблем. Приложенията съдържащат изходен текст на програми, формати на структури от данни, екранни форми, получени резултати, електрически схеми, графични оригинали на печатни пратки, справочни данни и др.</p>\r\n<p style=\"text-align: justify;\">\r\n	&nbsp;</p>\r\n<p style=\"text-align: justify;\">\r\n	<strong style=\"color: rgb(178, 34, 34);\"><span style=\"font-size: 14px;\">ИЗИСКВАНИЯ ЗА ФОРМАТИРАНЕ НА ТЕКСТА НА ДИПЛОМНАТА РАБОТА</span></strong></p>\r\n<p style=\"text-align: justify;\">\r\n	<b>Общи изисквания</b></p>\r\n<ul>\r\n	<li style=\"text-align: justify;\">\r\n		Страниците трябва да бъдат във формат А4 (21.0 cm x 29.7cm).</li>\r\n	<li style=\"text-align: justify;\">\r\n		Всеки раздел на дипломната работа започва на нова страница, като се изписва на първия ред, центрирано с главни букви, удебелено (Bold).</li>\r\n	<li style=\"text-align: justify;\">\r\n		Всеки параграф и подпараграф се изписва на нов ред, с табулация.&nbsp;</li>\r\n	<li style=\"text-align: justify;\">\r\n		Всички текстове трябва да бъдат двустранно подравнени, без пренасяния на срички.&nbsp;</li>\r\n	<li style=\"text-align: justify;\">\r\n		<span style=\"text-align: justify;\">Полетата на всяка страница да бъдат както следва:&nbsp;</span>\r\n		<ul>\r\n			<li>\r\n				отгоре 2.5 cm; отляво 3.0 cm</li>\r\n			<li>\r\n				отдолу 2.5 cm; отдясно 2.0 cm.&nbsp;</li>\r\n		</ul>\r\n	</li>\r\n</ul>\r\n<ul>\r\n	<li style=\"text-align: justify;\">\r\n		При форматирането на текста се&nbsp;<span style=\"font-family: &quot;Times New Roman&quot;, serif; font-size: 16px; text-align: justify; white-space-collapse: preserve;\">спазват следните параметри:</span>\r\n		<ul>\r\n			<li>\r\n				шрифт (Font): Times New Roman, размер 12 пункта (12 pt.), стил нормален (Regular), курсив (Italic) само за ключови понятия;&nbsp;</li>\r\n		</ul>\r\n	</li>\r\n</ul>\r\n<ul dir=\"ltr\">\r\n	<li style=\"text-align: justify;\">\r\n		междуредие (Line spacing): 1.5 lines;&nbsp;</li>\r\n	<li style=\"text-align: justify;\">\r\n		всеки абзац започва с отстъп (First line) 1.25 cm;&nbsp;</li>\r\n	<li style=\"text-align: justify;\">\r\n		бележки под линия: шрифт Times New Roman, размер 10 pt., междуредие Single;&nbsp;</li>\r\n	<li style=\"text-align: justify;\">\r\n		основният текст и бележките под линия да бъдат двустранно подравнени (Alignment: Justified);</li>\r\n	<li style=\"text-align: justify;\">\r\n		номерация на страниците: долу, в дясно, с арабски цифри;</li>\r\n</ul>\r\n<p style=\"text-align: justify;\">\r\n	<b>Титулна страница</b></p>\r\n<ul>\r\n	<li style=\"text-align: justify;\">\r\n		Надписът &bdquo;ТЕХНИЧЕСКИ УНИВЕРСИТЕТ &ndash; СОФИЯ&rdquo; се изписва с главни букви, размер 18 pt., удебелено и центрирано.&nbsp;</li>\r\n	<li style=\"text-align: justify;\">\r\n		Надписът ФАКУЛТЕТ &bdquo;КОМПЮТЪРНИ СИСТЕМИ И ТЕХНОЛИГИИ&rdquo; се изписва с главни букви, размер 16 pt., удебелено и центрирано.&nbsp;</li>\r\n	<li style=\"text-align: justify;\">\r\n		Заглавието на дипломната работа е с главни букви, размер 20 pt., удебелено и центрирано.&nbsp;</li>\r\n	<li style=\"text-align: justify;\">\r\n		Текстът под заглавието е с размер 14 pt., удебелен.&nbsp;</li>\r\n	<li style=\"text-align: justify;\">\r\n		Най-долу на заглавната страница се отбелязва годината, в която дипломната работа ще бъде защитавана.&nbsp;</li>\r\n</ul>\r\n<p>\r\n	<strong><span style=\"text-align: justify;\">Съдържание</span></strong></p>\r\n<p style=\"text-align: justify;\">\r\n	​В съдържанието заглавията на всички раздели, напр. &bdquo;УВОД&rdquo;, &bdquo;ЛИТЕРАТУРЕН ПРЕГЛЕД&rdquo; и др. се изписват с главни букви и размер на шрифта 12 pt. , удебелено.</p>\r\n<p>\r\n	<span style=\"font-family: &quot;Times New Roman&quot;, serif; font-size: 16px; font-weight: 700; text-align: justify; text-indent: 48px; white-space-collapse: preserve;\">Заглавия на раздели, параграфи и подпараграфи</span></p>\r\n<ul>\r\n	<li style=\"text-align: justify;\">\r\n		Разделите се номерират с римски цифри, изписват се с главни букви, центрирано и с удебелен шрифт, размер 14 pt.&nbsp;</li>\r\n</ul>\r\n<ul>\r\n	<li style=\"text-align: justify;\">\r\n		Параграфите се номерират с арабски цифри, изписват се на нов ред с размер на шрифта 14 pt., удебелено, с отстъпление 1.25 cm от лявото поле на листа.&nbsp;</li>\r\n</ul>\r\n<ul>\r\n	<li style=\"text-align: justify;\">\r\n		Подпараграфите са с размер на шрифта 13 pt., удебелено, с отстъпление 2.0 cm от лявото поле на листа.&nbsp;</li>\r\n</ul>\r\n<div style=\"margin-left: 40px; text-align: justify;\">\r\n	<em><strong>Пример:</strong></em></div>\r\n<div style=\"margin-left: 80px; text-align: justify;\">\r\n	I. ЗАГЛАВИЕ НА РАЗДЕЛ (Bold, 14 pt.)&nbsp;</div>\r\n<div style=\"margin-left: 80px; text-align: justify;\">\r\n	Заглавие на параграф (Bold, 14 pt.)&nbsp;</div>\r\n<div style=\"margin-left: 80px; text-align: justify;\">\r\n	Текст от изложението ................&nbsp;</div>\r\n<div style=\"margin-left: 80px; text-align: justify;\">\r\n	Заглавие на подпараграф (Bold, 13 pt.)&nbsp;</div>\r\n<div style=\"margin-left: 80px; text-align: justify;\">\r\n	Текст от изложението ..........................&nbsp;</div>\r\n<div style=\"margin-left: 80px; text-align: justify;\">\r\n	Заглавие на подпараграф (Bold, 13 pt.)&nbsp;</div>\r\n<div style=\"margin-left: 80px; text-align: justify;\">\r\n	Текст от изложението ................................ и т.н.</div>\r\n<div style=\"margin-left: 40px;\">\r\n	&nbsp;</div>\r\n<div>\r\n	<span style=\"font-family: &quot;Times New Roman&quot;, serif; font-size: 16px; font-weight: 700; text-align: justify; text-indent: 48px; white-space-collapse: preserve;\">Оформяне на таблици</span></div>\r\n<div>\r\n	<ul>\r\n		<li style=\"text-align: justify;\">\r\n			<div>\r\n				Таблиците в изложението трябва да бъдат номерирани и озаглавени.</div>\r\n		</li>\r\n		<li style=\"text-align: justify;\">\r\n			<div>\r\n				Номерирането на таблиците става с арабски числа, последователно за цялото изложение, за да се установи общия им брой (Таблица 1, Таблица 2, &hellip;).</div>\r\n		</li>\r\n		<li style=\"text-align: justify;\">\r\n			<div>\r\n				Номерът на таблицата се поставя непосредствено преди заглавието, което трябва да бъде формулирано кратко и ясно, като се изписват удебелено (Bold) и двустранно подравнено. Размерът на шрифта в таблицата не трябва да е по-малък от 10 pt. и не поголям от 12 pt.</div>\r\n		</li>\r\n		<li style=\"text-align: justify;\">\r\n			<div>\r\n				Задължително е в текста да има коментар и препратка към разположените в дипломната работа таблици &ndash; например: (Табл. 3).</div>\r\n		</li>\r\n		<li style=\"text-align: justify;\">\r\n			<div>\r\n				Всяка таблица следва да се разположи по възможност на една страница. Ако се налага пренасяне на следваща страница, в горния десен ъгъл се пише &bdquo;продължение&rdquo;. .&nbsp;<span style=\"font-family: &quot;Times New Roman&quot;, serif; font-size: 12pt; white-space-collapse: preserve;\">&nbsp;</span></div>\r\n		</li>\r\n	</ul>\r\n	<p>\r\n		<span style=\"white-space-collapse: preserve; font-family: &quot;Times New Roman&quot;, serif;\">​</span><span style=\"font-family: &quot;Times New Roman&quot;, serif; font-size: 16px; font-weight: 700; text-align: justify; text-indent: 48px; white-space-collapse: preserve;\">Оформяне на фигури</span></p>\r\n	<ul>\r\n		<li style=\"text-align: justify;\">\r\n			Всяка фигура (схема, диаграма) трябва да има пореден номер, ясно, кратко и точно заглавие.&nbsp;</li>\r\n		<li style=\"text-align: justify;\">\r\n			Номерирането и заглавието се изписват аналогично на таблиците с тази разлика, че се поставят центрирано под фигурата.&nbsp;</li>\r\n		<li style=\"text-align: justify;\">\r\n			Необходима е легенда за разчитане на показателите.&nbsp;</li>\r\n		<li style=\"text-align: justify;\">\r\n			Задължително е в текста да има коментар и препратка към разположените в дипломната работа фигури &ndash; например: (Фиг. 7).&nbsp;<span style=\"font-family: &quot;Times New Roman&quot;, serif; font-size: 12pt; white-space-collapse: preserve; text-align: justify;\">&nbsp;</span></li>\r\n	</ul>\r\n</div>\r\n<h2>\r\n	<span style=\"white-space-collapse: preserve; font-family: &quot;Times New Roman&quot;, serif;\">​</span><span style=\"white-space-collapse: preserve; font-family: &quot;Times New Roman&quot;, serif; font-size: 16px; text-align: justify; text-indent: 48px;\">Печат и подвързване</span></h2>\r\n<div style=\"text-align: justify;\">\r\n	Подвързването се извършва с пластмасов гребен (спирала), прозрачно безцветно фолио и черен гръб. Подвързаната дипломна работа се представя на научния ръководител, който я подписва по своя преценка.</div>\r\n<div style=\"text-align: justify;\">\r\n	Две седмици преди защитата, дипломната работа се предава на техническият секретар на катедрата, за да бъдат на разположение на членовете на комисията.</div>\r\n<div style=\"text-align: justify;\">\r\n	&nbsp;</div>\r\n<div>\r\n	&nbsp;</div>\r\n<h2>\r\n	Провеждане на дипломни защити</h2>\r\n<hr />\r\n<p>\r\n	<strong><span style=\"color:#b22222;\"><span style=\"font-size:14px;\">Определяне и утвърждаване на рецензент</span></span></strong></p>\r\n<ul>\r\n	<li style=\"text-align: justify;\">\r\n		Рецензентът на дипломната работа се определя от ръководителя на катедрата по предложение на ръководителя на дипломната работа.</li>\r\n</ul>\r\n<ul>\r\n	<li style=\"text-align: justify;\">\r\n		За рецензент на дипломната работа може да бъде избран всеки специалист с висше техническо образование, притежаващ нужните познания в съответната област. В случаите когато ръководителя на дипломната работа не е преподавател във ФКСТ, е задължително такъв преподавател да бъде избран за рецензент на дипломната работа.</li>\r\n</ul>\r\n<ul>\r\n	<li style=\"text-align: justify;\">\r\n		Ръководителят на дипломнанта записва своето предложение за рецензент на гърба на началната страница на дипломната работа.</li>\r\n</ul>\r\n<ul>\r\n	<li style=\"text-align: justify;\">\r\n		След утвърждаване на рецензента от страна на ръководителя на катедрата, дипломантът представя дипломната работа на рецензента.</li>\r\n</ul>\r\n<p>\r\n	<strong style=\"font-size: 14px;\"><span style=\"color:#b22222;\">Процедурата по защита на дипломната работа</span></strong></p>\r\n<ul>\r\n	<li style=\"text-align: justify;\">\r\n		Процедурата по защита на дипломната работа се стартира в определения за ФКСT график, след представянето на готовата дипломна работа и рецензията в канцеларията на катедрата.</li>\r\n</ul>\r\n<ul>\r\n	<li style=\"text-align: justify;\">\r\n		Дипломантът се насочва към съответната изпитна комисия от отговорника по диломните работи или от ръководителя на катедрата.</li>\r\n</ul>\r\n<ul>\r\n	<li style=\"text-align: justify;\">\r\n		Датата на дипломната защита се определя от председателя на изпитната комисия.</li>\r\n</ul>\r\n<ul>\r\n	<li style=\"text-align: justify;\">\r\n		За провеждане на защитата дипломантът трябва да подготви:</li>\r\n</ul>\r\n<ul style=\"margin-left: 40px;\">\r\n	<li style=\"text-align: justify;\">\r\n		Мултимедийна презентация с изложение върху същността на дипломната работа (~ 7- 8 минути)</li>\r\n</ul>\r\n<ul style=\"margin-left: 40px;\">\r\n	<li style=\"text-align: justify;\">\r\n		Демонстрация на живо създадения продукт (~ 3 - 4 минути).</li>\r\n</ul>\r\n', 'Yes', 560),
(30, 1, 'Как да кандидатствам?', '', '<p>\r\n	.</p>\r\n', 'Yes', 260),
(64, 1, 'Изпитна сесия', '', '<p>\r\n	<span style=\"color:#b22222;\"><strong>ВАЖНО</strong>: За подробности относно организацията и начина на провеждане на изпитите се свързвайте с вашите преподаватели като използвате установените комуникационни канали: e-mail, MS Teams и Moodle.&nbsp;<img alt=\"smiley\" height=\"20\" src=\"https://cs.fcst.bg/donthackplease/scripts/ckeditor/plugins/smiley/images/regular_smile.gif\" title=\"smiley\" width=\"20\" /></span></p>\r\n<h1>\r\n	<strong>Академична учебна година 2025/2026</strong></h1>\r\n<hr />\r\n<br />\r\n<h3>\r\n	<a href=\"https://docs.google.com/spreadsheets/d/e/2PACX-1vQtdNnxiHGoTyqorRtFprznN3HbVDZzUxZ48bmnITahn_vAsE8x1CKDyxyQHBJED7j-NDqZ0GPXI9Lj/pubhtml?gid=626350654&amp;single=true\">График за спец. &quot;Компютърно и софтуерно инженерство&quot;</a></h3>\r\n<ul>\r\n	<li>\r\n		Зимна изпитна сесия&nbsp;</li>\r\n	<li>\r\n		Зимна поправителна сесия</li>\r\n</ul>\r\n<ul>\r\n	<li>\r\n		Лятна изпитна сесия</li>\r\n	<li>\r\n		Лятна поправителна сесия</li>\r\n</ul>\r\n<ul>\r\n	<li>\r\n		Годишна ликвидационна сесия: Една седмицата преди започването на учебните занятия за учебната 2026/2027 г.</li>\r\n</ul>\r\n<h1>\r\n	&nbsp;</h1>\r\n', 'Yes', 600),
(31, 1, 'Специалности', '', '<p>\r\n	Кандидат студентски прием за учебната 2023 / 2024 има за следните магистърски програми:</p>\r\n<table border=\\\"0\\\" cellpadding=\\\"1\\\" cellspacing=\\\"1\\\">\r\n	<tbody>\r\n		<tr>\r\n			<td>\r\n				<img alt=\\\"\\\" src=\\\"https://cs.fcst.bg/userfiles/pages/students.png\\\" style=\\\"width: 228px; height: 152px;\\\" /></td>\r\n			<td>\r\n				<ul>\r\n					<li>\r\n						<div>\r\n							&bdquo;Компютърно и софтуерно инженерство&ldquo; - едногодишно обучение</div>\r\n					</li>\r\n					<li>\r\n						<div>\r\n							&bdquo;Компютърно и софтуерно инженерство&ldquo; -двугодишно обучение</div>\r\n					</li>\r\n					<li>\r\n						<div>\r\n							&quot;Графичен и уеб дизайн&quot; - едногодишно обучение</div>\r\n					</li>\r\n					<li>\r\n						<div>\r\n							&quot;Компютърни науки и инженерство (на английски език) - едногодишно обучение</div>\r\n					</li>\r\n				</ul>\r\n			</td>\r\n		</tr>\r\n	</tbody>\r\n</table>\r\n<p>\r\n	&nbsp;</p>\r\n<hr />\r\n<table border=\\\"0\\\" cellpadding=\\\"3\\\" cellspacing=\\\"3\\\">\r\n	<tbody>\r\n		<tr>\r\n			<td valign=\\\"top\\\">\r\n				<img alt=\\\"\\\" src=\\\"https://cs.fcst.bg/userfiles/pages/important1.png\\\" style=\\\"width: 60px; height: 50px;\\\" /></td>\r\n			<td>\r\n				<p>\r\n					Обучението във всички специалности е само&nbsp;<strong>редовно</strong>.</p>\r\n			</td>\r\n		</tr>\r\n	</tbody>\r\n</table>\r\n<hr />\r\n<p>\r\n	За по-подробна информация може да разгледате учебните планове &nbsp;и кратки характеристики на изучаваните дисциплини на:</p>\r\n<p>\r\n	&nbsp;- Специалност &quot;<strong>Компютърно и софтуерно инженерство&quot;</strong></p>\r\n<ul>\r\n	<li>\r\n		Учебен план</li>\r\n	<li>\r\n		Характеристики на дисциплините</li>\r\n</ul>\r\n<p>\r\n	<strong><span class=\\\"nolink\\\">&nbsp;-</span></strong><span class=\\\"nolink\\\">&nbsp;Специалност&nbsp;</span>&quot;<b>Графичен и web дизайн&quot;</b></p>\r\n<ul>\r\n	<li>\r\n		Учебен план</li>\r\n	<li>\r\n		<span class=\\\"nolink\\\">Характеристики на изучаваните дисциплини</span></li>\r\n</ul>\r\n', 'Yes', 270),
(22, 1, 'Дистанционно обучение', '', '<p>\r\n	<img alt=\\\"\\\" src=\\\"https://cs.fcst.bg/userfiles/pages/ESF_logo_BG.jpg\\\" style=\\\"width: 160px; height: 95px; float: left; margin-right: 120px;\\\" /><img alt=\\\"\\\" src=\\\"https://cs.fcst.bg/userfiles/pages/EU_logo_BG.jpg\\\" style=\\\"width: 122px; height: 95px; float: left;\\\" /></p>\r\n<p>\r\n	&nbsp;</p>\r\n<p>\r\n	&nbsp;</p>\r\n<p>\r\n	&nbsp;</p>\r\n<p>\r\n	&nbsp;</p>\r\n<p>\r\n	<span data-mce-mark=\\\"1\\\">Съдържанието на курсовете за дистанционна форма на обучение е разработено по проект &quot;<strong>Формални и неформални електронни форми за дистанционно обучение по &quot;Компютърни науки&quot;</strong> с<strong>&nbsp;</strong>финансовата подкрепа на Оперативна програма<strong> &bdquo;Развитие на човешките ресурси&rdquo;</strong>.&nbsp;</span></p>\r\n<hr />\r\n<h3 style=\\\"text-align: center;\\\">\r\n	Повече информация за програмите в дистанционна форма на обучение ще бъде достъпна на по-късен етап.&nbsp;</h3>\r\n<hr />\r\n<p>\r\n	&nbsp;</p>\r\n', 'No', 220),
(9, 2, 'Bachelor Programs', '', '<h3>\r\n	Bachelor Program &quot;Computer Science and Engineering&quot; (in English)</h3>\r\n<hr />\r\n<p>\r\n	<img src=\"https://cs.fcst.bg/userfiles/pages/readingstudents.jpg\" style=\"float: left; width: 200px; height: 173px; margin-right: 15px;\" />The program on &quot;Computer Science and Engineering&quot; opens up a wide range of career opportunities in industry, commerce and academia, including software engineer, systems designer, network administrator, systems administrator, database administrator, management information consultant, project manager, IT security manager, IT risk assessor, enterprise architect, multimedia system developer.</p>\r\n<p>\r\n	University degree: <strong>Bachelor</strong><br />\r\n	Professional qualification: <strong>Computer engineer</strong><br />\r\n	Duration of study: <strong>4 years</strong><br />\r\n	Form of study: <strong>Regular, Full-time</strong><br />\r\n	All courses are held in English</p>\r\n<ul>\r\n	<li>\r\n		<a href=\"https://cs.fcst.bg/userfiles/Bakalavri_UchebniPlanove/2013_Currl_CSE_bac_engl.pdf\">Curriculum</a></li>\r\n	<li>\r\n		<a href=\"https://cs.fcst.bg/userfiles/Bakalavri_UchebniPlanove/2013_CourseDescription_CSE_engl.pdf\">Course Descriptions</a></li>\r\n</ul>\r\n<p>\r\n	&nbsp;<span style=\"line-height: 1.3em;\">&nbsp;</span></p>\r\n<h3>\r\n	Bachelor Program &quot;Information Technologies in Transport&quot; (in English)</h3>\r\n<hr />\r\n<p>\r\n	<img src=\"https://cs.fcst.bg/userfiles/pages/readingstudents.jpg\" style=\"float: left; width: 200px; height: 173px; margin-right:15px;\" />The program &quot;Information Technologies in Transport&quot; opens up a wide range of career opportunities in the field of research, management, and training, consulting in public and private transportation companies at home and abroad. Successful graduates can develop their own business in the field of transport and logistics.</p>\r\n<p>\r\n	University degree: <strong>Bachelor</strong><br />\r\n	Professional qualification: <strong>Engineer</strong><br />\r\n	Duration of study: <strong>4 years</strong><br />\r\n	Form of study: <strong>Regular, Full-time</strong><br />\r\n	All courses are held in English.</p>\r\n<ul>\r\n	<li>\r\n		Curriculum</li>\r\n</ul>\r\n', 'Yes', 90);
INSERT INTO `pages_translations` (`page_id`, `language_id`, `title`, `short_description`, `content`, `active`, `position`) VALUES
(10, 2, 'Master Programs', '', '<h3>\r\n	Master Program &quot;Computer Science and Engineering&quot; (in English)</h3>\r\n<hr />\r\n<p>\r\n	<img src=\"https://cs.fcst.bg/userfiles/pages/readingstudents.jpg\" style=\"float: left; width: 200px; height: 173px; margin-right:15px;\" />The program on &quot;Computer Science and Engineering&quot; is intended for students who have completed bachelor degree in professional field of study &quot;Comunnication and Computer Technique&quot;.</p>\r\n<p>\r\n	University degree:&nbsp;<strong>Master</strong><br />\r\n	Professional qualification:&nbsp;<strong>Computer engineer</strong><br />\r\n	Duration of study:&nbsp;<strong>1.5 years</strong><br />\r\n	Form of study:&nbsp;<strong>Regular, Full-time</strong><br />\r\n	All courses are held in English</p>\r\n<p>\r\n	&nbsp;</p>\r\n<p>\r\n	&nbsp;</p>\r\n<ul>\r\n	<li>\r\n		<a href=\"https://cs.fcst.bg/userfiles/Magistri_UchebniPlanove/2013_Currl_CSE_master_engl.pdf\">Curriculum</a></li>\r\n	<li>\r\n		<a href=\"https://cs.fcst.bg/userfiles/Magistri_UchebniPlanove/KSI_EN.pdf\">Course Descriptions</a></li>\r\n</ul>\r\n<h3>\r\n	Master Program &quot;Computer Science and Engineering - Preparatory&quot; (in English)</h3>\r\n<hr />\r\n<p>\r\n	<img src=\"https://cs.fcst.bg/userfiles/pages/readingstudents.jpg\" style=\"float: left; width: 200px; height: 173px; margin-right:15px;\" />The program on &quot;Computer Science and Engineering - Preparatory&quot; is intended for students who have completed bachelor degree or master degree in professional fields of study: &quot;Natural Sciences&quot;, &quot;Engineering&quot;, &quot;Economics&quot;, &quot;Agricultural Science&quot;, &quot;Security and Defence&quot;, &quot;Education Sciences&quot;, &quot;Humanities&quot;, &quot;Social and Economic Sciences&quot;, &quot;Arts&quot;.</p>\r\n<p>\r\n	University degree:&nbsp;<strong>Master</strong><br />\r\n	Professional qualification:&nbsp;<strong>Computer engineer</strong><br />\r\n	Duration of study:&nbsp;<strong>1 year</strong><br />\r\n	Form of study:&nbsp;<strong>Regular, Full-time</strong><br />\r\n	All courses are held in English</p>\r\n<ul>\r\n	<li>\r\n		<a href=\"https://cs.fcst.bg/userfiles/Magistri_UchebniPlanove/2013_Currl_CSE_master_prep_engl.pdf\">Curriculum</a></li>\r\n	<li>\r\n		<a href=\"https://cs.fcst.bg/userfiles/Magistri_UchebniPlanove/CSE_prep_EN.pdf\">Course Descriptions</a></li>\r\n</ul>\r\n', 'Yes', 100),
(11, 2, 'PhD Programs', '', '<h3>\r\n	The information for PhD Programs will appear soon</h3>\r\n<hr />\r\n<p>\r\n	<img src=\"https://cs.fcst.bg/userfiles/pages/application_icon_PHD.jpg\" style=\"float: left; width: 185px; height: 242px; margin-right:15px;\" /></p>\r\n<h3>\r\n	What is a Ph.D.?</h3>\r\n<p align=\"justify\">\r\n	A Ph.D. is a long, in depth research exploration of one topic. By long we&rsquo;re typically talking about 6 years. By in depth we mean that at the end of the Ph.D. you will be the world expert or close to it in your particular area. You will know more than your advisor about your particular research area. You will know about your research than anyone at your school. By one we mean that by the last couple years of your Ph.D., you will typically be working on only one narrow problem. The Ph.D. is not about breadth, it is about depth.</p>\r\n<p>\r\n	&nbsp;</p>\r\n<h3>\r\n	Lack of emphasis on courses</h3>\r\n<p align=\"justify\">\r\n	The M.S. and B.A. degrees are about breadth not depth.&nbsp;<span style=\"line-height: 1.3em;\">The emphasis in the Ph.D. is not on classes, but rather on research. A Ph.D. student will typically take classes only when he feels that they will be useful in the particular research topic.</span></p>\r\n<p>\r\n	&nbsp;</p>\r\n<h3>\r\n	The research process and advisor/advisee relationships</h3>\r\n<p align=\"justify\">\r\n	As stated earlier, the main focus of a Ph.D. is on research. You typically begin your research at the time when you select an advisor.</p>\r\n<p>\r\n	Research is very different from taking classes. Many students never make the transition between taking classes and doing research &ndash; in fact, at most universities only 1/2 of the students who enter the Ph.D. program leave with a Ph.D.</p>\r\n<p>\r\n	<strong>Some key differences between classes and research:</strong></p>\r\n<ul>\r\n	<li>\r\n		In classes, the homework problems all have known answers and the techniques needed for solving the problems have (usually) been introduced in class. In research, you may be working on a problem for years without a clue of whether it is solvable. You will be the one inventing or ﬁnding the techniques for solving the problem.</li>\r\n	<li>\r\n		In classes, you are assigned certain problems to work on. In research, you get to pick the problems. In fact it is your job to ﬁnd good problems. By &ldquo;good&rdquo; we mean problems which are &ldquo;fundamental.&rdquo; You are also responsible for making sure that no one else has already solved this problem. This typically involves reading hundreds of papers on earlier research in this area.</li>\r\n	<li>\r\n		In classes, if you can&rsquo;t solve your homework problem, you can always ask other classmates. Even if none of your classmates know, you can ask the professor, who certainly knows the answer. In research, you are often working alone, or at best with you advisor and maybe one other student. You are free to ask anyone in the world for help, but they will typically not be able to help you, since they don&rsquo;t know the answer either &ndash; if they did, it wouldn&rsquo;t be research. Many students have a hard time with working independently.</li>\r\n	<li>\r\n		In classes, you are constantly being given grades and you are constantly being told what to do next. In research, there are no grades. There is some instruction (from your advisor), but mostly it&rsquo;s up to you to be self-motivated and pro-active.</li>\r\n</ul>\r\n<p>\r\n	&nbsp;</p>\r\n<p style=\"text-align: center;\">\r\n	<strong>Keep in mind that no one can give you a complete picture of what research is. The best way to learn what research is, and whether you like it, is simply to start doing it. The earlier the better!</strong></p>\r\n<p>\r\n	&nbsp;</p>\r\n<h3>\r\n	Funding during the Ph.D</h3>\r\n<p align=\"justify\">\r\n	Ideally, your only&nbsp;responsibility will be research. This is called doing an RAship (Research Assistantship). Y<span style=\"line-height: 1.3em;\">ou can only do an RAship if you have an advisor who has&nbsp;</span><span style=\"line-height: 1.3em;\">funding for you.</span></p>\r\n<p align=\"justify\">\r\n	There are many companies and government organizations which offer Graduate Fellowships for Ph.D. students. If you are lucky enough to get one of these, they will cover&nbsp;<span style=\"line-height: 1.3em;\">your full way through graduate school, and you will never have to worry about whether your advisor&nbsp;</span><span style=\"line-height: 1.3em;\">has funding or not.</span></p>\r\n<p>\r\n	&nbsp;</p>\r\n<h3>\r\n	Should I get a Ph.D.?</h3>\r\n<p>\r\n	Here are some things to keep in mind when making this decision:</p>\r\n<ul>\r\n	<li>\r\n		A Ph.D. is not for everyone!</li>\r\n	<li>\r\n		A Ph.D requires 3 years on average. The opportunity cost is high.</li>\r\n	<li>\r\n		Do not even think of applying for a Ph.D. if you have not tried research.</li>\r\n	<li>\r\n		A Ph.D. requires a particular type of personality. You need to be someone who is obsessed with ﬁguring out a problem. You need to have tremendous perseverance and be capable of hard work. You need to be willing to do whatever it takes to solve your problem (e.g., take additional math classes, learn a whole new scientific area, etc.).</li>\r\n	<li>\r\n		You need to know why you want a Ph.D. You need to have vision and ideas and you need to be able to express yourself.</li>\r\n</ul>\r\n<p>\r\n	&nbsp;</p>\r\n<h3>\r\n	The Application Process</h3>\r\n<p>\r\n	The Ph.D. application has several parts:</p>\r\n<p>\r\n	Transcript &ndash; Grades and classes</p>\r\n<p>\r\n	Personal Statement</p>\r\n<p>\r\n	Previous research experience (possibly in industry)</p>\r\n<p>\r\n	Recommendation letters</p>\r\n<p>\r\n	Awards and extracurricular activities</p>\r\n<hr />\r\n<p>\r\n	&nbsp;</p>\r\n', 'Yes', 110),
(24, 2, 'ERASMUS - study and practice', '', '<h1>\r\n	ERASMUS European Union Students Exchange Program</h1>\r\n<p>\r\n	The Department of &ldquo;Computer Systems&rdquo; announces that it has several signed bilateral agreements with foreign European Universities for the academic 2013-2014 year in the frame of the EU student mobility program. The students have an opportunity to apply for a short term study (inside the semester and/or diploma preparation) period into the following Universities:</p>\r\n<ul>\r\n	<li>\r\n		UINIVERSITY OF CATANIA, ITALY - http://www.unict.it/en/international-prospectus 3 students for an academic year, 18 months totally (required language level &ndash; English, В1 or Italian, А1)</li>\r\n	<li>\r\n		ANKARA UNIVERSITY, TURKEY - http://erasmus.ankara.edu.tr 2 students for an academic year, up to 10 months per student (required language level &ndash; English, В1)</li>\r\n	<li>\r\n		The UNIVERSITY OF MALTA - http://www.um.edu.mt/int-eu/erasmus 2 students for an academic year, 12 months totally (required language level &ndash; English, В1)</li>\r\n</ul>\r\n<p>\r\n	The interested students may ask for detailed information concerning the application procedure from the Erasmus Program local representatives &ndash; Mrs. Sevinch Mehmed (room 1327, ph.3139, еmail: <a href=\"mailto:sevinch_mehmed@tu-sofia.bg\">sevinch_mehmed@tu-sofia.bg</a>), or from Assoc. Prof. V.Mollov (room 1200, ph.3623, email: <a href=\"mailto:mollov@tu-sofia.bg\">mollov@tu-sofia.bg</a>). Formal detailed information is also available at the Web site of the Erasmus Program for the TU-Sofia: http://www.tu-sofia.bg/Erasmus Deadline for application: Nov. 15th, 2013.</p>\r\n<p>\r\n	More information about ERASMUS Program and admminsion documens can be found <a href=\"http://www.tu-sofia.bg/Erasmus/\" target=\"_blank\">here &gt;&gt;</a></p>\r\n', 'No', 120),
(14, 2, 'Research', '', '', 'Yes', 140),
