(61, 1, 'ЕРАЗЪМ+', '', '<p>\r\n	<img alt=\"\" src=\"https://cs.fcst.bg/images/empty.jpg\" style=\"width: 300px; height: 196px; float: left; margin-right: 18px; margin-bottom: 12px; position: relative; top: 5px;\" /></p>\r\n<p>\r\n	&nbsp;</p>\r\n<h1>\r\n	Международна дейност</h1>\r\n<hr />\r\n<p>\r\n	<a href=\"https://tu-sofia.bg/university/317\" target=\"_blank\">Еразъм+</a></p>\r\n<p>\r\n	<a href=\"https://tu-sofia.bg/university/3094\" target=\"_blank\">Международни магистърски програми</a></p>\r\n<p>\r\n	<a href=\"https://tu-sofia.bg/university/118\" target=\"_blank\">Академично сътрудничество</a></p>\r\n', 'Yes', 570),
(63, 1, 'Изпитна сесия - ОКС &quot;Бакалавър&quot;', '', '<p>\r\n	<span style=\"color:#b22222;\"><strong>ВАЖНО</strong>: За подробности относно организацията и начина на провеждане на изпитите се свързвайте с вашите преподаватели като използвате установените комуникационни канали: e-mail, MS Teams и Moodle.&nbsp;<img alt=\"smiley\" height=\"20\" src=\"https://cs.fcst.bg/donthackplease/scripts/ckeditor/plugins/smiley/images/regular_smile.gif\" title=\"smiley\" width=\"20\" /></span></p>\r\n<h1>\r\n	<strong>Академична учебна година 2025/2026</strong></h1>\r\n<hr />\r\n<br />\r\n<h3>\r\n	<a href=\"https://docs.google.com/spreadsheets/d/e/2PACX-1vQtdNnxiHGoTyqorRtFprznN3HbVDZzUxZ48bmnITahn_vAsE8x1CKDyxyQHBJED7j-NDqZ0GPXI9Lj/pubhtml?gid=0&amp;single=true\">График за бакалаври, спец. &quot;Компютърно и софтуерно инженерство&quot;</a></h3>\r\n<h3>\r\n	<a href=\"https://docs.google.com/spreadsheets/d/e/2PACX-1vQtdNnxiHGoTyqorRtFprznN3HbVDZzUxZ48bmnITahn_vAsE8x1CKDyxyQHBJED7j-NDqZ0GPXI9Lj/pubhtml?gid=1146137517&amp;single=true\">График за бакалавър-абсолвент, спец. &quot;Компютърно и софтуерно инженерство&quot;</a></h3>\r\n', 'Yes', 590),
(63, 2, 'Exam Session - Bachelor&#39;s Degree', '', '<p>\r\n	<span style=\"color:#b22222;\"><strong>IMPORTANT:</strong> Please contact your teachers using the established communication channels: e-mail, MS Teams, and Moodle for further details on the organization and delivery of the exams.</span></p>\r\n<br />\r\n<h1>\r\n	<strong>Academic Year 2025/2026</strong></h1>\r\n<hr />\r\n<br />\r\n<h3>\r\n	<a href=\"https://docs.google.com/spreadsheets/d/e/2PACX-1vQtdNnxiHGoTyqorRtFprznN3HbVDZzUxZ48bmnITahn_vAsE8x1CKDyxyQHBJED7j-NDqZ0GPXI9Lj/pubhtml?gid=1741952940&amp;single=true\">Bachelor: Schedule for specialty CSE</a></h3>\r\n<h3>\r\n	<a href=\"https://docs.google.com/spreadsheets/d/e/2PACX-1vQtdNnxiHGoTyqorRtFprznN3HbVDZzUxZ48bmnITahn_vAsE8x1CKDyxyQHBJED7j-NDqZ0GPXI9Lj/pubhtml?gid=1780117649&amp;single=true\">Bachelor - graduate: Schedule for specialty CSE</a></h3>\r\n<h1>\r\n	&nbsp;</h1>\r\n', 'Yes', 290),
(50, 2, 'Dates for diploma defences by commissions', '', '<h1>\r\n	Session Schedule:&nbsp;<strong style=\"font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 22px;\">22.01.2024 - 26.01.2024</strong></h1>\r\n<hr />\r\n<table border=\"1\" cellpadding=\"5\" cellspacing=\"5\" width=\"500px\">\r\n	<thead>\r\n		<tr>\r\n			<th scope=\"\\&quot;col\\&quot;\">\r\n				Commission</th>\r\n			<th scope=\"\\&quot;col\\&quot;\">\r\n				Chair</th>\r\n			<th scope=\"\\&quot;col\\&quot;\">\r\n				Date</th>\r\n			<th scope=\"\\&quot;col\\&quot;\">\r\n				Time</th>\r\n			<th scope=\"\\&quot;col\\&quot;\">\r\n				Hall</th>\r\n		</tr>\r\n	</thead>\r\n	<tbody>\r\n		<tr>\r\n			<td>\r\n				1</td>\r\n			<td>\r\n				&nbsp;</td>\r\n			<td>\r\n				&nbsp;</td>\r\n			<td>\r\n				&nbsp;</td>\r\n			<td>\r\n				&nbsp;</td>\r\n		</tr>\r\n		<tr>\r\n			<td>\r\n				2</td>\r\n			<td>\r\n				&nbsp;</td>\r\n			<td>\r\n				&nbsp;</td>\r\n			<td>\r\n				&nbsp;</td>\r\n			<td>\r\n				&nbsp;</td>\r\n		</tr>\r\n		<tr>\r\n			<td>\r\n				3</td>\r\n			<td>\r\n				&nbsp;</td>\r\n			<td>\r\n				&nbsp;</td>\r\n			<td>\r\n				&nbsp;</td>\r\n			<td>\r\n				&nbsp;</td>\r\n		</tr>\r\n		<tr>\r\n			<td>\r\n				4</td>\r\n			<td>\r\n				&nbsp;</td>\r\n			<td>\r\n				&nbsp;</td>\r\n			<td>\r\n				&nbsp;</td>\r\n			<td>\r\n				&nbsp;</td>\r\n		</tr>\r\n		<tr>\r\n			<td>\r\n				5</td>\r\n			<td>\r\n				&nbsp;</td>\r\n			<td>\r\n				&nbsp;</td>\r\n			<td>\r\n				&nbsp;</td>\r\n			<td>\r\n				&nbsp;</td>\r\n		</tr>\r\n		<tr>\r\n			<td>\r\n				6</td>\r\n			<td>\r\n				&nbsp;</td>\r\n			<td>\r\n				&nbsp;</td>\r\n			<td>\r\n				&nbsp;</td>\r\n			<td>\r\n				&nbsp;</td>\r\n		</tr>\r\n	</tbody>\r\n</table>\r\n<h2>\r\n	&nbsp;</h2>\r\n', 'Yes', 320),
