(73, 1, 'Академичен календар - абсолвенти', '', '<h2>\r\n	Учебна 2023/24 г.</h2>\r\n<hr />\r\n<ul>\r\n	<li>\r\n		<a href=\"https://cs.fcst.bg/userfiles/20232024/grafik_mag_absolvent_2023-24_KSI_last.pdf\" target=\"_blank\">График ОКС &quot;магистър&quot; - абсолвенти,</a>&nbsp;специалност КСИ</li>\r\n</ul>\r\n', 'Yes', 620),
